function v16ToEpochMs(value) {
 if (typeof value === 'string') {
 const text = value.trim();
 if (!text) return 0;
 const parsedDate = Date.parse(text);
 if (Number.isFinite(parsedDate) && parsedDate > 0) return Math.round(parsedDate);
 }
 const raw = Number(value || 0);
 if (!Number.isFinite(raw) || raw <= 0) return 0;
 if (raw > 1e15) return Math.round(raw / 1000);
 if (raw > 1e12) return Math.round(raw);
 if (raw > 1e9) return Math.round(raw * 1000);
 return Math.round(raw * 1000);
}

function v16ResolveWalletPct(value = 0, walletBalance = 0) {
 const wallet = Number(walletBalance || 0);
 if (!(wallet > 0)) return null;
 return (Number(value || 0) / wallet) * 100;
}

function v16FormatWalletPct(value = 0, walletBalance = 0, digits = 1, { abs = false } = {}) {
 const pct = v16ResolveWalletPct(value, walletBalance);
 if (!Number.isFinite(pct)) return '';
 const display = abs ? Math.abs(pct) : pct;
 return `${display >= 0 ? '+' : ''}${v16FmtNumber(display, digits)}%`;
}

function v16FormatSignedWithWalletPct(value = 0, walletBalance = 0, digits = 1) {
 const pct = v16FormatWalletPct(value, walletBalance, digits);
 return pct ? `${v16FmtSigned(Number(value || 0))} (${pct})` : v16FmtSigned(Number(value || 0));
}

function v16StartOfNextDay(now = Date.now()) {
 const next = new Date(Number(now || Date.now()));
 next.setUTCHours(24, 0, 0, 0);
 return next.getTime();
}

function v16SanitizeManualControls(state = {}, now = Date.now()) {
 const safeState = state && typeof state === 'object' ? state : {};
 const rawSymbols = safeState.symbols && typeof safeState.symbols === 'object' ? safeState.symbols : {};
 const symbols = Object.entries(rawSymbols).reduce((acc, [symbol, entry]) => {
 const normalizedSymbol = v16NormalizeSymbol(symbol);
 if (!normalizedSymbol || !entry || typeof entry !== 'object') return acc;
 const next = {
 symbol: normalizedSymbol,
 pausedUntil: Math.max(0, Number(entry.pausedUntil || 0)),
 reentryBlockedUntil: Math.max(0, Number(entry.reentryBlockedUntil || 0)),
 ignoreFundingUntil: Math.max(0, Number(entry.ignoreFundingUntil || 0)),
 reservedSlotUntil: Math.max(0, Number(entry.reservedSlotUntil || 0)),
 blockedTodayUntil: Math.max(0, Number(entry.blockedTodayUntil || 0)),
 note: String(entry.note || '').trim(),
 updatedAt: Math.max(0, Number(entry.updatedAt || 0)),
 };
 if (
 next.pausedUntil > now
 || next.reentryBlockedUntil > now
 || next.ignoreFundingUntil > now
 || next.reservedSlotUntil > now
 || next.blockedTodayUntil > now
 ) {
 acc[normalizedSymbol] = next;
 }
 return acc;
 }, {});
 return { symbols, updatedAt: Math.max(0, Number(safeState.updatedAt || now)) };
}

function v16ResolveManualControlRecord(state = {}, symbol = '', now = Date.now()) {
 const normalizedSymbol = v16NormalizeSymbol(symbol);
 const record = normalizedSymbol ? (state?.symbols?.[normalizedSymbol] || null) : null;
 return {
 symbol: normalizedSymbol,
 record,
 paused: Number(record?.pausedUntil || 0) > now,
 reentryBlocked: Number(record?.reentryBlockedUntil || 0) > now,
 ignoreFunding: Number(record?.ignoreFundingUntil || 0) > now,
 reservedSlot: Number(record?.reservedSlotUntil || 0) > now,
 blockedToday: Number(record?.blockedTodayUntil || 0) > now,
 };
}

function v16CountReservedSlotsFromControls(manualControls = {}, occupiedSymbols = new Set(), now = Date.now()) {
 return Object.values(manualControls?.symbols || {}).reduce((count, entry) => {
 const symbol = v16NormalizeSymbol(entry?.symbol || '');
 if (!symbol || !(Number(entry?.reservedSlotUntil || 0) > now)) return count;
 if (occupiedSymbols.has(symbol)) return count;
 return count + 1;
 }, 0);
}

function v16ResolveExposureTone(notionalValue = 0, walletBalance = 0, warningPct = 50, dangerPct = 80) {
 const pct = Math.abs(Number(v16ResolveWalletPct(notionalValue, walletBalance) || 0));
 if (!(pct > 0)) return { pct: 0, tone: '' };
 if (pct >= dangerPct) return { pct, tone: 'bad' };
 if (pct >= warningPct) return { pct, tone: 'warn' };
 return { pct, tone: 'good' };
}

