function v16FindJournalSetupPerformanceRow(trade = {}, review = null) {
 const setupMeta = v16ResolveTradeSetupFamilyMeta(trade, review);
 const rows = Array.isArray(v16LiveAnalyticsSetupCache?.rows) ? v16LiveAnalyticsSetupCache.rows : [];
 const candidates = [
 setupMeta.key,
 setupMeta.label,
 trade.setupFamilyKey,
 trade.setupFamily,
 trade.setupFamilyLabel,
 ].map(value => String(value || '').trim().toLowerCase()).filter(Boolean);
 return rows.find(row => {
 const rowValues = [
 row.familyKey,
 row.family,
 String(row.family || '').split('|')[0],
 ].map(value => String(value || '').trim().toLowerCase());
 return candidates.some(candidate => rowValues.some(value => value === candidate || value.startsWith(`${candidate}|`) || value.includes(candidate)));
 }) || null;
}

function v16BuildJournalTimelineHtml(trade = {}, review = null) {
 const normalizedReview = v16NormalizeJournalRecord(review || trade.review || trade.notes || '');
 const steps = [
 {
 label: 'Entry',
 value: v16FormatTs(trade.openedAt),
 copy: v16ResolveJournalEntryReason(trade, normalizedReview),
 },
 {
 label: 'Manage',
 value: Number(trade.holdMinutes || 0) > 0 ? `${Number(trade.holdMinutes || 0)}m hold` : 'Hold time pending',
 copy: Array.isArray(trade.targetShiftEvents) && trade.targetShiftEvents.length
 ? `${trade.targetShiftEvents.length} target shift${trade.targetShiftEvents.length === 1 ? '' : 's'} recorded.`
 : 'No target shifts recorded.',
 },
 {
 label: 'Exit',
 value: v16FormatTs(trade.closedAt),
 copy: v16ResolveJournalExitReason(trade, normalizedReview),
 },
 {
 label: 'Review',
 value: v16BuildJournalLessonStatus(normalizedReview),
 copy: normalizedReview.mistakeTag ? `Mistake tag: ${normalizedReview.mistakeTag}` : 'Add mistake tag and lesson after replay.',
 },
 ];
 return `<div class="journal-replay-timeline">${steps.map(step => `
 <div class="journal-replay-step">
 <span>${v16Esc(step.label)}</span>
 <strong>${v16Esc(step.value || '-')}</strong>
 <small>${v16Esc(step.copy || '')}</small>
 </div>`).join('')}</div>`;
}

function v16BuildJournalSetupPerformanceHtml(trade = {}, review = null, trades = []) {
 const setupMeta = v16ResolveTradeSetupFamilyMeta(trade, review);
 const row = v16FindJournalSetupPerformanceRow(trade, review);
 if (!row) {
 const peerTrades = (Array.isArray(trades) ? trades : []).filter(item => {
 const peerMeta = v16ResolveTradeSetupFamilyMeta(item, item.review || item.notes || '');
 return peerMeta.key && setupMeta.key && peerMeta.key === setupMeta.key;
 });
 if (peerTrades.length) {
 const pnl = peerTrades.reduce((sum, item) => sum + Number(item.pnl || 0), 0);
 const wins = peerTrades.filter(item => Number(item.pnl || 0) > 0).length;
 const winRate = peerTrades.length ? Math.round((wins / peerTrades.length) * 100) : 0;
 return `
 <div class="journal-replay-metric">
 <span>Setup Performance</span>
 <strong>${v16Esc(setupMeta.label || 'Untagged')}</strong>
 <small>${peerTrades.length} trade${peerTrades.length === 1 ? '' : 's'} in this view | ${v16FmtSigned(pnl)} P&L | ${winRate}% win</small>
 </div>`;
 }
 return `
 <div class="journal-replay-metric">
 <span>Setup Performance</span>
 <strong>${v16Esc(setupMeta.label || 'Untagged')}</strong>
 <small>No setup-family history loaded yet.</small>
 </div>`;
 }
 const status = v16ResolveSetupPromotion(row);
 return `
 <div class="journal-replay-metric">
 <span>Setup Performance</span>
 <strong>${v16Esc(setupMeta.label || row.family || 'Untagged')}</strong>
 <small>${Number(row.trades || 0)} trades | ${v16FmtSigned(Number(row.pnl || 0))} P&L | ${v16FmtNumber(Number(row.winRate || 0), 0)}% win | ${v16Esc(status.label)}</small>
 </div>`;
}

function v16RenderJournalReplayPanel(trades = []) {
 const panel = document.getElementById('liveJournalReplayPanel');
 if (!panel) return;
 const items = Array.isArray(trades) ? trades : [];
 if (!items.length) {
 panel.innerHTML = `<div class="empty"><div class="ei">--</div><div class="eh">Replay workflow waiting</div><div class="es">Closed trades will show a timeline, entry reason, exit reason, mistake tags, and setup performance.</div></div>`;
 return;
 }
 const selectedId = String(v16LiveAccountView.activeJournalId || '');
 const trade = items.find(item => String(item.id || '') === selectedId) || items[items.length - 1] || items[0];
 const review = v16NormalizeJournalRecord(trade.review || trade.notes || '');
 const pnl = Number(trade.pnl || 0);
 const chartSnapshot = review.chartSnapshot || `${v16FormatOptionalPrice(trade.entryPrice || 0)} entry | ${v16FormatOptionalPrice(trade.stopLoss || 0)} stop | ${v16FormatOptionalPrice(trade.exitPrice || 0)} exit`;
 panel.innerHTML = `
 <div class="journal-replay-head">
 <div>
 <div class="live-card-kicker">REPLAY WORKFLOW</div>
 <div class="live-card-title">${v16Esc(trade.symbol || 'Selected Trade')} ${v16Esc(String(trade.side || '').toUpperCase())}</div>
 <div class="live-card-meta">${v16Esc(v16BuildJournalTradeStory(trade, review))}</div>
 </div>
 <button class="bsm" type="button" data-open-journal-replay="${v16Esc(trade.id || '')}">Open Replay</button>
 </div>
 ${v16BuildJournalTimelineHtml(trade, review)}
 <div class="journal-replay-grid">
 <div class="journal-replay-metric">
 <span>Entry Reason</span>
 <strong>${v16Esc(v16ResolveJournalEntryReason(trade, review))}</strong>
 <small>${v16Esc(v16ResolveTradeModeLabel(trade))} | ${v16Esc(v16ResolveTradeSetupFamilyMeta(trade, review).label)}</small>
 </div>
 <div class="journal-replay-metric">
 <span>Chart Snapshot</span>
 <strong>${v16Esc(chartSnapshot)}</strong>
 <small>Open replay for the candle-level chart view.</small>
 </div>
 <div class="journal-replay-metric">
 <span>Exit Reason</span>
 <strong class="${pnl >= 0 ? 'good' : 'bad'}">${v16Esc(v16ResolveJournalExitReason(trade, review))}</strong>
 <small>${v16Esc(v16FmtSigned(pnl))} realized.</small>
 </div>
 <div class="journal-replay-metric">
 <span>Mistake Tags</span>
 <strong>${review.mistakeTag ? v16Esc(review.mistakeTag) : 'Not tagged'}</strong>
 <small>${review.notes ? 'Lesson note saved.' : 'Add lesson after replay.'}</small>
 </div>
 ${v16BuildJournalSetupPerformanceHtml(trade, review, items)}
 </div>`;
 panel.querySelector('[data-open-journal-replay]')?.addEventListener('click', () => openV16JournalDetail(trade));
}

function v16RenderJournal(trades = []) {
 const wrap = document.getElementById('liveJournalRows');
 const meta = document.getElementById('liveJournalMeta');
 if (!wrap || !meta) return;
 const items = Array.isArray(trades) ? trades : [];
 v16RenderJournalReplayPanel(items);
 meta.textContent = items.length
 ? `${items.length} closed trade${items.length === 1 ? '' : 's'} in the loaded review window.`
 : 'Closed live trades will appear here.';
 if (!items.length) {
 wrap.innerHTML = `<div class="empty"><div class="ei">--</div><div class="eh">No journal trades yet</div><div class="es">Closed positions detected from Delta history will appear here.</div></div>`;
 return;
 }
 wrap.innerHTML = items.slice(0, 40).map(trade => {
 const review = v16NormalizeJournalRecord(trade.review || trade.notes || '');
 const tradeMode = v16ResolveTradeModeLabel(trade);
 const reverseMeta = v16ResolveReverseTradeMeta(trade);
 const diagnosticSummary = v16BuildTradeDiagnosticSummary({ ...trade, review });
 const tradeStory = v16BuildJournalTradeStory(trade, review);
 return `
 <button class="live-journal-row ${review.notes ? '' : 'pending'}" data-live-journal-id="${v16Esc(trade.id)}">
 <div class="live-journal-top">
 <strong>${v16Esc(trade.symbol)}</strong>
 <span class="${Number(trade.pnl || 0) >= 0 ? 'good' : 'bad'}">${v16FmtSigned(Number(trade.pnl || 0))}</span>
 </div>
 <div class="live-journal-meta">${v16Esc(String(trade.side || '').toUpperCase())} | ${v16FmtNumber(Number(trade.size || 0), 4).replace(/\.?0+$/, '')} contracts | ${v16Esc(tradeMode)} | Closed ${v16Esc(v16FormatTs(trade.closedAt))}</div>
 <div class="live-journal-tags"><span class="live-journal-tag ${tradeMode === 'Auto' ? '' : 'warn'}">${v16Esc(tradeMode)}</span>${reverseMeta.enabled ? `<span class="live-journal-tag reverse" title="${v16Esc(reverseMeta.detail)}">Reversed</span>` : ''}<span class="live-journal-tag">${v16Esc(v16HumanizeCloseReasonLabel(trade.closeReasonLabel || 'closed on exchange'))}</span>${V16_MANAGE_REVIEW_CHECKS.filter(check => review.checklist?.[check.key]).map(check => `<span class="live-journal-tag">${v16Esc(check.label)}</span>`).join('')}${review.setupTag ? `<span class="live-journal-tag">${v16Esc(review.setupTag)}</span>` : ''}${review.mistakeTag ? `<span class="live-journal-tag warn">${v16Esc(review.mistakeTag)}</span>` : ''}</div>
 <div class="live-journal-meta">${v16Esc(tradeStory)}</div>
 <div class="live-journal-meta">${v16Esc(diagnosticSummary || 'Trade summary will become richer after more tracked closes.')}</div>
 <div class="live-journal-meta">${review.notes ? v16Esc(v16BuildJournalSummary(review)) : v16Esc(v16BuildJournalLessonStatus(review))}</div>
 </button>`;
 }).join('');
 wrap.querySelectorAll('[data-live-journal-id]').forEach(button => {
 button.addEventListener('click', () => {
 const trade = items.find(item => String(item.id || '') === String(button.dataset.liveJournalId || ''));
 if (trade) {
 v16LiveAccountView.activeJournalId = String(trade.id || '');
 v16RenderJournalReplayPanel(items);
 openV16JournalDetail(trade);
 }
 });
 });
 // Wire CSV export button
 const csvBtn = document.getElementById('btnExportJournalCSV');
 if (csvBtn) {
 csvBtn.onclick = () => v16ExportJournalCSV(items);
 }
}

function v16ExportJournalCSV(trades = []) {
 const csvEsc = v => `"${String(v ?? '').replace(/"/g, '""').replace(/\n/g, ' ')}"`;
 const headers = ['Symbol', 'Side', 'ReverseTrade', 'OriginalSide', 'ExecutionSide', 'Size', 'EntryPrice', 'ExitPrice', 'PnL', 'GrossPnL', 'Fees', 'OpenedAt', 'ClosedAt', 'EntryReason', 'ExitReason', 'ChartSnapshot', 'SetupTag', 'MistakeTag', 'Confidence', 'FollowedPlan', 'RespectedRisk', 'CleanExecution', 'Notes'];
 const rows = (trades || []).map(trade => {
 const review = v16NormalizeJournalRecord(trade.review || trade.notes || '');
 const reverseMeta = v16ResolveReverseTradeMeta(trade);
 return [
 trade.symbol,
 String(trade.side || '').toUpperCase(),
 reverseMeta.enabled ? 'Yes' : 'No',
 String(reverseMeta.originalSide || '').toUpperCase(),
 String(reverseMeta.executionSide || '').toUpperCase(),
 Number(trade.size || 0),
 Number(trade.entryPrice || 0),
 Number(trade.exitPrice || 0),
 Number(trade.pnl || 0),
 Number(trade.grossPnl || trade.grossMovePnl || 0),
 Number(trade.fees || trade.commission || 0),
 trade.openedAt ? new Date(trade.openedAt).toISOString() : '',
 trade.closedAt ? new Date(trade.closedAt).toISOString() : '',
 review.entryReason,
 review.exitReason,
 review.chartSnapshot,
 review.setupTag,
 review.mistakeTag,
 review.confidence,
 review.checklist?.followedPlan ? 'Yes' : 'No',
 review.checklist?.respectedRisk ? 'Yes' : 'No',
 review.checklist?.cleanExecution ? 'Yes' : 'No',
 review.notes,
 ].map(csvEsc).join(',');
 });
 const csv = [headers.join(','), ...rows].join('\n');
 const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url;
 a.download = `fwd_tradedesk_pro_journal_${new Date().toISOString().slice(0, 10)}.csv`;
 document.body.appendChild(a);
 a.click();
 document.body.removeChild(a);
 URL.revokeObjectURL(url);
}

function v16RenderTradeHistory(fills = [], orderHistory = [], rawFills = [], rawOrderHistory = []) {
 const wrap = document.getElementById('liveTradeHistoryRows');
 const meta = document.getElementById('liveTradeHistoryMeta');
 if (!wrap || !meta) return;
 const normalizedFills = Array.isArray(fills) ? fills : [];
 const normalizedOrders = Array.isArray(orderHistory) ? orderHistory : [];
 const feed = normalizedFills.length ? normalizedFills : normalizedOrders;
 const usingOrders = !normalizedFills.length && normalizedOrders.length > 0;
 const rawCopy = usingOrders
 ? `${Array.isArray(rawOrderHistory) ? rawOrderHistory.length : 0} raw orders`
 : `${Array.isArray(rawFills) ? rawFills.length : 0} raw fills`;
 meta.textContent = feed.length
 ? `${feed.length} activity record${feed.length === 1 ? '' : 's'} loaded | ${rawCopy}`
 : 'Waiting for Delta order history.';
 if (!feed.length) {
 wrap.innerHTML = `<div class="empty"><div class="ei">--</div><div class="eh">No trade activity loaded</div><div class="es">Refresh live data to load fills and order history from Delta Exchange.</div></div>`;
 return;
 }
 wrap.innerHTML = `<div class="live-trade-history-table-wrap"><table class="live-trade-history-table">
 <thead><tr><th>Symbol</th><th>Side</th><th>Size</th><th>Price</th><th>Fee / reason</th><th>State</th><th>Time</th></tr></thead>
 <tbody>${feed.slice(0, 80).map(item => {
 const side = String(item.side || '').toUpperCase();
 const price = Number(item.price || item.limitPrice || 0);
 const feeOrReason = usingOrders
 ? String(item.explanation || item.reason || 'Order history fallback')
 : `Fee -$${Math.abs(Number(item.commission || 0)).toFixed(4)}`;
 return `<tr class="${usingOrders ? 'is-order-row' : ''}">
 <td><strong>${v16Esc(item.symbol || '')}</strong></td>
 <td>${v16Esc(side || '-')}</td>
 <td>${v16FmtNumber(Number(item.size || 0), 4).replace(/\.?0+$/, '')}</td>
 <td>${price > 0 ? `$${v16FmtPrice(price)}` : '-'}</td>
 <td>${v16Esc(feeOrReason)}</td>
 <td>${usingOrders ? v16Esc(String(item.state || '').toUpperCase() || '-') : 'FILL'}</td>
 <td>${v16Esc(v16FormatTs(item.createdAt || item.closedAt || 0))}</td>
 </tr>`;
 }).join('')}</tbody>
 </table></div>`;
}

