// Capability shell, risk board, account state and trade journal
function renderV16CredentialModeStatus(profile = null, secret = null) {
 const noteEl = document.getElementById('accountCredentialModeNote');
 const keyInput = document.getElementById('accountTradingKey');
 const secretInput = document.getElementById('accountTradingSecret');
 if (!noteEl || !keyInput || !secretInput) return;

 const selectedProfile = profile || getV16SelectedAccountProfile();
 const selectedSecret = secret || getV16Secrets()?.[selectedProfile?.id] || {};
 const usesNative = v16UsesNativeCredential(selectedProfile);
 const label = String(selectedSecret?.label || selectedProfile?.credentialLabel || '').trim();

 if (usesNative) {
 noteEl.textContent = label
 ? `Stored in encrypted Windows app storage as "${label}". Leave key fields blank to keep it, or enter new values to replace it.`
 : 'Stored in encrypted Windows app storage. Leave key fields blank to keep it, or enter new values to replace it.';
 noteEl.className = 'account-inline-note good';
 keyInput.placeholder = 'Stored in encrypted Windows app storage';
 secretInput.placeholder = 'Stored in encrypted Windows app storage';
 return;
 }

 if (v16NativeCredentialState.available) {
 noteEl.textContent = 'Encrypted Windows app storage is available. Saving a full key and secret will move them out of session storage.';
 noteEl.className = 'account-inline-note good';
 } else {
 noteEl.textContent = 'Encrypted Windows app storage is not responding yet. Keys saved now stay only in this app session.';
 noteEl.className = 'account-inline-note warn';
 }
 keyInput.placeholder = 'Required for live account data';
 secretInput.placeholder = 'Required for live account data';
}

function v16UpsertEditorProfileDraft(metadata, secrets, profile, secret, options = {}) {
 const nextMetadata = clonePlain(metadata || {});
 const nextSecrets = clonePlain(secrets || {});
 const existingProfile = getV16ProfileById(profile.id) || {};
 const existingSecret = getV16Secrets()?.[profile.id] || {};
 const previousId = getV16ActiveAccountProfile()?.id || profile.id;
 nextMetadata.profiles = [profile];
 nextMetadata.ui = { ...(nextMetadata.ui || {}), selectedProfileId: profile.id };
 if (previousId !== profile.id && nextSecrets[previousId] && !nextSecrets[profile.id]) {
 nextSecrets[profile.id] = nextSecrets[previousId];
 delete nextSecrets[previousId];
 }

 const hasKeys = !!(String(secret?.tradingKey || '').trim() && String(secret?.tradingSecret || '').trim());
 const hasAnySecretDraft = !!(String(secret?.tradingKey || '').trim() || String(secret?.tradingSecret || '').trim() || String(secret?.label || '').trim());
 const keepNativeCredential = !hasKeys && v16UsesNativeCredential(profile);

 if (options.setActive || !nextMetadata.activeProfileId || (hasKeys && profile.capability !== 'Public')) {
 nextMetadata.activeProfileId = profile.id;
 }
 nextMetadata.updatedAt = Date.now();

 if (hasKeys || hasAnySecretDraft) {
 nextSecrets[profile.id] = secret;
 } else if (keepNativeCredential) {
 nextSecrets[profile.id] = {
 tradingKey: '',
 tradingSecret: '',
 label: String(existingSecret?.label || profile?.credentialLabel || existingProfile?.credentialLabel || '').trim(),
 updatedAt: Date.now(),
 };
 } else {
 delete nextSecrets[profile.id];
 }

 return { metadata: nextMetadata, secrets: nextSecrets };
}

function buildV16PriceLookup(scanResults = []) {
 const lookup = new Map();
 (Array.isArray(scanResults) ? scanResults : []).forEach(result => {
 const symbol = typeof sanitizeAnalyticsSymbol === 'function'
 ? sanitizeAnalyticsSymbol(result?.symbol)
 : String(result?.symbol || '').toUpperCase().trim();
 if (!symbol) return;
 lookup.set(symbol, Number(result?.price || result?.entry || 0));
 });
 return lookup;
}

function buildV16SessionSummary(snapshot = {}) {
 const profile = getV16ActiveAccountProfile();
 const scanResults = Array.isArray(snapshot.scanResults) ? snapshot.scanResults : [];
 const alerts = Array.isArray(snapshot.alerts) ? snapshot.alerts : [];
 const trades = [];
 const positions = Array.isArray(snapshot.analyticsPositions) ? snapshot.analyticsPositions : [];
 const marketIndex = snapshot.marketIndex || null;
 const prices = buildV16PriceLookup(scanResults);

 let manualPnl = 0;
 positions.forEach(position => {
 const symbol = typeof sanitizeAnalyticsSymbol === 'function'
 ? sanitizeAnalyticsSymbol(position?.symbol)
 : String(position?.symbol || '').toUpperCase().trim();
 const lastPrice = Number(prices.get(symbol) || 0);
 const entry = typeof toPosNum === 'function' ? toPosNum(position?.entry) : Number(position?.entry || 0);
 const qtyValue = typeof toPosNum === 'function' ? toPosNum(position?.qty) : Number(position?.qty || 0);
 const tradeValue = typeof toPosNum === 'function' ? toPosNum(position?.tradeValue) : Number(position?.tradeValue || 0);
 const qty = qtyValue > 0 ? qtyValue : (tradeValue > 0 && entry > 0 ? tradeValue / entry : 0);
 if (!symbol || !lastPrice || !entry || !qty) return;
 const direction = String(position?.side || 'long') === 'short' ? -1 : 1;
 manualPnl += (lastPrice - entry) * qty * direction;
 });

 const openTrades = trades.filter(trade => String(trade?.status || '').toLowerCase() === 'open');
 const closedTrades = trades.filter(trade => String(trade?.status || '').toLowerCase() === 'closed');
 const sessionBaseline = Number(profile.sessionStartBalance || profile.baseBalance || 0);
 const dailyLossCash = sessionBaseline > 0 ? sessionBaseline * Number(profile.dailyLossLimitPct || 0) / 100 : 0;
 const sessionPnl = manualPnl;
 const sessionPct = sessionBaseline > 0 ? (sessionPnl / sessionBaseline) * 100 : 0;
 const longSignals = scanResults.filter(result => String(result?.direction || '').includes('long')).length;
 const shortSignals = scanResults.filter(result => String(result?.direction || '').includes('short')).length;
 const executeCount = alerts.filter(alert => String(alert?.alertTier || '').toLowerCase() === 'execute').length;
 const breadth = longSignals - shortSignals;
 const condition = String(marketIndex?.condition || 'neutral').toLowerCase();
 const directionLabel = condition === 'euphoric' ? 'Euphoric'
 : condition === 'bull' ? 'Bullish'
 : condition === 'bear' ? 'Bearish'
 : condition === 'crash' ? 'Risk-Off'
 : 'Balanced';
 const directionTone = condition === 'euphoric' || condition === 'bull' ? 'good'
 : condition === 'bear' || condition === 'crash' ? 'bad'
 : 'warn';
 const regimeMeta = getMarketRegimeMeta(marketIndex?.regime);
 const thresholds = getRegimeThresholds(marketIndex?.regime, marketIndex?.thresholds || {});
 const thresholdCopy = `Execute >= ${thresholds.alertScore} | Setup >= ${thresholds.setupScore} | Watch >= ${thresholds.watchScore}`;
 const regimeCopy = marketIndex?.value != null
 ? `${directionLabel} direction | ${regimeMeta.label} volatility structure | ${Number(marketIndex.value) >= 0 ? '+' : ''}${Number(marketIndex.value).toFixed(2)}% FWD-10`
 : `Breadth ${breadth >= 0 ? '+' : ''}${breadth} with ${scanResults.length} live signals`;
 return {
 profile,
 manualPnl,
 sessionPnl,
 sessionPct,
 sessionBaseline,
 dailyLossCash,
 openTrades,
 closedTrades,
 executeCount,
 longSignals,
 shortSignals,
 breadth,
 marketIndex,
 regimeLabel: regimeMeta.label,
 regimeTone: regimeMeta.tone === 'muted' ? 'warn' : regimeMeta.tone,
 directionLabel,
 directionTone,
 regimeCopy,
 thresholdCopy,
 thresholds,
 lastScan: snapshot.lastScan || '',
 killSwitchSuggested: dailyLossCash > 0 && sessionPnl <= -dailyLossCash,
 };
}

