async function switchV16Capability(capability) {
 await loadV16AccountState();
 const nextCapability = sanitizeAccountCapability(capability);
 const metadata = clonePlain(getV16Metadata());
 const secrets = clonePlain(getV16Secrets());
 const profile = createAccountProfile({
 ...getV16ActiveAccountProfile(),
 capability: nextCapability,
 updatedAt: Date.now(),
 });
 metadata.profiles = [profile];
 metadata.activeProfileId = profile.id;
 metadata.ui = { ...(metadata.ui || {}), selectedProfileId: profile.id };
 metadata.updatedAt = Date.now();
 await persistV16AccountState(metadata, secrets);
 await renderV16All();
}

async function setV16KillSwitch(enabled, reason = '') {
 await loadV16AccountState();
 const metadata = clonePlain(getV16Metadata());
 metadata.killSwitch = sanitizeKillSwitchState({
 enabled: !!enabled,
 reason: enabled ? sanitizeText(reason || 'Execution locked', 'Execution locked', 140) : '',
 scope: 'global',
 triggeredBy: 'v16-ui',
 updatedAt: Date.now(),
 });
 metadata.updatedAt = Date.now();
 await persistV16AccountState(metadata, getV16Secrets());
 await renderV16All();
}

