function v16NormalizeFill(fill = {}) {
 const product = fill?.product || fill?.contract || {};
 const metaData = fill?.meta_data || fill?.metaData || {};
 const size = Math.abs(v16NumericField(fill, ['size', 'filled_size', 'fill_size', 'filled_qty', 'qty', 'quantity', 'executed_size', 'base_asset_quantity', 's']))
 || Math.abs(v16NumericField(metaData, ['size', 'filled_size', 'filled_qty', 'qty', 'quantity']));
 const price = v16NumericField(fill, ['price', 'fill_price', 'average_fill_price', 'avg_price', 'executed_price', 'execution_price', 'p', 'limit_price'])
 || v16NumericField(metaData, ['price', 'fill_price', 'average_fill_price', 'avg_price', 'execution_price', 'limit_price']);
 const side = String(v16TextField(fill, ['side', 'S'], 'buy')).toLowerCase() === 'sell' ? 'sell' : 'buy';
 const productId = v16TextField(fill, ['product_id'], v16TextField(product, ['id', 'product_id'], ''));
 return {
 id: v16TextField(fill, ['id', 'fill_id', 'order_id', 'f', 'o'], `fill_${Date.now()}`),
 orderId: v16TextField(fill, ['order_id', 'id', 'o'], ''),
 clientOrderId: v16TextField(fill, ['client_order_id'], v16TextField(metaData, ['client_order_id'], '')),
 symbol: v16NormalizeSymbol(v16TextField(fill, ['product_symbol', 'productSymbol', 'symbol', 'sy', 'contract_symbol'], v16TextField(product, ['symbol', 'product_symbol', 'code'], v16TextField(metaData, ['symbol', 'product_symbol'], productId ? `PRODUCT-${productId}` : '')))),
 side,
 size,
 price,
 commission: v16NumericField(fill, ['commission', 'paid_commission', 'commission_paid', 'fee', 'fees', 'trading_fee']) || v16NumericField(metaData, ['commission', 'fee', 'fees']),
 createdAt: v16ToEpochMs(v16TextField(fill, ['created_at', 'updated_at', 'timestamp', 'createdAt', 't', 'time']) || fill?.created_at || fill?.updated_at || fill?.time || metaData?.created_at || metaData?.updated_at || metaData?.timestamp || 0),
 raw: fill,
 };
}

function v16NormalizePosition(position = {}, priceLookup = new Map()) {
 const productId = v16TextField(position, ['product_id', 'id'], '');
 const symbol = v16NormalizeSymbol(v16TextField(position, ['product_symbol', 'symbol'], productId ? `PRODUCT-${productId}` : ''));
 const sizeValue = v16NumericField(position, ['size', 'net_size', 'balance']);
 const size = Math.abs(sizeValue);
 const side = sizeValue < 0 ? 'short' : 'long';
 const entry = v16NumericField(position, ['entry_price', 'avg_entry_price', 'average_entry_price']);
 const markPrice = v16NumericField(position, ['mark_price', 'current_price', 'spot_price', 'close']) || Number(priceLookup.get(symbol) || 0);
 const unrealized = v16NumericField(position, ['unrealized_pnl', 'unrealised_pnl', 'open_pnl', 'pnl']);
 const realized = v16NumericField(position, ['realized_pnl', 'realised_pnl', 'closed_pnl']);
 const liquidation = v16NumericField(position, ['liquidation_price']);
 const margin = v16NumericField(position, ['margin', 'position_margin', 'margin_used']);
 const createdAt = v16ToEpochMs(v16TextField(position, ['created_at', 'createdAt', 'timestamp']) || position?.created_at || position?.createdAt || position?.timestamp || 0);
 const updatedAt = v16ToEpochMs(v16TextField(position, ['updated_at', 'updatedAt', 'timestamp']) || position?.updated_at || position?.updatedAt || position?.timestamp || 0);
 const computedUnrealized = (!unrealized && markPrice > 0 && entry > 0 && size > 0)
 ? (side === 'short' ? (entry - markPrice) * size : (markPrice - entry) * size)
 : unrealized;
 return {
 id: v16TextField(position, ['id', 'product_id'], symbol),
 symbol,
 side,
 size,
 entry,
 markPrice,
 unrealized: computedUnrealized,
 realized,
 liquidation,
 margin,
 createdAt,
 updatedAt,
 raw: position,
 };
}

function v16NormalizeFundingIntervalSeconds(value, fallback = 28800) {
 const n = Number(value || 0);
 if (!Number.isFinite(n) || n <= 0) return fallback;
 return Math.round(n);
}

function v16FundingEventsPerDay(intervalSeconds = 28800) {
 const interval = v16NormalizeFundingIntervalSeconds(intervalSeconds);
 return 86400 / interval;
}

function v16FundingIntervalHours(intervalSeconds = 28800) {
 return v16NormalizeFundingIntervalSeconds(intervalSeconds) / 3600;
}

function v16PositionFundingHorizonLabel(horizon = '24h') {
 return String(horizon || '24h') === '365d' ? '365d' : '24h';
}

function v16ResolveFundingHorizonEstimate(fundingEstimate = {}, horizon = '24h') {
 const perSettlement = Number(fundingEstimate?.estimatedFunding || 0);
 const eventsPerDay = Number(fundingEstimate?.eventsPerDay || v16FundingEventsPerDay(fundingEstimate?.intervalSeconds || 28800));
 if (!perSettlement || !Number.isFinite(eventsPerDay) || eventsPerDay <= 0) return 0;
 return v16PositionFundingHorizonLabel(horizon) === '365d'
 ? +(perSettlement * eventsPerDay * 365).toFixed(4)
 : +(perSettlement * eventsPerDay).toFixed(4);
}

function v16FormatFundingRateLabel(fundingEstimate = {}, horizon = '24h') {
 const rate = Number(fundingEstimate?.fundingRate || 0);
 const intervalHours = v16FundingIntervalHours(fundingEstimate?.intervalSeconds || 28800);
 const eventsPerDay = v16FundingEventsPerDay(fundingEstimate?.intervalSeconds || 28800);
 const signedRate = `${rate >= 0 ? '+' : ''}${v16FmtNumber(rate, 4)}%`;
 if (v16PositionFundingHorizonLabel(horizon) === '365d') {
 return `${signedRate} / ${v16FmtNumber(intervalHours, intervalHours % 1 ? 1 : 0)}h -> ${v16FmtNumber(eventsPerDay * 365, 0)}x/365d`;
 }
 return `${signedRate} / ${v16FmtNumber(intervalHours, intervalHours % 1 ? 1 : 0)}h -> ${v16FmtNumber(eventsPerDay, eventsPerDay % 1 ? 1 : 0)}x/24h`;
}

function v16BuildPositionFundingLookup(scanResults = [], fundingHeatmap = []) {
 const lookup = new Map();
 const add = (symbol = '', fundingRate = 0, nextFundingAt = 0, fundingIntervalSeconds = 28800) => {
 const normalized = v16NormalizeSymbol(symbol);
 if (!normalized) return;
 const item = {
 fundingRate: Number(fundingRate || 0),
 nextFundingAt: Number(nextFundingAt || 0),
 intervalSeconds: v16NormalizeFundingIntervalSeconds(fundingIntervalSeconds),
 };
 lookup.set(normalized, item);
 const base = normalized.replace(/(USD|USDT)$/, '');
 if (!base) return;
 if (!lookup.has(base)) lookup.set(base, item);
 if (!lookup.has(`${base}USD`)) lookup.set(`${base}USD`, item);
 if (!lookup.has(`${base}USDT`)) lookup.set(`${base}USDT`, item);
 };
 (Array.isArray(scanResults) ? scanResults : []).forEach(item => add(item?.symbol, item?.fundingRate, item?.nextFundingAt, item?.fundingIntervalSeconds));
 (Array.isArray(fundingHeatmap) ? fundingHeatmap : []).forEach(item => add(item?.symbol, item?.fundingRate, item?.nextFundingAt, item?.fundingIntervalSeconds));
 return lookup;
}

function v16ResolvePositionNotional(position = {}) {
 const displayUnit = String(position.displayUnit || 'contracts').trim().toLowerCase();
 const quantity = displayUnit === 'contracts'
 ? Math.abs(Number(position.size || 0))
 : Math.abs(Number(position.displaySize || 0));
 const referencePrice = Math.abs(Number(position.markPrice || position.entry || 0));
 if (!quantity || !referencePrice) return 0;
 return +(quantity * referencePrice).toFixed(4);
}

function v16ResolvePositionFundingEstimate(position = {}, fundingLookup = new Map()) {
 const normalized = v16NormalizeSymbol(position.symbol || '');
 const base = normalized.replace(/(USD|USDT)$/, '');
 const fundingInfo = fundingLookup.get(normalized)
 || fundingLookup.get(base)
 || fundingLookup.get(`${base}USD`)
 || fundingLookup.get(`${base}USDT`)
 || { fundingRate: 0, nextFundingAt: 0 };
 const fundingRate = Number(fundingInfo.fundingRate || 0);
 const nextFundingAt = Number(fundingInfo.nextFundingAt || 0);
 const intervalSeconds = v16NormalizeFundingIntervalSeconds(fundingInfo.intervalSeconds || 28800);
 const notional = v16ResolvePositionNotional(position);
 const estimatedFunding = notional > 0 && fundingRate
 ? +(notional * (fundingRate / 100) * (position.side === 'short' ? 1 : -1)).toFixed(4)
 : 0;
 return {
 fundingRate,
 nextFundingAt,
 intervalSeconds,
 intervalHours: v16FundingIntervalHours(intervalSeconds),
 eventsPerDay: v16FundingEventsPerDay(intervalSeconds),
 estimated24h: v16ResolveFundingHorizonEstimate({ estimatedFunding, intervalSeconds }, '24h'),
 estimated365d: v16ResolveFundingHorizonEstimate({ estimatedFunding, intervalSeconds }, '365d'),
 estimatedFunding,
 };
}

