function v16ResolveSetupPromotion(row = {}) {
 const trades = Number(row?.trades || 0);
 const expectancy = Number(row?.expectancy || 0);
 const liveCount = Number(row?.liveCount || 0);
 if (trades <= 0 && liveCount > 0) return { label: 'Stage 1 Watch', tone: 'info', copy: 'Live signal only; wait for paper closes.' };
 if (trades < 20) return { label: 'Stage 2 Paper', tone: 'warn', copy: `${trades}/20 closed samples before edge validation.` };
 if (expectancy > 0) return { label: 'Stage 3 Small Live', tone: 'good', copy: 'Positive sample; keep size controlled until manually promoted.' };
 return { label: 'Stage 1 Watch', tone: 'bad', copy: 'Weak sample; avoid live promotion.' };
}

function v16RenderAnalyticsReliabilityPanel(snapshot = {}, analyticsModel = null, shadowLedger = {}) {
 const wrap = document.getElementById('liveAnalyticsReliabilityPanel');
 if (!wrap) return;
 storeGet(['autoScan', 'autoScanInterval', 'scanStatus', 'scanActive', 'lastScan', 'lastScanTs', 'autoTradeSettings', V16_SHADOW_TRADE_LEDGER_KEY, 'apiCircuitBreaker']).then(store => {
 const now = Date.now();
 const lastScanTs = Number(store?.lastScanTs || 0);
 const scanAgeMs = lastScanTs > 0 ? now - lastScanTs : 0;
 const autoScan = store?.autoScan === true;
 const settings = sanitizeAutoTradeSettings(store?.autoTradeSettings || {});
 const ledger = shadowLedger && typeof shadowLedger === 'object' ? shadowLedger : (store?.[V16_SHADOW_TRADE_LEDGER_KEY] || {});
 const ledgerUpdatedAt = Number(ledger?.updatedAt || 0);
 const paperFresh = ledgerUpdatedAt > 0 && (now - ledgerUpdatedAt) < Math.max(20 * 60 * 1000, Number(store?.autoScanInterval || 5) * 3 * 60 * 1000);
 const apiBlocked = !!store?.apiCircuitBreaker?.blockedUntil && Number(store.apiCircuitBreaker.blockedUntil || 0) > now;
 const items = [
 { label: 'Auto Scan', value: autoScan ? 'Running' : 'Stopped', tone: autoScan ? 'good' : 'bad', detail: autoScan ? `Every ${Number(store?.autoScanInterval || 0) || '?'} min | last ${store?.lastScan || 'pending'}` : 'Enable auto scan to collect paper data.' },
 { label: 'Paper Tracking', value: settings.paperTrackingEnabled ? 'On' : 'Off', tone: settings.paperTrackingEnabled ? 'good' : 'bad', detail: settings.paperTrackingEnabled ? `${Number(ledger?.open?.length || 0)} open | ${Number(ledger?.closed?.length || 0)} closed` : 'Paper ledger is disabled in Settings.' },
 { label: 'Last Paper Update', value: ledgerUpdatedAt ? v16FormatDurationShort(now - ledgerUpdatedAt) : 'None', tone: paperFresh ? 'good' : (ledgerUpdatedAt ? 'warn' : 'bad'), detail: ledgerUpdatedAt ? `Updated ${v16FormatTs(ledgerUpdatedAt)}` : 'No paper ledger update yet.' },
 { label: 'App Lock', value: 'Safe for paper', tone: 'info', detail: 'The 15-minute app lock does not close the background scanner while the app stays open and Windows is awake.' },
 { label: 'Sleep Risk', value: 'PC must stay awake', tone: 'warn', detail: 'Closing the app or Windows sleep stops scan, paper tracking, and live automation.' },
 { label: 'API/Data', value: apiBlocked ? 'Blocked' : (lastScanTs ? (scanAgeMs < 20 * 60 * 1000 ? 'Fresh' : 'Stale') : 'Pending'), tone: apiBlocked ? 'bad' : (lastScanTs && scanAgeMs < 20 * 60 * 1000 ? 'good' : 'warn'), detail: apiBlocked ? 'API circuit breaker is active.' : (lastScanTs ? `Last scan ${v16FormatDurationShort(scanAgeMs)} ago.` : 'No scan timestamp yet.') },
 ];
 wrap.innerHTML = `
 <section class="risk-manage-setup-shell">
 <div class="risk-manage-section-label">BACKGROUND RELIABILITY</div>
 <div class="live-order-audit-grid live-system-health-grid compact">
 ${items.map(item => `<div class="live-system-health-item live-system-health-item--${v16Esc(item.tone)}"><span>${v16Esc(item.label)}</span><strong class="${v16Esc(item.tone)}">${v16Esc(item.value)}</strong><small>${v16Esc(item.detail)}</small></div>`).join('')}
 </div>
 </section>`;
 }).catch(() => {
 wrap.innerHTML = `<div class="account-inline-note warn">Background reliability status is unavailable right now.</div>`;
 });
}

