function v16DownloadCsv(filename = '', headers = [], rows = []) {
 const csvEsc = v => `"${String(v ?? '').replace(/"/g, '""').replace(/\n/g, ' ')}"`;
 const csv = [headers.map(csvEsc).join(','), ...rows.map(row => row.map(csvEsc).join(','))].join('\n');
 const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
 const url = URL.createObjectURL(blob);
 const a = document.createElement('a');
 a.href = url;
 a.download = filename || `fwd_tradedesk_report_${new Date().toISOString().slice(0, 10)}.csv`;
 document.body.appendChild(a);
 a.click();
 document.body.removeChild(a);

// Live analytics charts, setup report and equity visualization
 URL.revokeObjectURL(url);
}

function v16ExportSetupPerformanceReport() {
 const rows = Array.isArray(v16LiveAnalyticsSetupCache?.rows) ? v16LiveAnalyticsSetupCache.rows : [];
 const headers = ['Setup', 'Stage', 'Closed Trades', 'Paper Trades', 'Live Trades', 'Win Rate', 'Expectancy', 'Avg R', 'Max Drawdown', 'Live Now', 'Regime Fit'];
 const csvRows = rows.map(row => {
 const stage = v16ResolveSetupPromotion(row);
 return [
 row.family,
 stage.label,
 Number(row.trades || 0),
 Number(row.paperTrades || 0),
 Number(row.liveTrades || 0),
 Number(row.winRate || 0),
 Number(row.expectancy || 0),
 row.avgR == null ? '' : Number(row.avgR || 0),
 Number(row.maxDrawdown || 0),
 Number(row.liveCount || 0),
 `${Number(row.regimeFitCount || 0)}/${Number(row.liveCount || 0)}`,
 ];
 });
 v16DownloadCsv(`fwd_tradedesk_setup_performance_${new Date().toISOString().slice(0, 10)}.csv`, headers, csvRows);
}

async function v16LoadLiveAnalyticsView(force = false) {
 if (!force && v16LiveAnalyticsViewLoaded) return v16LiveAnalyticsView;
 const stored = await storeGet(V16_LIVE_ANALYTICS_VIEW_KEY);
 v16LiveAnalyticsView = v16NormalizeLiveAnalyticsView(stored?.[V16_LIVE_ANALYTICS_VIEW_KEY] || {});
 v16LiveAnalyticsViewLoaded = true;
 return v16LiveAnalyticsView;
}

async function v16PersistLiveAnalyticsView(patch = {}) {
 v16LiveAnalyticsView = v16NormalizeLiveAnalyticsView({
 ...v16LiveAnalyticsView,
 ...(patch && typeof patch === 'object' ? patch : {}),
 legend: {
 ...(v16LiveAnalyticsView?.legend || {}),
 ...(patch?.legend || {}),
 },
 });
 v16LiveAnalyticsViewLoaded = true;
 await storeSet({ [V16_LIVE_ANALYTICS_VIEW_KEY]: v16LiveAnalyticsView });
 return v16LiveAnalyticsView;
}

function v16AnalyticsStartOfDay(ts = 0) {
 const date = new Date(Number(ts || 0) || Date.now());
 date.setUTCHours(0, 0, 0, 0);
 return date.getTime();
}

function v16LocalStartOfDay(ts = 0) {
 const date = new Date(Number(ts || 0) || Date.now());
 date.setHours(0, 0, 0, 0);
 return date.getTime();
}

function v16AnalyticsFormatDay(ts = 0) {
 return new Date(Number(ts || 0) || Date.now()).toLocaleDateString(undefined, {
 day: '2-digit',
 month: 'short',
 });
}

function v16AnalyticsRangeStart(range = '7d') {
 const now = Date.now();
 const parsed = typeof range === 'number'
 ? Number(range)
 : Number(String(range || '').match(/^(\d{1,3})d$/i)?.[1] || 7);
 const days = Math.min(365, Math.max(1, Number.isFinite(parsed) ? Math.round(parsed) : 7));
 return now - (days * 24 * 60 * 60 * 1000);
}

function v16AnalyticsRangeLabel(days = 7) {
 const safeDays = Math.min(365, Math.max(1, Number(days || 7) || 7));
 return `Last ${safeDays} day${safeDays === 1 ? '' : 's'}`;
}

function v16AnalyticsProductType(symbol = '', productDefinitions = new Map()) {
 const definition = productDefinitions.get(v16NormalizeSymbol(symbol));
 if (definition?.productType === 'options') return 'options';
 if (definition?.productType === 'futures') return 'futures';
 const normalizedSymbol = v16NormalizeSymbol(symbol);
 if (/-\d{1,2}[A-Z]{3}\d{2,4}-/i.test(normalizedSymbol) || /(?:-C|-P)$/i.test(normalizedSymbol)) return 'options';
 return 'futures';
}

function v16AnalyticsMatchesInstrument(symbol = '', productDefinitions = new Map(), instrument = 'all') {
 if (instrument === 'all') return true;
 return v16AnalyticsProductType(symbol, productDefinitions) === instrument;
}

function v16AnalyticsCanUseTradeRecord(trade = {}, productDefinitions = new Map()) {
 const productType = v16AnalyticsProductType(trade.symbol || '', productDefinitions);
 if (productType !== 'options') return true;
 const pnlSource = String(trade?.pnlSource || trade?.source || '').toLowerCase();
 if (pnlSource === 'delta_order' || pnlSource === 'delta') return true;
 const matchedCloseOrderIds = Array.isArray(trade?.matchedCloseOrderIds) ? trade.matchedCloseOrderIds.filter(Boolean) : [];
 if (matchedCloseOrderIds.length) return true;
 const closeReason = String(trade?.closeReason || '').toLowerCase();
 return (
 closeReason.includes('expire')
 || closeReason.includes('assign')
 || closeReason.includes('exercise')
 || closeReason.includes('settlement')
 );
}

function v16AnalyticsDisplaySize(record = {}, productDefinitions = new Map()) {
 const definition = productDefinitions.get(v16NormalizeSymbol(record.symbol || '')) || null;
 return Math.abs(v16DisplayQuantity(
 Number(record.displaySize || 0) > 0 && Number(record.size || 0) > 0
 ? (Number(record.displaySize || 0) / Math.max(1e-12, Number(record.size || 0)))
 : Number(record.size || 0),
 definition
 ));
}

function v16AnalyticsFillNotional(fill = {}, productDefinitions = new Map()) {
 const definition = productDefinitions.get(v16NormalizeSymbol(fill.symbol || '')) || null;
 const multiplier = Number(definition?.displayMultiplier || 1);
 const size = Math.abs(Number(fill.size || 0)) * (multiplier > 0 ? multiplier : 1);
 const price = Math.abs(Number(fill.price || 0));
 return +(size * price).toFixed(4);
}

function v16AnalyticsBucketFactory(ts = 0) {
 return {
 ts,
 label: v16AnalyticsFormatDay(ts),
 realized: 0,
 volume: 0,
 fees: 0,
 rebates: 0,
 funding: 0,
 deposits: 0,
 withdrawals: 0,
 liquidationFees: 0,
 trades: 0,
 wins: 0,
 losses: 0,
 };
}

function v16AnalyticsBuildBucketMap(startTs = 0, endTs = Date.now()) {
 const buckets = [];
 const byTs = new Map();
 let cursor = v16AnalyticsStartOfDay(startTs);
 const end = v16AnalyticsStartOfDay(endTs);
 while (cursor <= end) {
 const bucket = v16AnalyticsBucketFactory(cursor);
 buckets.push(bucket);
 byTs.set(cursor, bucket);
 cursor += 24 * 60 * 60 * 1000;
 }
 if (!buckets.length) {
 const bucket = v16AnalyticsBucketFactory(v16AnalyticsStartOfDay(Date.now()));
 buckets.push(bucket);
 byTs.set(bucket.ts, bucket);
 }
 return { buckets, byTs };
}

function v16AnalyticsWalletAdjustmentValue(tx = {}) {
 return Number(tx.amount || tx.commission || 0);
}

function v16AnalyticsOrderLiquidationFee(order = {}) {
 const text = `${order.explanation || ''} ${order.reason || ''} ${order.role || ''}`.toLowerCase();
 if (!text.includes('liquid')) return 0;
 return Math.max(0, Math.abs(Number(order.commission || 0)));
}

function v16AnalyticsIsClosedOrder(order = {}) {
 return v16IsClosedRealizedOrder(order);
}

function v16BuildAnalyticsClosedRecords(metrics = {}, productDefinitions = new Map(), rangeStart = 0, instrument = 'all') {
 const tradeRecords = (metrics.trades || [])
 .filter(trade => Number(trade.closedAt || 0) >= rangeStart)
 .filter(trade => v16AnalyticsMatchesInstrument(trade.symbol, productDefinitions, instrument))
 .filter(trade => v16AnalyticsCanUseTradeRecord(trade, productDefinitions))
 .map(trade => ({
 id: String(trade.id || `${trade.symbol}_${trade.closedAt}`),
 symbol: trade.symbol,
 side: trade.side,
 size: Number(trade.size || 0),
 pnl: +Number(trade.pnl || 0).toFixed(6),
 commission: +Math.abs(Number(trade.commission || 0)).toFixed(6),
 closedAt: Number(trade.closedAt || 0),
 explanation: '',
 source: String(trade.source || 'reconstructed'),
 raw: trade,
 }));
 if (tradeRecords.length) return tradeRecords.sort((a, b) => Number(b.closedAt || 0) - Number(a.closedAt || 0));
 const orderRecords = (metrics.orderHistory || [])
 .filter(order => Number(order.createdAt || 0) >= rangeStart)
 .filter(order => v16AnalyticsMatchesInstrument(order.symbol, productDefinitions, instrument))
 .filter(v16AnalyticsIsClosedOrder)
 .map(order => ({
 id: `delta_order_${String(order.id || order.orderId || `${order.symbol}_${order.createdAt}`)}`,
 symbol: order.symbol,
 side: String(order.side || '').toLowerCase() === 'sell' ? 'short' : 'long',
 size: Number(order.size || 0),
 pnl: +Number(v16ResolveOrderRealizedPnl(order) || 0).toFixed(6),
 commission: +Math.abs(Number(order.commission || 0)).toFixed(6),
 closedAt: Number(order.createdAt || 0),
 explanation: String(order.explanation || ''),
 source: 'delta_order',
 raw: order,
 }));
 if (orderRecords.length) return orderRecords.sort((a, b) => Number(b.closedAt || 0) - Number(a.closedAt || 0));
 return [];
}

function v16BuildLiveAnalyticsModel(metrics = {}, productDefinitions = new Map(), view = {}) {
 const normalizedView = v16NormalizeLiveAnalyticsView(view);
 const rangeStart = v16AnalyticsRangeStart(normalizedView.rangeDays);
 const now = Date.now();
 const { buckets, byTs } = v16AnalyticsBuildBucketMap(rangeStart, now);
 const bucketForTs = (ts) => byTs.get(v16AnalyticsStartOfDay(ts)) || buckets[buckets.length - 1];
 const closedRecords = v16BuildAnalyticsClosedRecords(metrics, productDefinitions, rangeStart, normalizedView.instrument);
 const fills = (metrics.fills || [])
 .filter(fill => Number(fill.createdAt || 0) >= rangeStart)
 .filter(fill => v16AnalyticsMatchesInstrument(fill.symbol, productDefinitions, normalizedView.instrument));
 const positions = (metrics.positions || [])
 .filter(position => v16AnalyticsMatchesInstrument(position.symbol, productDefinitions, normalizedView.instrument));
 const orderHistory = (metrics.orderHistory || [])
 .filter(order => Number(order.createdAt || 0) >= rangeStart)
 .filter(order => v16AnalyticsMatchesInstrument(order.symbol, productDefinitions, normalizedView.instrument));
 const walletTransactions = (metrics.walletTransactions || [])
 .filter(item => Number(item.createdAt || 0) >= rangeStart);

 closedRecords.forEach(record => {
 const bucket = bucketForTs(record.closedAt);
 const pnl = Number(record.pnl || 0);
 bucket.realized += pnl;
 bucket.trades += 1;
 if (pnl > 0) bucket.wins += 1;
 else if (pnl < 0) bucket.losses += 1;
 });

 fills.forEach(fill => {
 const bucket = bucketForTs(fill.createdAt);
 bucket.volume += v16AnalyticsFillNotional(fill, productDefinitions);
 const commission = Number(fill.commission || 0);
 if (commission >= 0) bucket.fees += Math.abs(commission);
 else bucket.rebates += Math.abs(commission);
 });

 walletTransactions.forEach(tx => {
 const bucket = bucketForTs(tx.createdAt);
 const role = v16WalletTransactionRole(tx);
 const amount = v16AnalyticsWalletAdjustmentValue(tx);
 if (role === 'funding' && normalizedView.instrument !== 'options') bucket.funding += amount;
 if (role === 'deposit') bucket.deposits += Math.abs(amount);
 if (role === 'withdrawal') bucket.withdrawals += Math.abs(amount);
 if (role === 'liquidation_fee') bucket.liquidationFees += Math.abs(amount);
 if (role === 'fee' && normalizedView.instrument === 'all' && !fills.length) bucket.fees += Math.abs(amount);
 if (role === 'rebate' && normalizedView.instrument === 'all' && !fills.length) bucket.rebates += Math.abs(amount);
 });

 orderHistory.forEach(order => {
 const liquidationFee = v16AnalyticsOrderLiquidationFee(order);
 if (!liquidationFee) return;
 const bucket = bucketForTs(order.createdAt);
 bucket.liquidationFees += liquidationFee;
 });

 const wins = closedRecords.filter(record => Number(record.pnl || 0) > 0);
 const losses = closedRecords.filter(record => Number(record.pnl || 0) < 0);
 const totalRealized = closedRecords.reduce((sum, record) => sum + Number(record.pnl || 0), 0);
 const totalVolume = buckets.reduce((sum, bucket) => sum + Number(bucket.volume || 0), 0);
 const totalFees = buckets.reduce((sum, bucket) => sum + Number(bucket.fees || 0), 0);
 const totalRebates = buckets.reduce((sum, bucket) => sum + Number(bucket.rebates || 0), 0);
 const totalFunding = buckets.reduce((sum, bucket) => sum + Number(bucket.funding || 0), 0);
 const totalDeposits = buckets.reduce((sum, bucket) => sum + Number(bucket.deposits || 0), 0);
 const totalWithdrawals = buckets.reduce((sum, bucket) => sum + Number(bucket.withdrawals || 0), 0);
 const totalLiquidationFees = buckets.reduce((sum, bucket) => sum + Number(bucket.liquidationFees || 0), 0);
 const selectedUnrealized = positions.reduce((sum, position) => sum + Number(position.unrealized || 0), 0);
 const hasOpenOptionExposure = normalizedView.instrument === 'options' && positions.length > 0;
 const totalTradingChange = buckets.reduce((sum, bucket) => (
 sum
 + Number(bucket.realized || 0)
 - Number(bucket.fees || 0)
 + Number(bucket.rebates || 0)
 + Number(bucket.funding || 0)
 - Number(bucket.liquidationFees || 0)
 ), 0);
 const absoluteMode = normalizedView.instrument === 'all';
 const baseEquity = absoluteMode
 ? Number(metrics.walletBalance || 0) - (totalDeposits - totalWithdrawals) - totalTradingChange - selectedUnrealized
 : 0;

 let runningEquity = baseEquity;
 const equitySeries = buckets.map((bucket, index) => {
 runningEquity += Number(bucket.realized || 0) - Number(bucket.fees || 0) + Number(bucket.rebates || 0) + Number(bucket.funding || 0) - Number(bucket.liquidationFees || 0);
 const equity = runningEquity + (index === buckets.length - 1 ? selectedUnrealized : 0);
 return {
 ts: bucket.ts,
 label: bucket.label,
 equity: +equity.toFixed(4),
 realized: +Number(bucket.realized || 0).toFixed(4),
 volume: +Number(bucket.volume || 0).toFixed(4),
 fees: +Number(bucket.fees || 0).toFixed(4),
 funding: +Number(bucket.funding || 0).toFixed(4),
 deposits: +Number(bucket.deposits || 0).toFixed(4),
 withdrawals: +Number(bucket.withdrawals || 0).toFixed(4),
 liquidationFees: +Number(bucket.liquidationFees || 0).toFixed(4),
 trades: bucket.trades,
 };
 });

 return {
 view: normalizedView,
 rangeStart,
 instrumentLabel: normalizedView.instrument === 'all'
 ? 'All instruments'
 : normalizedView.instrument === 'options'
 ? 'Options only'
 : 'Futures only',
 equityMode: absoluteMode ? 'absolute' : 'relative',
 equitySeries,
 realizedPnlSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.realized || 0).toFixed(4) })),
 volumeSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.volume || 0).toFixed(4) })),
 feesSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.fees || 0).toFixed(4) })),
 fundingSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.funding || 0).toFixed(4) })),
 depositSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.deposits || 0).toFixed(4) })),
 withdrawalSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.withdrawals || 0).toFixed(4) })),
 liquidationFeeSeries: buckets.map(bucket => ({ ts: bucket.ts, label: bucket.label, value: +Number(bucket.liquidationFees || 0).toFixed(4) })),
 positions,
 fills,
 orderHistory,
 closedRecords: closedRecords.sort((a, b) => Number(b.closedAt || 0) - Number(a.closedAt || 0)),
 trades: closedRecords.sort((a, b) => Number(b.closedAt || 0) - Number(a.closedAt || 0)),
 tradeCount: closedRecords.length,
 primaryPnlLabel: hasOpenOptionExposure ? 'OPEN P&L' : 'REALIZED P&L',
 primaryPnlValue: hasOpenOptionExposure ? selectedUnrealized : totalRealized,
 primaryPnlMeta: hasOpenOptionExposure
 ? `Mark-to-market across ${positions.length} live option position${positions.length === 1 ? '' : 's'} from Delta positions.`
 : `${closedRecords.length} closed trade${closedRecords.length === 1 ? '' : 's'} in range.`,
 usesDeltaOptionMtM: hasOpenOptionExposure,
 realized: totalRealized,
 winRate: closedRecords.length ? ((wins.length / closedRecords.length) * 100) : 0,
 avgWin: wins.length ? (wins.reduce((sum, record) => sum + Number(record.pnl || 0), 0) / wins.length) : 0,
 avgLoss: losses.length ? (losses.reduce((sum, record) => sum + Number(record.pnl || 0), 0) / losses.length) : 0,
 volume: totalVolume,
 fees: totalFees,
 rebates: totalRebates,
 funding: totalFunding,
 deposits: totalDeposits,
 withdrawals: totalWithdrawals,
 liquidationFees: totalLiquidationFees,
 unrealized: selectedUnrealized,
 endingEquity: equitySeries[equitySeries.length - 1]?.equity || 0,
 };
}

function v16GetAnalyticsEquityChartModel(model = {}) {
 const series = Array.isArray(model.equitySeries) ? model.equitySeries : [];
 if (!series.length) return null;
 const width = 860;
 const height = 260;
 const padX = 28;
 const padY = 24;
 const values = series.map(point => Number(point.equity || 0));
 const min = Math.min(...values, 0);
 const max = Math.max(...values, 0);
 const range = Math.max(1, max - min);
 const zeroY = height - padY - (((0 - min) / range) * (height - padY * 2));
 const points = series.map((point, index) => {
 const x = padX + ((width - padX * 2) * index / Math.max(1, series.length - 1));
 const y = height - padY - (((Number(point.equity || 0) - min) / range) * (height - padY * 2));
 return { ...point, x, y };
 });
 return {
 width,
 height,
 padX,
 padY,
 zeroY,
 points,
 isNegative: values[values.length - 1] < 0,
 };
}

function v16BuildAnalyticsEquityChart(model = {}) {
 const chartModel = v16GetAnalyticsEquityChartModel(model);
 if (!chartModel) {
 return `<div class="empty"><div class="ei">--</div><div class="eh">No analytics history yet</div><div class="es">Refresh live data to build the selected range.</div></div>`;
 }
 const { width, height, padX, padY, zeroY, points, isNegative } = chartModel;
 const path = points.map(point => `${point.x.toFixed(1)},${point.y.toFixed(1)}`).join(' ');
 const depositMarkers = model.view?.legend?.deposits
 ? points.filter(point => Number(point.deposits || 0) > 0).map(point => `<circle cx="${point.x.toFixed(1)}" cy="${point.y.toFixed(1)}" r="4" class="analytics-event-marker deposits"><title>${v16Esc(point.label)} deposit ${v16FmtSigned(point.deposits)}</title></circle>`).join('')
 : '';
 const withdrawalMarkers = model.view?.legend?.withdrawals
 ? points.filter(point => Number(point.withdrawals || 0) > 0).map(point => `<circle cx="${point.x.toFixed(1)}" cy="${point.y.toFixed(1)}" r="4" class="analytics-event-marker withdrawals"><title>${v16Esc(point.label)} withdrawal ${v16FmtSigned(-point.withdrawals)}</title></circle>`).join('')
 : '';
 const liquidationMarkers = model.view?.legend?.liquidationFees
 ? points.filter(point => Number(point.liquidationFees || 0) > 0).map(point => `<circle cx="${point.x.toFixed(1)}" cy="${point.y.toFixed(1)}" r="4" class="analytics-event-marker liquidation"><title>${v16Esc(point.label)} liquidation fee ${v16FmtSigned(-point.liquidationFees)}</title></circle>`).join('')
 : '';
 const xLabels = points.filter((_, index) => index === 0 || index === points.length - 1 || index === Math.floor((points.length - 1) / 2))
 .map(point => `<span style="left:${((point.x / width) * 100).toFixed(2)}%">${v16Esc(point.label)}</span>`)
 .join('');
 return `<div class="live-analytics-equity-plot ${isNegative ? 'negative' : 'positive'}">
 <svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none" class="live-analytics-equity-svg">
 <line x1="${padX}" y1="${zeroY.toFixed(1)}" x2="${width - padX}" y2="${zeroY.toFixed(1)}" class="live-equity-zero"></line>
 <polyline fill="none" stroke="url(#liveAnalyticsStroke)" stroke-width="3.2" stroke-linecap="round" stroke-linejoin="round" points="${path}"></polyline>
 <defs>
 <linearGradient id="liveAnalyticsStroke" x1="0" y1="${padY}" x2="0" y2="${height - padY}" gradientUnits="userSpaceOnUse">
 <stop offset="0%" stop-color="#4fd1ff"></stop>
 <stop offset="100%" stop-color="${isNegative ? '#ff6b82' : '#1de9b6'}"></stop>
 </linearGradient>
 </defs>
 ${depositMarkers}
 ${withdrawalMarkers}
 ${liquidationMarkers}
 </svg>
 <div class="live-equity-hoverline" hidden></div>
 <div class="live-equity-tooltip" hidden></div>
 <div class="live-analytics-axis-labels">${xLabels}</div>
 </div>`;
}

function v16EquityTooltipTone(value) {
 const numeric = Number(value || 0);
 if (numeric > 0) return 'good';
 if (numeric < 0) return 'bad';
 return '';
}

function v16EquityTooltipRow(label, value, tone = '', prefix = '') {
 return `<div class="live-equity-tooltip-meta"><span>${v16Esc(label)}</span><strong class="${tone}">${prefix}${value}</strong></div>`;
}

function v16PositionEquityTooltip(plot, tooltip, leftPct) {
 const placement = leftPct < 18 ? 'is-left-edge' : (leftPct > 82 ? 'is-right-edge' : '');
 tooltip.classList.toggle('is-left-edge', placement === 'is-left-edge');
 tooltip.classList.toggle('is-right-edge', placement === 'is-right-edge');
 tooltip.style.left = `${Math.max(4, Math.min(96, leftPct))}%`;
}

function v16EquityDrawdownAt(points = [], point = {}) {
 const ts = Number(point.ts || 0);
 const eligible = points.filter(item => Number(item.ts || 0) <= ts);
 const peak = eligible.reduce((max, item) => Math.max(max, Number(item.equity || 0)), Number(point.equity || 0));
 return Math.min(0, Number(point.equity || 0) - peak);
}

function v16RenderAnalyticsEquityChart(model = {}) {
 const chartEl = document.getElementById('liveAnalyticsEquityChart');
 if (!chartEl) return;
 chartEl.innerHTML = v16BuildAnalyticsEquityChart(model);
 const chartModel = v16GetAnalyticsEquityChartModel(model);
 if (!chartModel) return;
 const plot = chartEl.querySelector('.live-analytics-equity-plot');
 const tooltip = chartEl.querySelector('.live-equity-tooltip');
 const hoverline = chartEl.querySelector('.live-equity-hoverline');
 if (!plot || !tooltip || !hoverline) return;
 const nearestClosedRecordByTs = (ts) => (model.closedRecords || []).reduce((closest, record) => {
 if (!record) return closest;
 if (!closest) return record;
 return Math.abs(Number(record.closedAt || 0) - ts) < Math.abs(Number(closest.closedAt || 0) - ts) ? record : closest;
 }, null);
 const showPoint = (point) => {
 const leftPct = Math.max(0, Math.min(100, (point.x / chartModel.width) * 100));
 hoverline.hidden = false;
 hoverline.style.left = `${leftPct}%`;
 const nearestRecord = nearestClosedRecordByTs(point.ts);
 const drawdown = v16EquityDrawdownAt(chartModel.points, point);
 const feeImpact = -Number(point.fees || 0) + Number(point.rebates || 0) + Number(point.funding || 0) - Number(point.liquidationFees || 0);
 const cashFlow = Number(point.deposits || 0) - Number(point.withdrawals || 0);
 const closedTrades = Number(point.trades || 0);
 const eventCopy = nearestRecord && Math.abs(Number(nearestRecord.closedAt || 0) - point.ts) <= 12 * 60 * 60 * 1000
 ? `<div class="live-equity-tooltip-note ${nearestRecord.pnl >= 0 ? 'good' : 'bad'}">${v16Esc(nearestRecord.symbol)} close ${v16FmtSigned(nearestRecord.pnl)}</div>`
 : '';
 tooltip.hidden = false;
 tooltip.className = `live-equity-tooltip ${point.realized >= 0 ? 'good' : 'bad'}`;
 tooltip.innerHTML = `
 <div class="live-equity-tooltip-head">
 <span class="live-equity-tooltip-time">${v16Esc(v16FormatTs(point.ts))}</span>
 <span class="live-equity-tooltip-event">${closedTrades} close${closedTrades === 1 ? '' : 's'}</span>
 </div>
 <div class="live-equity-tooltip-kicker">Net trading change</div>
 <div class="live-equity-tooltip-value ${v16EquityTooltipTone(point.realized)}">${v16FmtSigned(point.realized || 0)}</div>
 ${v16EquityTooltipRow('Trading equity', `$${v16FmtNumber(point.equity, 2)}`)}
 ${v16EquityTooltipRow('Realized P&L', v16FmtSigned(point.realized || 0), v16EquityTooltipTone(point.realized))}
 ${v16EquityTooltipRow('Fees, funding', v16FmtSigned(feeImpact), v16EquityTooltipTone(feeImpact))}
 ${v16EquityTooltipRow('Cash flow', v16FmtSigned(cashFlow), v16EquityTooltipTone(cashFlow))}
 ${v16EquityTooltipRow('Drawdown', v16FmtSigned(drawdown), drawdown < 0 ? 'bad' : '')}
 ${eventCopy}`;
 v16PositionEquityTooltip(plot, tooltip, leftPct);
 };
 plot.addEventListener('mousemove', (event) => {
 const rect = plot.getBoundingClientRect();
 const normalizedX = ((event.clientX - rect.left) / Math.max(1, rect.width)) * chartModel.width;
 const point = chartModel.points.reduce((closest, item) => (
 !closest || Math.abs(item.x - normalizedX) < Math.abs(closest.x - normalizedX) ? item : closest
 ), null);
 if (point) showPoint(point);
 });
 plot.addEventListener('mouseleave', () => {
 tooltip.hidden = true;
 hoverline.hidden = true;
 });
}

function v16GetAnalyticsBarChartModel(series = [], tone = 'neutral') {
 const points = Array.isArray(series) ? series : [];
 const hasData = points.some(point => Math.abs(Number(point.value || 0)) > 0);
 if (!points.length || !hasData) return null;
 const width = 420;
 const height = 170;
 const padX = 22;
 const padY = 18;
 const values = points.map(point => Number(point.value || 0));
 const min = Math.min(...values, 0);
 const max = Math.max(...values, 0);
 const range = Math.max(1, max - min);
 const zeroY = height - padY - (((0 - min) / range) * (height - padY * 2));
 const barGap = 6;
 const slot = (width - padX * 2) / Math.max(1, points.length);
 const barWidth = Math.max(8, slot - barGap);
 const bars = points.map((point, index) => {
 const value = Number(point.value || 0);
 const x = padX + (slot * index) + ((slot - barWidth) / 2);
 const y = height - padY - (((value - min) / range) * (height - padY * 2));
 const rectY = Math.min(y, zeroY);
 const rectH = Math.max(2, Math.abs(zeroY - y));
 const klass = tone === 'signed'
 ? (value >= 0 ? 'positive' : 'negative')
 : tone;
 return {
 ...point,
 x,
 y,
 rectY,
 rectH,
 barWidth,
 klass,
 };
 });
 return {
 width,
 height,
 padX,
 padY,
 zeroY,
 bars,
 hasData,
 };
}

function v16BuildAnalyticsBarChart(series = [], tone = 'neutral', emptyTitle = 'No data yet', emptyCopy = 'Refresh live data to populate this chart.') {
 const chartModel = v16GetAnalyticsBarChartModel(series, tone);
 if (!chartModel) {
 return `<div class="empty compact"><div class="ei">--</div><div class="eh">${v16Esc(emptyTitle)}</div><div class="es">${v16Esc(emptyCopy)}</div></div>`;
 }
 const { width, height, padX, zeroY, bars } = chartModel;
 const barMarkup = bars.map(point => (
 `<g><rect x="${point.x.toFixed(1)}" y="${point.rectY.toFixed(1)}" width="${point.barWidth.toFixed(1)}" height="${point.rectH.toFixed(1)}" rx="4" class="live-analytics-bar ${v16Esc(point.klass)}"></rect></g>`
 )).join('');
 const labels = bars.filter((_, index) => index === 0 || index === bars.length - 1 || index === Math.floor((bars.length - 1) / 2))
 .map(point => `<span>${v16Esc(point.label)}</span>`)
 .join('');
 return `<div class="live-analytics-bar-shell">
 <svg viewBox="0 0 ${width} ${height}" preserveAspectRatio="none" class="live-analytics-bar-svg">
 <line x1="${padX}" y1="${zeroY.toFixed(1)}" x2="${width - padX}" y2="${zeroY.toFixed(1)}" class="live-equity-zero"></line>
 ${barMarkup}
 </svg>
 <div class="live-equity-hoverline" hidden></div>
 <div class="live-equity-tooltip" hidden></div>
 <div class="live-analytics-bar-labels">${labels}</div>
 </div>`;
}

function v16RenderAnalyticsBarChart(elementId, series = [], tone = 'neutral', emptyTitle = 'No data yet', emptyCopy = 'Refresh live data to populate this chart.', valueLabel = 'Value', valueFormatter = (value => `${value}`)) {
 const chartEl = document.getElementById(elementId);
 if (!chartEl) return;
 chartEl.innerHTML = v16BuildAnalyticsBarChart(series, tone, emptyTitle, emptyCopy);
 const chartModel = v16GetAnalyticsBarChartModel(series, tone);
 if (!chartModel) return;
 const plot = chartEl.querySelector('.live-analytics-bar-shell');
 const tooltip = chartEl.querySelector('.live-equity-tooltip');
 const hoverline = chartEl.querySelector('.live-equity-hoverline');
 if (!plot || !tooltip || !hoverline) return;
 const showPoint = (point) => {
 const leftPct = Math.max(0, Math.min(100, ((point.x + (point.barWidth / 2)) / chartModel.width) * 100));
 hoverline.hidden = false;
 hoverline.style.left = `${leftPct}%`;
 tooltip.hidden = false;
 tooltip.className = `live-equity-tooltip ${Number(point.value || 0) >= 0 ? 'good' : 'bad'}`;
 tooltip.innerHTML = `
 <div class="live-equity-tooltip-time">${v16Esc(point.label)}</div>
 <div class="live-equity-tooltip-value ${Number(point.value || 0) >= 0 ? 'good' : 'bad'}">${v16Esc(valueFormatter(Number(point.value || 0)))}</div>
 <div class="live-equity-tooltip-meta">${v16Esc(valueLabel)} <strong>${v16Esc(valueFormatter(Number(point.value || 0)))}</strong></div>`;
 tooltip.style.left = `${Math.max(12, Math.min(88, leftPct))}%`;
 };
 plot.addEventListener('mousemove', (event) => {
 const rect = plot.getBoundingClientRect();
 const normalizedX = ((event.clientX - rect.left) / Math.max(1, rect.width)) * chartModel.width;
 const point = chartModel.bars.reduce((closest, item) => {
 const itemCenter = item.x + (item.barWidth / 2);
 const closestCenter = closest ? (closest.x + (closest.barWidth / 2)) : 0;
 return !closest || Math.abs(itemCenter - normalizedX) < Math.abs(closestCenter - normalizedX) ? item : closest;
 }, null);
 if (point) showPoint(point);
 });
 plot.addEventListener('mouseleave', () => {
 tooltip.hidden = true;
 hoverline.hidden = true;
 });
}

function v16RenderLiveAnalyticsKpis(model = {}) {
 const wrap = document.getElementById('liveAnalyticsKpis');
 if (!wrap) return;
 const avgLoss = Number(model.avgLoss || 0);
 const primaryPnlValue = Number((model.primaryPnlValue ?? model.realized) || 0);
 const cards = [
 { label: String(model.primaryPnlLabel || 'REALIZED P&L'), value: v16FmtSigned(primaryPnlValue), tone: primaryPnlValue >= 0 ? 'good' : 'bad', meta: String(model.primaryPnlMeta || `${model.tradeCount || 0} closed trade${model.tradeCount === 1 ? '' : 's'} in range.`) },
 { label: 'WIN RATE', value: `${v16FmtNumber(model.winRate || 0, 1)}%`, tone: Number(model.winRate || 0) >= 50 ? 'good' : 'warn', meta: `${model.instrumentLabel || 'All instruments'}.` },
 { label: 'AVERAGE WIN', value: v16FmtSigned(model.avgWin || 0), tone: Number(model.avgWin || 0) > 0 ? 'good' : 'warn', meta: `${model.tradeCount ? 'Winning trades only.' : 'No winning trades yet.'}` },
 { label: 'AVERAGE LOSS', value: v16FmtSigned(avgLoss || 0), tone: avgLoss >= 0 ? 'warn' : 'bad', meta: `${model.tradeCount ? 'Losing trades only.' : 'No losing trades yet.'}` },
 { label: '# TRADES', value: `${Number(model.tradeCount || 0)}`, tone: '', meta: `${Number(model.tradeCount || 0)} closed trade${model.tradeCount === 1 ? '' : 's'} selected.` },
 { label: 'VOLUME TRADED', value: `$${v16FmtNumber(model.volume || 0, model.volume >= 1000 ? 0 : 2)}`, tone: '', meta: 'Approximate notional from fills.' },
 { label: 'FEES PAID', value: v16FmtSigned(-(model.fees || 0)), tone: Number(model.fees || 0) > 0 ? 'bad' : '', meta: model.rebates > 0 ? `Rebates ${v16FmtSigned(model.rebates || 0)}.` : 'Commissions in range.' },
 { label: 'FUNDING', value: v16FmtSigned(model.funding || 0), tone: Number(model.funding || 0) >= 0 ? 'good' : 'bad', meta: model.view?.instrument === 'options' ? 'Options filter excludes funding.' : 'Wallet funding adjustments.' },
 { label: 'DEPOSITS', value: v16FmtSigned(model.deposits || 0), tone: Number(model.deposits || 0) > 0 ? 'good' : '', meta: 'Account-level cash inflows in range.' },
 { label: 'WITHDRAWALS', value: v16FmtSigned(-(model.withdrawals || 0)), tone: Number(model.withdrawals || 0) > 0 ? 'warn' : '', meta: 'Account-level cash outflows in range.' },
 ];
 wrap.innerHTML = cards.map(card => `
 <div class="live-analytics-kpi-card">
 <span>${v16Esc(card.label)}</span>
 <strong class="${v16Esc(card.tone)}">${v16Esc(card.value)}</strong>
 <small>${v16Esc(card.meta)}</small>
 </div>`).join('');
}

function v16RenderLiveAnalyticsReview(model = {}) {
 const journalMeta = document.getElementById('liveAnalyticsJournalMeta');
 const journalWrap = document.getElementById('liveAnalyticsJournalRows');
 const historyMeta = document.getElementById('liveAnalyticsTradeHistoryMeta');
 const historyWrap = document.getElementById('liveAnalyticsTradeHistoryRows');
 if (!journalMeta || !journalWrap || !historyMeta || !historyWrap) return;
 const trades = Array.isArray(model.trades) ? model.trades : [];
 journalMeta.textContent = trades.some(trade => !trade.hasNotes)
 ? 'At least one closed trade still needs post-trade notes.'
 : `${trades.length} closed trade${trades.length === 1 ? '' : 's'} ready for review.`;
 if (!trades.length) {
 journalWrap.innerHTML = `<div class="empty"><div class="ei">--</div><div class="eh">No journal trades yet</div><div class="es">Closed positions detected from Delta history will appear here.</div></div>`;
 } else {
 journalWrap.innerHTML = trades.slice(0, 40).map(trade => `
 <button class="live-journal-row ${trade.hasNotes ? '' : 'pending'}" data-live-analytics-journal-id="${v16Esc(trade.id)}">
 <div class="live-journal-top">
 <strong>${v16Esc(trade.symbol)}</strong>
 <span class="${trade.pnl >= 0 ? 'good' : 'bad'}">${v16FmtSigned(trade.pnl)}</span>
 </div>
 <div class="live-journal-meta">${v16Esc(String(trade.side || '').toUpperCase())} | ${v16FmtNumber(trade.size, 4).replace(/\.?0+$/, '')} contracts | ${v16Esc(v16FormatTs(trade.closedAt))}</div>
 <div class="live-journal-tags">${V16_MANAGE_REVIEW_CHECKS.filter(check => trade.review?.checklist?.[check.key]).map(check => `<span class="live-journal-tag">${v16Esc(check.label)}</span>`).join('')}${trade.review?.setupTag ? `<span class="live-journal-tag">${v16Esc(trade.review.setupTag)}</span>` : ''}${trade.review?.mistakeTag ? `<span class="live-journal-tag warn">${v16Esc(trade.review.mistakeTag)}</span>` : ''}</div>
 <div class="live-journal-meta">${trade.hasNotes ? v16Esc(v16BuildJournalSummary(trade.review)) : 'Add post-trade notes'}</div>
 </button>`).join('');
 journalWrap.querySelectorAll('[data-live-analytics-journal-id]').forEach(button => {
 button.addEventListener('click', () => {
 const trade = trades.find(item => item.id === button.dataset.liveAnalyticsJournalId);
 if (trade) openV16JournalDetail(trade);
 });
 });
 }

 const fills = Array.isArray(model.fills) ? model.fills : [];
 const orders = Array.isArray(model.orderHistory) ? model.orderHistory : [];
 const resolvedFeed = fills.length ? fills : orders;
 const usingOrders = !fills.length && orders.length;
 historyMeta.textContent = resolvedFeed.length
 ? `${resolvedFeed.length} activity record${resolvedFeed.length === 1 ? '' : 's'} in the selected range.`
 : 'No activity in the selected range.';
 if (!resolvedFeed.length) {
 historyWrap.innerHTML = `<div class="empty"><div class="ei">--</div><div class="eh">No trade activity loaded</div><div class="es">Refresh live data to load fills and order history from Delta Exchange.</div></div>`;
 return;
 }
 historyWrap.innerHTML = resolvedFeed.slice(0, 40).map(item => `
 <div class="live-fill-row ${usingOrders ? 'is-order-row' : ''}">
 <div>
 <div class="live-fill-symbol">${v16Esc(item.symbol)}</div>
 <div class="live-fill-meta">${v16Esc(String(item.side || '').toUpperCase())} | ${v16FmtNumber(Number(item.size || 0), 4).replace(/\.?0+$/, '')}${Number(item.price || 0) > 0 ? ` @ $${v16FmtPrice(item.price)}` : ''}${usingOrders ? ` | ${v16Esc(String(item.state || '').toUpperCase())}` : ''}</div>
 <small>${usingOrders ? 'Order history fallback' : `Fee -$${Math.abs(Number(item.commission || 0)).toFixed(4)}`}</small>
 </div>
 </div>`).join('');
}

