function v16ClassifyOpenOrder(order = {}) {
 const role = String(order.role || '').toLowerCase();
 const linked = !!String(order.linkedPositionId || '').trim()
 || !!order.reduceOnly
 || ['stop_loss', 'take_profit', 'exit'].includes(role);
 if (!linked && role === 'entry') {
 return {
 key: 'fresh',
 label: 'Fresh Entry Orders',
 copy: 'New working entries that can open or add exposure.',
 tone: 'good',
 badge: 'Fresh',
 };
 }
 if (linked) {
 return {
 key: 'linked',
 label: 'Linked / Protection Orders',
 copy: 'Targets, stops, exits, and other orders tied to live exposure.',
 tone: 'warn',
 badge: 'Linked',
 };
 }
 return {
 key: 'other',
 label: 'Other Working Orders',
 copy: 'Orders that need review because their purpose is not explicit.',
 tone: 'dim',
 badge: 'Review',
 };
}

