function v16RenderOrdersStatusRail(metrics = {}, filteredOrders = null) {
 const rail = document.getElementById('liveOrdersStatusRail');
 if (!rail) return;
 const orders = Array.isArray(filteredOrders) ? filteredOrders : (Array.isArray(metrics.openOrders) ? metrics.openOrders : []);
 const families = v16BuildOrderLineageFamilies(metrics);
 const fresh = orders.filter(order => v16ClassifyOpenOrder(order).key === 'fresh').length;
 const stops = orders.filter(order => String(order.role || '').toLowerCase() === 'stop_loss').length;
 const targets = orders.filter(order => String(order.role || '').toLowerCase() === 'take_profit').length;
 const reduceOnly = orders.filter(order => !!order.reduceOnly).length;
 const other = orders.filter(order => v16ClassifyOpenOrder(order).key === 'other').length;
 const missingStop = families.filter(family => family.state === 'live' && !Number(family.lineage?.stop?.length || 0)).length;
 const missingTarget = families.filter(family => family.state === 'live' && !Number(family.lineage?.target?.length || 0)).length;
 const cards = [
 ['Pending entries', fresh, 'Fresh orders that can open exposure', fresh ? 'warn' : 'dim'],
 ['Pending stops', stops, `${missingStop} live position${missingStop === 1 ? '' : 's'} missing stop`, missingStop ? 'bad' : 'good'],
 ['Pending targets', targets, `${missingTarget} live position${missingTarget === 1 ? '' : 's'} missing target`, missingTarget ? 'warn' : 'good'],
 ['Reduce-only', reduceOnly, 'Protection or exit orders', reduceOnly ? 'good' : 'dim'],
 ['Review', other, 'Orders without explicit purpose', other ? 'bad' : 'dim'],
 ];
 rail.innerHTML = cards.map(([label, value, copy, tone]) => `
 <div class="orders-status-card orders-status-card--${v16Esc(tone)}">
 <span>${v16Esc(label)}</span>
 <strong>${v16Esc(String(value))}</strong>
 <small>${v16Esc(copy)}</small>
 </div>`).join('');
}

