function v16ResolveLineageOrderPrice(order = {}) {
 const role = String(order.role || '').toLowerCase();
 if (role === 'entry') return Number(order.limitPrice || order.price || order.stopPrice || 0);
 return Number(v16ResolvePlannedExitPrice(order) || 0);
}

function v16FormatLineageOrderRef(order = {}) {
 const raw = String(order.orderId || order.id || order.clientOrderId || '').trim();
 if (!raw) return 'no-ref';
 return raw.length > 12 ? raw.slice(-12).toUpperCase() : raw.toUpperCase();
}

function v16RenderLineageOrderPill(order = {}, tone = 'dim') {
 const price = v16ResolveLineageOrderPrice(order);
 const state = String(order.state || '').trim().toUpperCase() || 'OPEN';
 const parts = [
 state,
 order.reduceOnly ? 'RO' : '',
 order.postOnly ? 'PO' : '',
 `#${v16FormatLineageOrderRef(order)}`,
 ].filter(Boolean);
 return `
 <div class="live-order-lineage-pill live-order-lineage-pill--${v16Esc(tone)}">
 <strong>${v16Esc(v16OrderRoleLabel(order.role || 'order'))}</strong>
 <span>${price > 0 ? `$${v16FmtPrice(price)}` : '-'}</span>
 <small>${v16Esc(parts.join(' | '))}</small>
 </div>`;
}

function v16RenderLineageLane(label = '', orders = [], tone = 'dim', emptyCopy = 'No orders linked') {
 return `
 <div class="live-order-lineage-lane">
 <div class="live-order-lineage-lane-label">${v16Esc(label)}</div>
 <div class="live-order-lineage-lane-body">
 ${orders.length
 ? orders.map(order => v16RenderLineageOrderPill(order, tone)).join('')
 : `<div class="live-order-lineage-empty">${v16Esc(emptyCopy)}</div>`}
 </div>
 </div>`;
}

function v16BuildQueuedLineageModel(symbol = '', openOrders = []) {
 const symbolOrders = (openOrders || []).filter(order => String(order.symbol || '').trim().toUpperCase() === symbol);
 const entry = symbolOrders.filter(order => v16ClassifyOpenOrder(order).key === 'fresh');
 const linked = symbolOrders.filter(order => v16ClassifyOpenOrder(order).key !== 'fresh');
 const stop = linked.filter(order => String(order.role || '').toLowerCase() === 'stop_loss');
 const target = linked.filter(order => String(order.role || '').toLowerCase() === 'take_profit');
 const exit = linked.filter(order => String(order.role || '').toLowerCase() === 'exit');
 const knownIds = new Set([...stop, ...target, ...exit].map(order => String(order.orderId || order.id || order.clientOrderId || '')));
 const orphan = linked.filter(order => !knownIds.has(String(order.orderId || order.id || order.clientOrderId || '')));
 return {
 all: symbolOrders,
 entry,
 stop,
 target,
 exit,
 orphan,
 dsManaged: linked.filter(v16IsFWDTradeDeskManagedOrder),
 };
}

function v16BuildOrderLineageFamilies(metrics = {}) {
 const positions = (Array.isArray(metrics?.positions) ? metrics.positions : [])
 .filter(position => {
 const symbol = v16NormalizeSymbol(position?.symbol || '');
 return symbol && v16AnalyticsProductType(symbol) === 'futures';
 });
 const openOrders = (Array.isArray(metrics?.openOrders) ? metrics.openOrders : [])
 .filter(order => {
 const symbol = v16NormalizeSymbol(order?.symbol || '');
 const productType = String(order?.productType || '').trim().toLowerCase();
 return symbol && (productType ? productType === 'futures' : v16AnalyticsProductType(symbol) === 'futures');
 });
 const liveSymbols = new Set();
 const families = positions.map(position => {
 const symbol = String(position.symbol || '').trim().toUpperCase();
 liveSymbols.add(symbol);
 const lineage = position.linkedOrders || v16BuildLinkedOrderModel(position, openOrders);
 const freshOrders = openOrders.filter(order => String(order.symbol || '').trim().toUpperCase() === symbol && v16ClassifyOpenOrder(order).key === 'fresh');
 return {
 key: `live:${position.id || symbol}`,
 symbol,
 state: 'live',
 slotLabel: '1 live slot',
 position,
 freshOrders,
 lineage,
 };
 });
 const queuedSymbols = Array.from(new Set(openOrders
 .filter(order => v16ClassifyOpenOrder(order).key === 'fresh')
 .map(order => String(order.symbol || '').trim().toUpperCase())
 .filter(symbol => symbol && !liveSymbols.has(symbol))));
 queuedSymbols.forEach(symbol => {
 families.push({
 key: `queued:${symbol}`,
 symbol,
 state: 'queued',
 slotLabel: '1 queued slot',
 position: null,
 freshOrders: openOrders.filter(order => String(order.symbol || '').trim().toUpperCase() === symbol && v16ClassifyOpenOrder(order).key === 'fresh'),
 lineage: v16BuildQueuedLineageModel(symbol, openOrders),
 });
 });
 return families.sort((a, b) => {
 if (a.state !== b.state) return a.state === 'live' ? -1 : 1;
 return String(a.symbol || '').localeCompare(String(b.symbol || ''));
 });
}

function v16RenderOrderLineage(metrics = {}) {
 const wrap = document.getElementById('liveOrderLineageRows');
 const meta = document.getElementById('liveOrderLineageMeta');
 if (!wrap || !meta) return;
 const families = v16BuildOrderLineageFamilies(metrics);
 const slotSummary = v16ResolveConcurrentExposureSummary(metrics);
 meta.textContent = `${families.length} symbol ${families.length === 1 ? 'family' : 'families'} | ${slotSummary.used}/${slotSummary.maxConcurrent} slots used | ${slotSummary.available} free | ${slotSummary.reserved || 0} reserved`;
 if (!families.length) {
 wrap.innerHTML = `<div class="empty"><div class="ei">+</div><div class="eh">No order lineage yet</div><div class="es">Working entry orders and live positions will appear here as parent-child families.</div></div>`;
 return;
 }
 wrap.innerHTML = families.map(family => {
 const position = family.position || null;
 const lineage = family.lineage || { entry: [], stop: [], target: [], exit: [], orphan: [], all: [] };
 const childCount = Number(lineage.stop?.length || 0) + Number(lineage.target?.length || 0) + Number(lineage.exit?.length || 0) + Number(lineage.orphan?.length || 0);
 const freshCount = Number(family.freshOrders?.length || 0);
 const entryPrice = position
 ? Number(position.entry || 0)
 : Number(family.freshOrders?.[0]?.limitPrice || family.freshOrders?.[0]?.price || family.freshOrders?.[0]?.stopPrice || 0);
 const parentLabel = position
 ? `${String(position.side || '').toUpperCase()} live position`
 : 'Queued fresh entry';
 const parentMeta = position
 ? `${v16FmtNumber(Number(position.displaySize || position.size || 0), 4).replace(/\.?0+$/, '')} ${v16DisplayUnit({ displayUnit: position.displayUnit })}`
 : `${freshCount} fresh entry order${freshCount === 1 ? '' : 's'}`;
 const pnlLabel = position
 ? v16FmtSigned(Number(position.unrealized || 0))
 : (freshCount ? `${freshCount} working` : '-');
 const pnlTone = position
 ? (Number(position.unrealized || 0) >= 0 ? 'good' : 'bad')
 : 'warn';
 const stateTone = family.state === 'live' ? 'good' : 'warn';
 return `
 <article class="live-order-lineage-family live-order-lineage-family--${v16Esc(family.state)}">
 <div class="live-order-lineage-head">
 <div>
 <div class="live-order-lineage-symbol">${v16Esc(family.symbol)}</div>
 <div class="live-order-lineage-sub">${v16Esc(parentLabel)} | ${v16Esc(parentMeta)} | ${childCount} linked child order${childCount === 1 ? '' : 's'}</div>
 </div>
 <div class="live-order-lineage-badges">
 <span class="live-position-badge live-order-lineage-state live-order-lineage-state--${v16Esc(stateTone)}">${family.state === 'live' ? 'LIVE' : 'QUEUED'}</span>
 <span class="live-position-badge live-order-lineage-slot">${v16Esc(family.slotLabel)}</span>
 </div>
 </div>
 <div class="live-order-lineage-grid">
 <div><span>Parent</span><strong>${v16Esc(parentLabel)}</strong></div>
 <div><span>Entry</span><strong>${entryPrice > 0 ? `$${v16FmtPrice(entryPrice)}` : '-'}</strong></div>
 <div><span>Fresh Adds</span><strong>${freshCount}</strong></div>
 <div><span>Children</span><strong>${childCount}</strong></div>
 <div><span>Slot Use</span><strong>${v16Esc(family.slotLabel)}</strong></div>
 <div><span>${position ? 'Open P&amp;L' : 'Queue State'}</span><strong class="${v16Esc(pnlTone)}">${v16Esc(pnlLabel)}</strong></div>
 </div>
 <div class="live-order-lineage-lanes">
 ${v16RenderLineageLane('Fresh Entry', family.freshOrders || lineage.entry || [], 'good', 'No fresh entry order')}
 ${v16RenderLineageLane('Stop', lineage.stop || [], 'bad', 'No stop linked')}
 ${v16RenderLineageLane('Target', lineage.target || [], 'good', 'No target linked')}
 ${v16RenderLineageLane('Other', [...(lineage.exit || []), ...(lineage.orphan || [])], 'dim', 'No other linked orders')}
 </div>
 </article>`;
 }).join('');
}

function v16ResolveConfiguredAutoTradeProfile(settings = {}) {
 const configuredProfileId = String(settings?.profileId || '').trim();
 if (configuredProfileId) return getV16ProfileById(configuredProfileId) || null;
 return getV16ActiveAccountProfile();
}

function v16ExplainAutoTradeReason(reason = '', status = '') {
 const raw = String(reason || '').trim();
 const lower = raw.toLowerCase();
 if (!raw) return 'No explicit block reason was recorded.';
 if (lower.includes('kill switch is armed')) return 'Kill switch is armed, so the engine can scan but cannot place new orders.';
 if (lower.includes('tradeenabled profile required')) return 'Auto-trade needs a Trade Enabled profile before it can place live orders.';
 if (lower.includes('readonly or tradeenabled profile required')) return 'Choose a Delta profile before auto-trade can continue.';
 if (lower.includes('trading key and secret are required')) return 'Trading credentials are missing for the configured profile.';
 if (lower.includes('windows credential alias is missing')) return 'Windows credential alias is missing for the configured profile.';
 if (lower.includes('no active delta profile found')) return 'No active Delta profile is available right now.';
 if (lower.includes('api circuit breaker')) return 'Delta API protection is paused after repeated auth or request failures.';
 if (lower.startsWith('funding block:')) return raw.replace(/^funding block:\s*/i, 'Funding is adverse: ');
 if (lower.includes('max concurrent reached')) return 'All auto-trade slots are currently in use, so no fresh entry can be added.';
 if (lower.includes('max trades per day reached')) return 'The daily trade budget is fully used for today.';
 if (lower.includes('daily loss limit reached')) return 'The daily loss guard is blocking fresh entries until the next reset.';
 if (String(status || '').trim().toLowerCase() === 'blocked_protection') return 'A live position is missing valid stop protection, so new entries are paused.';
 if (String(status || '').trim().toLowerCase() === 'no_candidates') return raw;
 return raw;
}

function v16ResolveAuditFocusSymbol(audit = {}) {
 return v16NormalizeSymbol(
 audit?.symbol
 || audit?.bestSignal?.symbol
 || (Array.isArray(audit?.topSignals) ? audit.topSignals[0]?.symbol : '')
 || (Array.isArray(audit?.placedSymbols) ? audit.placedSymbols[0] : '')
 || ''
 );
}

function v16BuildAuditManualControlNotes(manualControls = {}, symbol = '', now = Date.now()) {
 const manual = v16ResolveManualControlRecord(manualControls, symbol, now);
 if (!manual?.record) return [];
 return [
 manual.paused ? `Pause active until ${v16FormatTs(manual.record?.pausedUntil || 0)}` : '',
 manual.reentryBlocked ? `Re-entry block active until ${v16FormatTs(manual.record?.reentryBlockedUntil || 0)}` : '',
 manual.ignoreFunding ? `Funding override active until ${v16FormatTs(manual.record?.ignoreFundingUntil || 0)}` : '',
 manual.reservedSlot ? `Reserved slot held until ${v16FormatTs(manual.record?.reservedSlotUntil || 0)}` : '',
 manual.blockedToday ? `Blocked for the rest of today until ${v16FormatTs(manual.record?.blockedTodayUntil || v16StartOfNextDay(now))}` : '',
 ].filter(Boolean);
}

function v16BuildAuditNextPassSummary({
 status = '',
 currentCapacity = 0,
 remainingDayBudget = 0,
 dailyLossUsed = 0,
 dailyLossLimit = 0,
 slotSummary = {},
 maxPerScan = 0,
 dailyLossResetTs = 0,
} = {}) {
 const normalizedStatus = String(status || '').trim().toLowerCase();
 if (normalizedStatus === 'placed') {
 return 'The last engine pass already placed an entry. The next pass will only add more trades if fresh capacity opens and another qualified setup remains.';
 }
 if (currentCapacity > 0) {
 return `The next pass can still try up to ${currentCapacity} new entr${currentCapacity === 1 ? 'y' : 'ies'} with ${Math.max(0, remainingDayBudget)} day slot${remainingDayBudget === 1 ? '' : 's'} left and ${Math.max(0, Number(slotSummary?.maxConcurrent || 0) - Number(slotSummary?.used || 0))} live slot${Math.max(0, Number(slotSummary?.maxConcurrent || 0) - Number(slotSummary?.used || 0)) === 1 ? '' : 's'} open.`;
 }
 if (normalizedStatus === 'blocked_daily_loss' && dailyLossLimit > 0) {
 return `No fresh entry can be placed until the daily loss guard resets at ${dailyLossResetTs ? v16FormatTs(dailyLossResetTs) : 'the next reset window'}. Current loss is $${v16FmtNumber(dailyLossUsed, 2)} against the $${v16FmtNumber(dailyLossLimit, 2)} limit.`;
 }
 if (normalizedStatus === 'blocked_daily_limit') {
 return `The engine is waiting for the daily trade counter to reset. Max per scan is ${maxPerScan}, but no new entries can be added until the next trading day.`;
 }
 if (normalizedStatus === 'blocked_concurrent') {
 return `No new entry can be added until live, queued, or reserved slot usage drops below ${Number(slotSummary?.maxConcurrent || 0)}.`;
 }
 return 'The engine can scan again on the next pass, but the current blockers must clear before a new entry can be placed.';
}

function v16BuildAuditReasonFacts({
 statusMeta = {},
 effectiveReason = '',
 bestSignal = null,
 currentCapacity = 0,
 slotSummary = {},
 remainingDayBudget = 0,
 dailyCount = 0,
 maxPerDay = 0,
 dailyLossUsed = 0,
 dailyLossLimit = 0,
 dailyLossResetTs = 0,
} = {}) {
 const facts = [
 `Exact blocker: ${statusMeta?.label || 'Unknown state'}.`,
 effectiveReason ? `Plain language: ${effectiveReason}` : '',
 `Slots: ${Number(slotSummary?.used || 0)}/${Number(slotSummary?.maxConcurrent || 0)} used, with ${Number(slotSummary?.live || 0)} live, ${Number(slotSummary?.queued || 0)} queued, and ${Number(slotSummary?.reserved || 0)} reserved.`,
 maxPerDay > 0 ? `Day budget: ${dailyCount}/${maxPerDay} used, ${remainingDayBudget} left today.` : '',
 dailyLossLimit > 0 ? `Daily loss: $${v16FmtNumber(dailyLossUsed, 2)} used out of $${v16FmtNumber(dailyLossLimit, 2)}. Reset ${dailyLossResetTs ? v16FormatTs(dailyLossResetTs) : 'not available'}.` : '',
 `Next pass capacity: ${currentCapacity} new entr${currentCapacity === 1 ? 'y' : 'ies'} available right now.`,
 bestSignal ? `Lead signal: ${String(bestSignal.symbol || '-').toUpperCase()} ${String(bestSignal.direction || '').toLowerCase()} with TQ ${v16FmtNumber(Number(bestSignal.tradeQuality || 0), 0)} and score ${v16FmtNumber(Number(bestSignal.score || 0), 0)}.` : '',
 ];

// Security setup, overlays, ledger actions and live order scaffolding
 return facts.filter(Boolean);
}

