async function v16RenderAutoTradeDecisionAudit(metrics = {}) {
 const wrap = document.getElementById('liveOrderAuditRows');
 const meta = document.getElementById('liveOrderAuditMeta');
 if (!wrap || !meta) return;
 const store = await storeGet(['autoTrade', 'autoTradeSettings', 'autoTradeDecisionAuditV16', 'autoTradeLastSkipReason', 'autoTradeDailyLoss', 'autoTradeDailyResetTs', V16_AUTO_TRADE_MANUAL_CONTROLS_KEY]);
 const uxHintDismissals = await v16LoadUxHintDismissals();
 const audit = store?.autoTradeDecisionAuditV16 || {};
 const manualControls = v16SanitizeManualControls(store?.[V16_AUTO_TRADE_MANUAL_CONTROLS_KEY] || {}, Date.now());
 const configuredProfileId = String(store?.autoTradeSettings?.profileId || '').trim();
 const activeProfile = getV16ActiveAccountProfile();
 const configuredProfile = configuredProfileId ? (getV16ProfileById(configuredProfileId) || null) : activeProfile;
 const configuredProfileLabel = String(configuredProfile?.label || configuredProfile?.name || configuredProfile?.id || configuredProfileId || 'No profile').trim();
 const configuredProfileCapability = String(configuredProfile?.capability || '').trim() || 'Unknown';
 const configuredProfileHasSecret = configuredProfile?.id ? hasV16SessionSecret(configuredProfile.id) : false;
 const killSwitchState = getV16KillSwitchState();
 const engineState = v16ResolveAuditEngineState({
 autoTradeEnabled: !!store?.autoTrade,
 killSwitchEnabled: !!killSwitchState?.enabled,
 });
 const slotSummary = v16ResolveConcurrentExposureSummary(metrics);
 const currentMaxConcurrent = Math.max(1, Number(slotSummary.maxConcurrent || store?.autoTradeSettings?.maxConcurrent || 5));
 const status = String(audit.status || '').trim().toLowerCase();
 const staleConcurrent = status === 'blocked_concurrent'
 && Number(audit.maxConcurrent || currentMaxConcurrent) > 0
 && slotSummary.used < Number(audit.maxConcurrent || currentMaxConcurrent);
 const statusMeta = v16ResolveAuditStatusMeta(status, staleConcurrent);
 const updatedAt = Number(audit.updatedAt || 0);
 const dailyCount = Number(audit.dailyCount || 0);
 const dailyLossUsed = Number((audit.dailyLossUsed ?? store?.autoTradeDailyLoss) || 0);
 const dailyLossLimit = Number((audit.dailyLossLimitUSD ?? store?.autoTradeSettings?.dailyLossLimitUSD) || 0);
 const dailyLossResetTs = Number(audit.dailyLossResetTs || store?.autoTradeDailyResetTs || 0);
 const maxPerDay = Number(audit.maxPerDay || store?.autoTradeSettings?.maxPerDay || 0);
 const remainingDayBudget = Math.max(0, Number((audit.remainingDayBudget ?? (maxPerDay - dailyCount)) || 0));
 const maxPerScan = Math.max(1, Number(store?.autoTradeSettings?.maxPerScan || 2));
 const currentRemainingDayBudget = Math.max(0, maxPerDay - dailyCount);
 const currentCapacity = Math.max(0, Math.min(maxPerScan, Math.max(0, currentMaxConcurrent - slotSummary.used), currentRemainingDayBudget));
 const effectiveReason = staleConcurrent
 ? `The last engine run saw ${Number(audit.openCount || 0)}/${Number(audit.maxConcurrent || currentMaxConcurrent)} slots in use, but the live desk now shows ${slotSummary.used}/${slotSummary.maxConcurrent}. The old slot block has cleared. Auto-trade can try again on the next scan or lifecycle replay.`
 : v16ExplainAutoTradeReason(String(audit.reason || store?.autoTradeLastSkipReason || '').trim(), status);
 const lossTrades = (Array.isArray(metrics.autoTradeLog) ? metrics.autoTradeLog : [])
 .filter(entry => Number(entry?.closePnl || 0) < 0)
 .sort((a, b) => Number(b?.closedAt || b?.ts || 0) - Number(a?.closedAt || a?.ts || 0))
 .slice(0, 4);
 const bestSignal = audit.bestSignal || null;
 const topSignals = Array.isArray(audit.topSignals) ? audit.topSignals : [];
 const placedSymbols = Array.isArray(audit.placedSymbols) ? audit.placedSymbols : [];
 const focusSymbol = v16ResolveAuditFocusSymbol(audit);
 const focusManualNotes = v16BuildAuditManualControlNotes(manualControls, focusSymbol, Date.now());
 const nextPassSummary = v16BuildAuditNextPassSummary({
 status,
 currentCapacity,
 remainingDayBudget,
 dailyLossUsed,
 dailyLossLimit,
 slotSummary,
 maxPerScan,
 dailyLossResetTs,
 });
 const reasonFacts = v16BuildAuditReasonFacts({
 statusMeta,
 effectiveReason,
 bestSignal,
 currentCapacity,
 slotSummary,
 remainingDayBudget,
 dailyCount,
 maxPerDay,
 dailyLossUsed,
 dailyLossLimit,
 dailyLossResetTs,
 });
 meta.textContent = `${engineState.metaLabel}${updatedAt ? ` | Last engine ${v16FormatTs(updatedAt)}` : ''}`;
 if (!updatedAt && !effectiveReason) {
 wrap.innerHTML = `<div class="empty"><div class="ei">+</div><div class="eh">No auto-trade decision captured</div><div class="es">Run a scan with auto-trade enabled to record the latest placement or block reason.</div></div>`;
 return;
 }
 wrap.innerHTML = `
 <div class="live-order-audit-status live-order-audit-status--${v16Esc(statusMeta.tone)}">
 <div>
 <strong>${v16Esc(statusMeta.label)}</strong>
 <small>${updatedAt ? `Updated ${v16Esc(v16FormatTs(updatedAt))}` : 'No timestamp yet'}</small>
 </div>
 <span>${v16Esc(engineState.engineLabel)}</span>
 </div>
 ${v16BuildFirstUseHintHtml({
 key: 'audit_blockers',
 title: 'Audit now explains blockers in plain language',
 body: 'Start with Exact Blocker, then check Next Engine Pass and Why blocked? to see whether the engine is waiting on slots, the daily loss guard, funding, or a manual control.',
 dismissals: uxHintDismissals,
 tone: statusMeta.tone === 'bad' ? 'warn' : 'info',
 })}
 <div class="live-order-audit-grid">
 <div class="live-order-audit-metric"><span>Configured Profile</span><strong>${v16Esc(configuredProfileLabel)}</strong><small>${v16Esc(configuredProfileCapability)} | ${configuredProfileHasSecret ? 'credentials ready' : 'credentials missing'}</small></div>
 <div class="live-order-audit-metric live-order-audit-metric--blocker"><span>Exact Blocker ${v16BuildInlineHelpHtml('Exact blocker', 'This is the one state that is currently stopping the engine from placing a fresh entry.')}</span><strong>${v16Esc(statusMeta.label)}</strong><small>${v16Esc(effectiveReason || 'No explicit block reason was recorded.')}</small></div>
 <div class="live-order-audit-metric live-order-audit-metric--capacity"><span>Next Engine Pass ${v16BuildInlineHelpHtml('Next engine pass', 'This tells you what the next scan can still do if the current blocker clears before the engine checks again.')}</span><strong>${currentCapacity}</strong><small>${v16Esc(nextPassSummary)}</small></div>
 <div class="live-order-audit-metric"><span>Slots Now</span><strong>${slotSummary.used}/${slotSummary.maxConcurrent}</strong><small>${slotSummary.live} live | ${slotSummary.queued} queued | ${slotSummary.reserved || 0} reserved</small></div>
 <div class="live-order-audit-metric live-order-audit-metric--loss"><span>Daily Loss</span><strong>$${v16FmtNumber(dailyLossUsed, 2)} / ${dailyLossLimit > 0 ? `$${v16FmtNumber(dailyLossLimit, 2)}` : 'Not set'}</strong><small>${dailyLossResetTs ? `Reset ${v16Esc(v16FormatTs(dailyLossResetTs))}` : 'Reset time unavailable'}</small></div>
 <div class="live-order-audit-metric"><span>Today&apos;s Budget</span><strong>${dailyCount}/${maxPerDay || '-'}</strong><small>${remainingDayBudget} remaining today | Last engine saw ${Number(audit.openCount || 0)}/${Number(audit.maxConcurrent || currentMaxConcurrent)}</small></div>
 </div>
 <div class="live-order-audit-reason ${v16Esc(statusMeta.tone)}">${v16Esc(effectiveReason || 'No explicit block reason was recorded.')}</div>
 <details class="live-order-audit-drawer" ${statusMeta.tone === 'bad' ? 'open' : ''}>
 <summary>Why blocked?</summary>
 <div class="live-order-audit-drawer-body">
 ${reasonFacts.map(fact => `<div class="live-order-audit-drawer-line">${v16Esc(fact)}</div>`).join('')}
 </div>
 </details>
 ${focusSymbol ? `<div class="live-order-audit-best"><span>Focus Symbol</span><strong>${v16Esc(focusSymbol)}</strong><small>${focusManualNotes.length ? 'Manual controls are active on this symbol.' : 'No manual control is active on this symbol right now.'}</small></div>` : ''}
 ${focusManualNotes.length ? `<div class="live-order-audit-list">${focusManualNotes.map(note => `
 <div class="live-order-audit-item">
 <div>
 <strong>${v16Esc(focusSymbol)}</strong>
 <small>Active manual control</small>
 </div>
 <div class="live-order-audit-item-reasons">${v16Esc(note)}</div>
 </div>`).join('')}</div>` : ''}
 ${status === 'blocked_kill_switch' ? `<div class="live-order-audit-best"><span>Kill Switch</span><strong>${killSwitchState?.enabled ? 'Armed' : 'Cleared'}</strong><small>${killSwitchState?.enabled ? 'Turn it off in Settings before the engine can place new orders.' : 'The kill switch looks cleared now. Run another scan to refresh the audit state.'}</small></div>` : ''}
 ${dailyLossLimit > 0 ? `<div class="live-order-audit-best"><span>Loss Guard</span><strong>$${v16FmtNumber(dailyLossUsed, 2)} / $${v16FmtNumber(dailyLossLimit, 2)}</strong><small>${dailyLossUsed >= dailyLossLimit ? 'The loss guard is actively blocking fresh entries.' : 'The loss guard has not reached its block threshold.'}</small></div>` : ''}
 ${lossTrades.length ? `<div class="live-order-audit-best"><span>Trades Counted Toward Daily Loss</span><strong>${lossTrades.length}</strong><small>These recent losing closes are contributing to the current daily loss guard.</small></div>` : ''}
 ${lossTrades.length ? `<div class="live-order-audit-list">${lossTrades.map(entry => `
 <div class="live-order-audit-item">
 <div>
 <strong>${v16Esc(String(entry.symbol || '-').toUpperCase())}</strong>
 <small>${v16Esc(v16ResolveTradeModeLabel(entry))} | ${v16Esc(v16HumanizeCloseReasonLabel(v16ResolveJournalCloseReason(entry, entry, []) || 'closed on exchange'))}</small>
 </div>
 <div class="live-order-audit-item-reasons">Loss ${v16FmtSigned(Number(entry.closePnl || 0))} | Exit ${v16Esc(v16FormatTs(entry.closedAt || entry.ts || 0))}</div>
 </div>`).join('')}</div>` : ''}
 ${bestSignal ? `
 <div class="live-order-audit-best">
 <span>Best Signal Right Now</span>
 <strong>${v16Esc(bestSignal.symbol || '-')}</strong>
 <small>${v16Esc(String(bestSignal.direction || '').toUpperCase())} | TQ ${v16FmtNumber(Number(bestSignal.tradeQuality || 0), 0)} | Score ${v16FmtNumber(Number(bestSignal.score || 0), 0)} | ${currentCapacity > 0 ? 'Can still be attempted on the next pass if blockers clear.' : 'Still waiting on a blocker to clear.'}</small>
 </div>` : ''}
 ${placedSymbols.length ? `
 <div class="live-order-audit-best">
 <span>Placed This Run</span>
 <strong>${v16Esc(placedSymbols.join(', '))}</strong>
 <small>${placedSymbols.length} symbol${placedSymbols.length === 1 ? '' : 's'} placed successfully.</small>
 </div>` : ''}
 ${topSignals.length ? `
 <div class="live-order-audit-list">
 ${topSignals.map(item => `
 <div class="live-order-audit-item">
 <div>
 <strong>${v16Esc(item.symbol || '-')}</strong>
 <small>${v16Esc(String(item.direction || '').toUpperCase())} | ${v16Esc(v16HumanizeDecisionActionLabel(item.action || 'PASS'))} | TQ ${v16FmtNumber(Number(item.tradeQuality || 0), 0)} | Score ${v16FmtNumber(Number(item.score || 0), 0)}</small>
 </div>
 <div class="live-order-audit-item-reasons">${v16Esc((Array.isArray(item.reasons) && item.reasons.length) ? item.reasons.join(' | ') : 'Eligible on the last engine pass.')}</div>
 </div>`).join('')}
 </div>` : ''}
 `;
 v16BindUxHintDismissButtons(wrap);
}

function v16ResolveRelinkProtectionOrder(position = {}, kind = 'stop') {
 const plan = position?.exposurePlan || {};
 const orders = kind === 'target' ? plan.targetOrders : plan.stopOrders;
 return Array.isArray(orders) ? orders[0] || null : null;
}

function v16BuildAutoTradeRelinkEntry(position = {}) {
 const now = Date.now();
 const symbol = v16NormalizeSymbol(position?.symbol || '');
 const positionSide = String(position?.side || '').trim().toLowerCase() === 'short' ? 'short' : 'long';
 const protection = position.protection || v16ResolvePositionProtectionMeta(position, position.trailingEntry);
 const stopOrder = v16ResolveRelinkProtectionOrder(position, 'stop');
 const targetOrder = v16ResolveRelinkProtectionOrder(position, 'target');
 const entryPrice = Number(position?.entry || 0);
 const size = Math.max(0, Number(position?.size || 0));
 const notional = Math.max(0, Number(position?.notionalValue || (entryPrice > 0 && size > 0 ? entryPrice * size : 0)));
 const targetPrice = Number(protection?.targetPrice || targetOrder?.limitPrice || targetOrder?.stopPrice || 0);
 const stopPrice = Number(protection?.stopPrice || stopOrder?.stopPrice || stopOrder?.limitPrice || 0);
 return {
 id: `RELINK_${symbol}_${now}`,
 symbol,
 side: positionSide === 'short' ? 'sell' : 'buy',
 positionSide,
 status: 'live',
 source: 'relinked',
 entry: entryPrice,
 sl: stopPrice,
 tp: targetPrice,
 tp1: targetPrice,
 tp2: 0,
 tp3: 0,
 tp4: 0,
 takeProfitLimitPrice: targetPrice,
 sizeUSD: Number(notional.toFixed(4)),
 requestedSizeUSD: Number(notional.toFixed(4)),
 requestedMaxNotionalUSD: Number(notional.toFixed(4)),
 previewContracts: size,
 previewDisplaySize: size,
 previewDisplayUnit: 'contracts',
 expectedNotionalUSD: Number(notional.toFixed(4)),
 profileId: String(getV16ActiveAccountProfile().id || '').trim(),
 baseUrl: String(v16LiveAccountView?.data?.baseUrl || '').trim(),
 positionSeenAt: now,
 markPrice: Number(position?.markPrice || 0),
 stopOrderId: String(stopOrder?.orderId || stopOrder?.id || '').trim(),
 targetOrderId: String(targetOrder?.orderId || targetOrder?.id || '').trim(),
 targetAutoShiftStage: targetPrice > 0 ? 'tp1' : '',
 targetShiftEvents: [],
 protectionState: stopPrice > 0 ? 'manual_native' : 'unprotected',
 stopProtectionSource: stopPrice > 0 ? 'manual_native' : '',
 targetProtectionSource: targetPrice > 0 ? 'manual_native' : '',
 protectionBlockReason: stopPrice > 0 ? '' : 'Relinked position has no detected native stop order.',
 notifications: { relinkedAt: now },
 relinkedAt: now,
 updatedAt: now,
 ts: now,
 };
}

async function v16RelinkExchangePosition(symbol = '') {
 const normalizedSymbol = v16NormalizeSymbol(symbol || '');
 if (!normalizedSymbol) return;
 const metrics = v16LiveAccountView.lastPositionMetrics || {};
 const position = (Array.isArray(metrics.positions) ? metrics.positions : [])
 .find(item => v16NormalizeSymbol(item?.symbol || '') === normalizedSymbol);
 if (!position) {
 reportUiError('Relink failed', new Error(`${normalizedSymbol} is not in the current live position snapshot.`), { timeoutMs: 5000 });
 return;
 }
 const stored = await storeGet('autoTradeLog');
 const autoTradeLog = Array.isArray(stored?.autoTradeLog) ? stored.autoTradeLog : [];
 const activeStatuses = new Set(['placed', 'pending', 'live']);
 const relinkEntry = v16BuildAutoTradeRelinkEntry(position);
 const nextLog = [
 relinkEntry,
 ...autoTradeLog.filter(entry => !(
 activeStatuses.has(String(entry?.status || '').toLowerCase())
 && v16NormalizeSymbol(entry?.symbol || '') === normalizedSymbol
 )),
 ].slice(0, 500);
 await storeSet({ autoTradeLog: nextLog });
 const nextMetrics = {
 ...metrics,
 autoTradeLog: nextLog,
 positions: (Array.isArray(metrics.positions) ? metrics.positions : []).map(item => {
 if (v16NormalizeSymbol(item?.symbol || '') !== normalizedSymbol) return item;
 const trailingEntry = v16ResolvePositionTrailingEntry(item, nextLog, relinkEntry.profileId, v16LiveAccountView.autoTradeSettings || {});
 return {
 ...item,
 trailingEntry,
 protection: v16ResolvePositionProtectionMeta(item, trailingEntry),
 autoTradeSizingSummary: v16BuildAutoTradeSizingSummary(trailingEntry),
 };
 }),
 };
 v16LiveAccountView.lastPositionMetrics = nextMetrics;
 v16RenderExchangeReconciliation(nextMetrics);
 v16NotifyOrderConfirmation('Position relinked', `${normalizedSymbol} is now linked to the live tracker using its current native stop and target.`);
}

function v16BuildExchangeReconciliationModel(metrics = {}) {
 const positions = Array.isArray(metrics.positions) ? metrics.positions : [];
 const openOrders = Array.isArray(metrics.openOrders) ? metrics.openOrders : [];
 const autoTradeLog = Array.isArray(metrics.autoTradeLog) ? metrics.autoTradeLog : [];
 const manualControls = metrics.manualControls || { symbols: {} };
 const liveTracked = autoTradeLog.filter(entry => ['placed', 'pending', 'live'].includes(String(entry?.status || '').toLowerCase()));
 const trackedSymbols = new Set(liveTracked.map(entry => v16NormalizeSymbol(entry?.symbol || '')).filter(Boolean));
 const liveSymbols = new Set(positions.map(position => v16NormalizeSymbol(position?.symbol || '')).filter(Boolean));
 const freshOrders = openOrders.filter(order => v16ClassifyOpenOrder(order).key === 'fresh');
 const queuedSymbols = new Set(freshOrders.map(order => v16NormalizeSymbol(order?.symbol || '')).filter(Boolean));
 const unprotected = positions.filter(position => {
 const protection = position.protection || v16ResolvePositionProtectionMeta(position, position.trailingEntry);
 return !(Number(protection?.stopPrice || 0) > 0);
 });
 const orphanOrders = positions.reduce((count, position) => count + Number(position?.linkedOrders?.orphan?.length || 0), 0);
 const missingTracked = Array.from(trackedSymbols).filter(symbol => !liveSymbols.has(symbol) && !queuedSymbols.has(symbol));
 const untrackedLive = positions.filter(position => !trackedSymbols.has(v16NormalizeSymbol(position?.symbol || '')));
 const controls = Object.values(manualControls?.symbols || {});
 const pausedCount = controls.filter(entry => Number(entry?.pausedUntil || 0) > Date.now()).length;
 const blockedTodayCount = controls.filter(entry => Number(entry?.blockedTodayUntil || 0) > Date.now()).length;
 const reservedCount = controls.filter(entry => Number(entry?.reservedSlotUntil || 0) > Date.now()).length;
 return {
 matchedLive: positions.length - untrackedLive.length,
 untrackedLive,
 missingTracked,
 unprotected,
 orphanOrders,
 freshOrders: freshOrders.length,
 pausedCount,
 blockedTodayCount,
 reservedCount,
 };
}

function v16RenderExchangeReconciliation(metrics = {}) {
 const wrap = document.getElementById('liveReconciliationRows');
 const meta = document.getElementById('liveReconciliationMeta');
 if (!wrap || !meta) return;
 const model = v16BuildExchangeReconciliationModel(metrics);
 meta.textContent = `${model.matchedLive} matched | ${model.untrackedLive.length} untracked live | ${model.missingTracked.length} stale tracked | ${model.orphanOrders} orphan linked`;
 const summaryCards = `
 <div class="live-order-audit-grid">
 <div><span>Matched Live</span><strong>${model.matchedLive}</strong><small>Live positions tied back to tracked auto-trade context.</small></div>
 <div><span>Untracked Live</span><strong>${model.untrackedLive.length}</strong><small>Exchange positions that are live but not linked to active tracked entries.</small></div>
 <div><span>Missing Tracked</span><strong>${model.missingTracked.length}</strong><small>Tracked entries that no longer show as live or queued on the exchange.</small></div>
 <div><span>Unprotected</span><strong>${model.unprotected.length}</strong><small>Live positions without a detected native stop order.</small></div>
 <div><span>Fresh Orders</span><strong>${model.freshOrders}</strong><small>Queued fresh entries currently consuming slot capacity.</small></div>
 <div><span>Manual Controls</span><strong>${model.pausedCount + model.blockedTodayCount + model.reservedCount}</strong><small>${model.pausedCount} paused | ${model.blockedTodayCount} blocked today | ${model.reservedCount} reserved</small></div>
 </div>`;
 const listItems = [
 ...model.untrackedLive.map(position => ({
 tone: 'warn',
 title: `${position.symbol} live but not tracked`,
 copy: 'Exchange position exists without an active tracked auto-trade entry. Review whether it was manual, restored, or needs relinking.',
 action: 'relink',
 symbol: position.symbol,
 })),
 ...model.missingTracked.map(symbol => ({
 tone: 'dim',
 title: `${symbol} tracked but no live exposure`,
 copy: 'Tracked entry is stale. The exchange no longer shows a live position or queued fresh entry for this symbol.',
 })),
 ...model.unprotected.map(position => ({
 tone: 'bad',
 title: `${position.symbol} missing stop protection`,
 copy: 'A live position was found without a native stop order. This is the highest-risk reconciliation mismatch.',
 })),
 ].slice(0, 10);
 wrap.innerHTML = `${summaryCards}${listItems.length ? `<div class="live-reconciliation-list">${listItems.map(item => `
 <div class="live-reconciliation-item live-reconciliation-item--${v16Esc(item.tone)}">
 <div>
 <strong>${v16Esc(item.title)}</strong>
 <small>${v16Esc(item.copy)}</small>
 </div>
 ${item.action === 'relink' ? `<button class="bsm live-reconciliation-action" type="button" data-live-relink-symbol="${v16Esc(item.symbol)}">Relink</button>` : ''}
 </div>`).join('')}</div>` : `<div class="empty"><div class="ei">+</div><div class="eh">No reconciliation mismatches</div><div class="es">Live positions, queued entries, and tracked records are currently aligned.</div></div>`}`;
 wrap.querySelectorAll('[data-live-relink-symbol]').forEach(button => {
 button.addEventListener('click', () => {
 button.disabled = true;
 v16RelinkExchangePosition(button.dataset.liveRelinkSymbol || '')
 .catch(error => reportUiError('Relink failed', error, { timeoutMs: 6000 }))
 .finally(() => { button.disabled = false; });
 });
 });
}

function v16BuildNotificationCenterEntries(metrics = {}) {
 const feed = Array.isArray(metrics.notificationFeed) ? metrics.notificationFeed : [];
 const alerts = (Array.isArray(metrics.recentAlerts) ? metrics.recentAlerts : [])
 .slice(0, 6)
 .map(alert => ({
 id: String(alert.alertKey || alert.symbol || Math.random()),
 ts: Number(alert.ts || Date.now()),
 tone: String(alert.alertTier || '').toLowerCase() === 'execute' ? 'success' : 'info',
 title: `${String(alert.alertTier || 'signal').toUpperCase()} ${String(alert.symbol || '').toUpperCase()}`,
 what: `${String(alert.direction || '').toUpperCase()} score ${Number(alert.score || 0)} | entry $${v16FmtPrice(Number(alert.entry || alert.price || 0))}`,
 why: Array.isArray(alert.reasons) && alert.reasons.length ? alert.reasons.slice(0, 2).join(' | ') : 'Signal entered the alert stack.',
 next: 'The engine will re-check live filters and auto-trade rules on the next decision pass.',
 action: 'Open the signal popup to inspect live decision status and funding forecast.',
 }));
 return [...feed, ...alerts]
 .sort((a, b) => Number(b?.ts || 0) - Number(a?.ts || 0))
 .slice(0, 14);
}

function v16ResolveNotificationCategory(item = {}) {
 const text = `${item?.title || ''} ${item?.what || ''} ${item?.why || ''} ${item?.action || ''}`.toLowerCase();
 if (
 text.includes('target shifted')
 || text.includes('target armed')
 || text.includes('trade closed')
 || text.includes('entry cancelled')
 || text.includes('signal flip')
 || text.includes('execute ')
 || text.includes('setup ')
 || text.includes('watch ')
 || text.includes('placed')
 || text.includes('stop armed')
 ) return 'Trade Events';
 if (
 text.includes('funding')
 || text.includes('kill switch')
 || text.includes('daily loss')
 || text.includes('loss guard')
 || text.includes('slot cap')
 || text.includes('slot')
 || text.includes('protection')
 || text.includes('unprotected')
 ) return 'Risk Events';
 if (
 text.includes('profile')
 || text.includes('secret')
 || text.includes('credential')
 || text.includes('api circuit breaker')
 || text.includes('auth failure')
 || text.includes('missing')
 || text.includes('unavailable')
 ) return 'Warnings';
 return 'System Events';
}

function v16ResolveNotificationSeverity(item = {}) {
 const tone = String(item?.tone || 'info').trim().toLowerCase();
 if (tone === 'error' || tone === 'bad') return { label: 'High', className: 'error' };
 if (tone === 'warn') return { label: 'Medium', className: 'warn' };
 if (tone === 'success' || tone === 'good') return { label: 'Low', className: 'success' };
 return { label: 'Info', className: 'info' };
}

function v16BuildNotificationExplanation(item = {}) {
 const parts = [
 String(item?.what || '').trim(),
 String(item?.why || '').trim(),
 ].filter(Boolean);
 const joined = parts.join(' ');
 return joined || String(item?.next || item?.action || 'System update recorded.').trim();
}

function v16BuildGroupedNotificationCenterEntries(metrics = {}) {
 const groups = ['Trade Events', 'Risk Events', 'System Events', 'Warnings'];
 const grouped = new Map(groups.map(group => [group, []]));
 v16BuildNotificationCenterEntries(metrics).forEach(item => {
 const category = v16ResolveNotificationCategory(item);
 grouped.get(category)?.push({
 ...item,
 category,
 severity: v16ResolveNotificationSeverity(item),
 explanation: v16BuildNotificationExplanation(item),
 });
 });
 return groups.map(group => ({
 title: group,
 items: grouped.get(group) || [],
 }));
}

function v16RenderNotificationCenter(metrics = {}) {
 const wrap = document.getElementById('liveNotificationRows');
 const meta = document.getElementById('liveNotificationMeta');
 if (!wrap || !meta) return;
 const groups = v16BuildGroupedNotificationCenterEntries(metrics);
 const dismissals = v16NormalizeUxHintDismissals(metrics.uxHintDismissals || v16LiveAccountView.uxHintDismissals || {});
 const totalItems = groups.reduce((sum, group) => sum + group.items.length, 0);
 meta.textContent = `${totalItems} recent update${totalItems === 1 ? '' : 's'} grouped by trade, risk, system, and warning events`;
 if (!totalItems) {
 wrap.innerHTML = `<div class="empty"><div class="ei">+</div><div class="eh">No notifications yet</div><div class="es">Scanner alerts and auto-trade lifecycle updates will appear here with cause and next-step context.</div></div>`;
 return;
 }
 wrap.innerHTML = `
 ${v16BuildFirstUseHintHtml({
 key: 'notification_center',
 title: 'Notification center now reads by category first',
 body: 'Trade Events show lifecycle changes, Risk Events call out exposure or loss guards, System Events cover engine state, and Warnings highlight issues that need attention.',
 dismissals,
 tone: 'info',
 })}
 ${groups.map(group => `
 <section class="live-notification-group">
 <div class="live-notification-group-head">
 <strong>${v16Esc(group.title)}</strong>
 <span>${group.items.length}</span>
 </div>
 ${group.items.length ? group.items.map(item => `
 <div class="live-notification-item live-notification-item--${v16Esc(String(item.severity?.className || 'info').toLowerCase())}">
 <div class="live-notification-head">
 <strong>${v16Esc(item.title || 'System update')}</strong>
 <div class="live-notification-head-side">
 <span class="live-notification-severity live-notification-severity--${v16Esc(String(item.severity?.className || 'info').toLowerCase())}">${v16Esc(item.severity?.label || 'Info')}</span>
 <span>${v16Esc(v16FormatTs(item.ts || 0))}</span>
 </div>
 </div>
 <div class="live-notification-summary">${v16Esc(item.explanation)}</div>
 </div>`).join('') : `<div class="live-notification-group-empty">No ${v16Esc(group.title.toLowerCase())} yet.</div>`}
 </section>`).join('')}
 `;
 v16BindUxHintDismissButtons(wrap);
}

