function v16CapabilityAllowsAccountRead() {
 const profile = getV16ActiveAccountProfile();
 return !!getAccountCapabilityMeta(profile.capability).allowsAccountRead;
}

function v16CapabilityAllowsTrade() {
 const profile = getV16ActiveAccountProfile();
 return !!getAccountCapabilityMeta(profile.capability).allowsTrade && !getV16KillSwitchState().enabled;
}

function v16PositionActionLabel(action = 'close') {
 if (action === 'reduce25') return 'Reduce 25%';
 if (action === 'reduce50') return 'Reduce 50%';
 return 'Close Position';
}

function v16FormatStraddleStatus(status = '') {
 return String(status || 'active').replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());
}

function v16GetActiveStraddleEntries(dashboard = null) {
 const entries = Array.isArray(dashboard?.entries) ? dashboard.entries : [];
 return entries.filter(entry => ['active', 'partial_stop'].includes(String(entry?.status || '').toLowerCase()));
}

function v16BuildBulkClosePayload(position = {}, openOrders = []) {
 const linkedOrders = position.linkedOrders || v16BuildLinkedOrderModel(position, openOrders);
 return {
 symbol: position.symbol,
 positionSide: position.side,
 positionSize: Math.max(1, Math.round(Number(position.size || 1))),
 requestedAction: 'close',
 linkedOrderIds: (linkedOrders.dsManaged || []).map(order => String(order.orderId || order.id || '').trim()).filter(Boolean),
 linkedClientOrderIds: (linkedOrders.dsManaged || []).map(order => String(order.clientOrderId || '').trim()).filter(Boolean),
 baseUrl: v16LiveAccountView.data?.baseUrl || '',
 };
}

function v16GetFlattenTargets(metrics = {}) {
 const straddles = v16GetActiveStraddleEntries(metrics?.straddleDashboard);
 const straddleSymbols = new Set(straddles.map(entry => v16NormalizeSymbol(entry.symbol || entry.sourceSymbol || '')).filter(Boolean));
 const positions = (Array.isArray(metrics?.positions) ? metrics.positions : []).filter(position => !straddleSymbols.has(v16NormalizeSymbol(position?.symbol || '')));
 return {
 positions,
 straddles,
 totalCount: positions.length + straddles.length,
 };
}

function v16ArmBulkConfirm(kind = 'flatten') {
 const key = kind === 'straddles' ? 'bulkCloseStraddlesConfirmUntil' : 'bulkFlattenConfirmUntil';
 const otherKey = kind === 'straddles' ? 'bulkFlattenConfirmUntil' : 'bulkCloseStraddlesConfirmUntil';
 const now = Date.now();
 const armedUntil = Number(v16LiveAccountView[key] || 0);
 if (armedUntil > now) {
 v16LiveAccountView[key] = 0;
 return true;
 }
 v16LiveAccountView[key] = now + 5000;
 v16LiveAccountView[otherKey] = 0;
 v16RefreshPositionsView();
 globalThis.showSystemToast?.(
 kind === 'straddles' ? 'Confirm close all straddles' : 'Confirm flatten all',
 kind === 'straddles'
 ? 'Click again within 5 seconds to close the visible active straddles.'
 : 'Click again within 5 seconds to close every live position and active straddle.',
 'warn',
 2600,
 );
 setTimeout(() => {
 if (Number(v16LiveAccountView[key] || 0) <= Date.now()) {
 v16LiveAccountView[key] = 0;
 v16RefreshPositionsView();
 }
 }, 5200);
 return false;
}

async function v16ExecuteBulkFlatten(metrics = {}) {
 const { positions, straddles, totalCount } = v16GetFlattenTargets(metrics);
 if (!totalCount) {
 globalThis.showSystemToast?.('Nothing to flatten', 'There are no live positions or active straddles to close.', 'warn', 2200);
 return;
 }
 const openOrders = Array.isArray(metrics?.openOrders) ? metrics.openOrders : [];
 const profileId = getV16ActiveAccountProfile().id;
 let closedPositions = 0;
 let closedStraddles = 0;
 let firstFailure = '';
 for (const entry of straddles) {
 const result = await v16RuntimeSend('v17:closeStraddleEntry', { entryId: entry.id });
 if (result?.ok) closedStraddles += 1;
 else if (!firstFailure) firstFailure = `${entry.symbol || entry.id}: ${result?.error || 'close failed'}`;
 }
 for (const position of positions) {
 const result = await v16RuntimeSend('v16:placePositionAction', {
 profileId,
 ...v16BuildBulkClosePayload(position, openOrders),
 });
 if (result?.ok) closedPositions += 1;
 else if (!firstFailure) firstFailure = `${position.symbol || position.id}: ${result?.error || 'close failed'}`;
 }
 v16LiveAccountView.bulkFlattenConfirmUntil = 0;
 if (closedPositions || closedStraddles) {
 v16LiveAccountView.lastOrderAction = { type: 'flatten-all', symbol: '', at: Date.now() };
 }
 globalThis.showSystemToast?.(
 firstFailure ? 'Flatten partially completed' : 'Flatten complete',
 firstFailure
 ? `Closed ${closedPositions} positions and ${closedStraddles} straddles. ${firstFailure}`
 : `Closed ${closedPositions} positions and ${closedStraddles} straddles.`,
 firstFailure ? 'warn' : 'success',
 firstFailure ? 4200 : 2600,
 );
 await renderV16PositionsPane(null, true);
}

async function v16ExecuteCloseAllStraddles(metrics = {}) {
 const statusFilter = String(v16LiveAccountView.straddleStatusFilter || 'active').toLowerCase();
 const underlyingFilter = String(v16LiveAccountView.straddleUnderlyingFilter || 'all').toUpperCase();
 const entries = v16GetActiveStraddleEntries(metrics?.straddleDashboard).filter(entry => {
 if (statusFilter === 'closed') return false;
 if (underlyingFilter !== 'ALL' && underlyingFilter && String(entry?.underlying || '').toUpperCase() !== underlyingFilter) return false;
 return true;
 });
 if (!entries.length) {
 globalThis.showSystemToast?.('No active straddles', 'There are no visible active straddles to close.', 'warn', 2200);
 return;
 }
 let closedCount = 0;
 let firstFailure = '';
 for (const entry of entries) {
 const result = await v16RuntimeSend('v17:closeStraddleEntry', { entryId: entry.id });
 if (result?.ok) closedCount += 1;
 else if (!firstFailure) firstFailure = `${entry.symbol || entry.id}: ${result?.error || 'close failed'}`;
 }
 v16LiveAccountView.bulkCloseStraddlesConfirmUntil = 0;
 if (closedCount) {
 v16LiveAccountView.lastOrderAction = { type: 'close-all-straddles', symbol: '', at: Date.now() };
 }
 globalThis.showSystemToast?.(
 firstFailure ? 'Straddles partially closed' : 'Straddles closed',
 firstFailure ? `Closed ${closedCount} straddles. ${firstFailure}` : `Closed ${closedCount} active straddles.`,
 firstFailure ? 'warn' : 'success',
 firstFailure ? 4200 : 2600,
 );
 await renderV16PositionsPane(null, true);
}

function v16BuildStraddleManageSection(dashboard = null, canTrade = false) {
 const entries = Array.isArray(dashboard?.entries) ? dashboard.entries : [];
 const statusFilter = String(v16LiveAccountView.straddleStatusFilter || 'active').toLowerCase();
 const underlyingFilter = String(v16LiveAccountView.straddleUnderlyingFilter || 'all').toUpperCase();
 const filtered = entries.filter(entry => {
 if (underlyingFilter !== 'ALL' && underlyingFilter && String(entry?.underlying || '').toUpperCase() !== underlyingFilter) return false;
 if (statusFilter === 'active') return ['active', 'partial_stop'].includes(String(entry?.status || ''));
 if (statusFilter === 'closed') return String(entry?.status || '') === 'closed';
 return true;
 });
 const statusPills = ['all', 'active', 'closed'].map(value => `<button type="button" class="bsm ${statusFilter === value ? 'active' : ''}" data-straddle-filter="${value}">${value === 'all' ? 'All' : value === 'active' ? 'Active' : 'Closed'}</button>`).join('');
 const underlyingPills = ['ALL', 'BTC', 'ETH'].map(value => `<button type="button" class="bsm ${underlyingFilter === value ? 'active' : ''}" data-straddle-underlying="${value}">${value}</button>`).join('');
 const summary = dashboard?.summary || {};
 const filteredActiveCount = filtered.filter(entry => ['active', 'partial_stop'].includes(String(entry?.status || '').toLowerCase())).length;
 const closeAllArmed = Number(v16LiveAccountView.bulkCloseStraddlesConfirmUntil || 0) > Date.now();
 const closeAllLabel = closeAllArmed ? 'Confirm Close All' : `Close All Straddles${filteredActiveCount ? ` (${filteredActiveCount})` : ''}`;
 const meta = `${Number(summary.activeCount || 0)} active | ${Number(summary.closedCount || 0)} closed | Active P&L ${v16FmtSigned(Number(summary.activePnlUSD || 0))} | Open credit $${v16FmtNumber(Number(summary.premiumOpenUSD || 0), 2)}`;
 if (!filtered.length) {
 return `<div class="live-straddle-section">
 <div class="live-straddle-header"><div><div class="mo-section">Straddles</div><div class="live-journal-meta">${v16Esc(meta)}</div></div><div class="live-straddle-filters">${statusPills}${underlyingPills}<button class="bsm danger ${closeAllArmed ? 'armed' : ''}" data-straddle-action="close-all" ${canTrade && filteredActiveCount ? '' : 'disabled'}>${v16Esc(closeAllLabel)}</button></div></div>
 <div class="empty"><div class="ei">+</div><div class="eh">No straddles in this view</div><div class="es">Change the filters or place a native straddle from the Options Desk.</div></div>
 </div>`;
 }
 const rows = filtered.map(entry => {
 const isActive = ['active', 'partial_stop'].includes(String(entry.status || '').toLowerCase());
 const stopState = String(entry.stopHealth || entry.protectionState || '').trim().toLowerCase();
 const stopPriceLabel = Number(entry.stopPrice || 0) > 0
 ? `$${v16FmtPrice(Number(entry.stopPrice || 0))}`
 : (isActive ? '<span class="bad">No Stop</span>' : '-');
 const stopOrderMeta = entry.protectionSource === 'manual_native'
 ? 'Manual Native Stop'
 : stopState === 'armed'
 ? 'Static Stop'
 : stopState === 'unprotected'
 ? 'Unprotected'
 : (isActive ? 'No Stop' : '-');
 const stopOrderMetaClass = (stopState === 'unprotected' || (isActive && !entry.stopOrderId && entry.protectionSource !== 'manual_native' && stopState !== 'armed'))
 ? 'bad'
 : 'dim';
 return `<tr>
 <td>${v16Esc(entry.underlying || '-')}</td>
 <td>${v16Esc(entry.symbol || entry.sourceSymbol || '-')}</td>
 <td>${v16Esc(v16FormatTs(entry.ts))}</td>
 <td>${v16Esc(v16FormatTs(entry.expiryTs))}</td>
 <td>${v16Esc(String(Number(entry.qty || 0)))}</td>
 <td>$${v16FmtNumber(Number(entry.premiumUSD || 0), 2)}</td>
 <td class="${Number(entry.totalPnlUSD || 0) >= 0 ? 'good' : 'bad'}">${v16FmtSigned(Number(entry.totalPnlUSD || 0))}</td>
 <td>${stopPriceLabel}</td>
 <td>${entry.stopOrderId ? v16Esc(String(entry.stopOrderId)) : '-'}<br/><small class="${stopOrderMetaClass}">${v16Esc(stopOrderMeta)}</small></td>
 <td>${v16Esc(String(Number(entry.reentryCount || 0)))}</td>
 <td>${v16Esc(v16FormatStraddleStatus(entry.status))}</td>
 <td>${v16Esc(String(entry.closeReason || '-').replace(/_/g, ' '))}</td>
 <td><div class="pos-table-actions">
 <button class="bsm" data-straddle-action="open" data-straddle-symbol="${v16Esc(String(entry.sourceSymbol || entry.symbol || ''))}" data-straddle-underlying="${v16Esc(String(entry.underlying || ''))}" data-straddle-expiry-key="${v16Esc(String(entry.expiryKey || ''))}">Open Source</button>
 <button class="bsm danger" data-straddle-action="close" data-straddle-id="${v16Esc(String(entry.id || ''))}" ${canTrade && String(entry.status || '') !== 'closed' ? '' : 'disabled'}>Close Now</button>
 </div></td>
 </tr>`;
 }).join('');
 return `<div class="live-straddle-section">
 <div class="live-straddle-header">
 <div><div class="mo-section">Straddles</div><div class="live-journal-meta">${v16Esc(meta)}</div></div>
 <div class="live-straddle-filters">${statusPills}${underlyingPills}<button class="bsm danger ${closeAllArmed ? 'armed' : ''}" data-straddle-action="close-all" ${canTrade && filteredActiveCount ? '' : 'disabled'}>${v16Esc(closeAllLabel)}</button></div>
 </div>
 <table class="live-positions-table live-straddle-table">
 <thead><tr><th>Base</th><th>Symbol</th><th>Entry</th><th>Expiry</th><th>Qty</th><th>Credit</th><th>Live P&amp;L</th><th>Stop</th><th>Stop Order</th><th>Re-entries</th><th>Status</th><th>Close Reason</th><th>Actions</th></tr></thead>
 <tbody>${rows}</tbody>
 </table>
 </div>`;
}

function v16GetOpenStraddleEntries(dashboard = null) {
 const entries = Array.isArray(dashboard?.entries) ? dashboard.entries : [];
 return entries.filter(entry => ['active', 'partial_stop'].includes(String(entry?.status || '').toLowerCase()));
}

function v16StraddleMatchesSearch(entry = {}, query = '') {
 const needle = String(query || '').trim().toUpperCase();
 if (!needle) return true;
 return [
 entry.symbol,
 entry.sourceSymbol,
 entry.underlying,
 entry.expiryKey,
 entry.id,
 ].some(value => String(value || '').toUpperCase().includes(needle));
}

