function v16ReadPositionActionDraftFromForm() {
 const existing = v16LiveAccountView.positionAction || {};
 const orderType = String(document.getElementById('livePositionActionOrderType')?.value || existing.orderType || 'market_order').trim().toLowerCase() === 'limit_order'
 ? 'limit_order'
 : 'market_order';
 const entryModeRaw = String(document.getElementById('livePositionActionEntryMode')?.value || existing.entryMode || (orderType === 'limit_order' ? 'limit' : 'market')).trim().toLowerCase();
 const entryMode = orderType === 'limit_order'
 ? (entryModeRaw === 'maker_only' || entryModeRaw === 'maker' ? 'maker_only' : 'limit')
 : 'market';
 const limitPrice = Math.max(0, Number(document.getElementById('livePositionActionLimitPrice')?.value || existing.limitPrice || existing.markPrice || 0));
 return {
 ...existing,
 orderType,
 entryMode,
 postOnly: orderType === 'limit_order' && entryMode === 'maker_only',
 limitPrice: orderType === 'limit_order' ? limitPrice : 0,
 };
}

function v16ReadLiveOrderDraftFromForm() {
 const existing = v16LiveAccountView.orderSignal || {};
 const sizeMode = v16NormalizeLiveOrderSizeMode(document.getElementById('liveOrderQtyMode')?.value || v16LiveAccountView.orderSignalMeta?.sizeMode || 'usd');
 const enteredSize = Math.max(0, Number(document.getElementById('liveOrderSize')?.value || existing.size || 0));
 const symbol = String(document.getElementById('liveOrderSymbol')?.value || existing.symbol || '').trim().toUpperCase();
 const sideChoice = String(document.getElementById('liveOrderSide')?.value || existing.side || 'long').trim().toLowerCase();
 const orderType = String(document.getElementById('liveOrderType')?.value || existing.orderType || 'market_order').trim().toLowerCase() === 'limit_order'
 ? 'limit_order'
 : 'market_order';
 const entryMode = String(document.getElementById('liveOrderEntryMode')?.value || existing.entryMode || (orderType === 'limit_order' ? 'limit' : 'market')).trim().toLowerCase();
 const entry = Math.max(0, Number(document.getElementById('liveOrderEntryPrice')?.value || existing.entry || existing.price || 0));
 const limitPrice = Math.max(0, Number(document.getElementById('liveOrderLimitPrice')?.value || existing.limitPrice || 0));
 const stopLoss = Math.max(0, Number(document.getElementById('liveOrderStopLoss')?.value || existing.stopLoss || existing.sl || 0));
 const takeProfit = Math.max(0, Number(document.getElementById('liveOrderTakeProfit')?.value || existing.takeProfit || existing.tp1 || existing.tp || 0));
 const takeProfit2 = Math.max(0, Number(document.getElementById('liveOrderTakeProfit2')?.value || existing.takeProfit2 || existing.tp2 || 0));
 const sizingPrice = v16ResolveLiveOrderSizingPrice({
 orderType,
 entry,
 price: entry,
 limitPrice: orderType === 'limit_order' ? Math.max(limitPrice, entry) : 0,
 });
 const size = v16ComputeLiveOrderContractsFromInput(enteredSize, sizeMode, {
 definition: v16LiveAccountView.orderSignalMeta?.definition || null,
 price: sizingPrice,
 });
 return {
 symbol,
 side: sideChoice === 'short' || sideChoice === 'sell' ? 'short' : 'long',
 size,
 sizeMode,
 sizeInput: enteredSize,
 entry,
 price: entry,
 orderType,
 entryMode,
 limitPrice: orderType === 'limit_order' ? Math.max(limitPrice, entry) : 0,
 stopLoss,
 takeProfit,
 takeProfit2,
 reduceOnly: false,
 manualOverride: true,
 baseUrl: existing.baseUrl || v16LiveAccountView.data?.baseUrl || '',
 };
}

