async function refreshV16PrivateAccountData(force = false) {
 globalThis.FWDAppLock?.touchActivity?.();
 const profile = getV16ActiveAccountProfile();
 const statusEl = document.getElementById('liveAccountStatus');
 const secret = getV16Secrets()?.[profile.id] || {};
 if (!v16CapabilityAllowsAccountRead()) {
 v16LiveAccountView = {
 ...v16LiveAccountView,
 status: 'idle',
 data: null,
 error: 'Switch to ReadOnly or TradeEnabled to load private account data.',
 rateLimit: null,
 };
 v16UpdateRateLimitBanner(null);
 if (statusEl) statusEl.textContent = v16LiveAccountView.error;
 return null;
 }
 if (!hasV16SessionSecret(profile.id)) {
 v16LiveAccountView = {
 ...v16LiveAccountView,
 status: 'idle',
 data: null,
 error: 'Add Trading Key and Trading Secret in Settings -> User Profile -> Advanced.',
 rateLimit: null,
 };
 v16UpdateRateLimitBanner(null);
 if (statusEl) statusEl.textContent = v16LiveAccountView.error;
 return null;
 }
 const activeRateLimit = v16NormalizeRateLimitMeta(v16LiveAccountView.rateLimit || v16LiveAccountView.data?.rateLimit);
 if (activeRateLimit && v16LiveAccountView.data) {
 v16LiveAccountView = { ...v16LiveAccountView, status: 'success', error: '', rateLimit: activeRateLimit };
 v16UpdateRateLimitBanner(activeRateLimit, 'Private account');
 if (statusEl) statusEl.textContent = `Private Delta API cooling down for ${v16FormatDurationShort(activeRateLimit.waitMs)} | using cached snapshot.`;
 return {
 ...v16LiveAccountView.data,
 rateLimit: activeRateLimit,
 };
 }
 if (!force && v16LiveAccountView.status === 'success' && (Date.now() - Number(v16LiveAccountView.fetchedAt || 0)) < V16_PRIVATE_VIEW_CACHE_TTL_MS) {
 return v16LiveAccountView.data;
 }
 if (v16PrivateAccountRefreshPromise) return v16PrivateAccountRefreshPromise;

 const currentBaseUrl = v16LiveAccountView.data?.baseUrl || '';
 v16LiveAccountView = { ...v16LiveAccountView, status: 'loading', error: '' };
 if (statusEl) statusEl.textContent = 'Loading private Delta account data...';

 v16PrivateAccountRefreshPromise = (async () => {
 const marketDataMode = await v16GetMarketDataMode();
 const socketPreferred = marketDataMode !== 'polling';
 let socketSnapshot = null;
 let socketError = '';
 const [socketResult, response] = await Promise.all([
 socketPreferred
 ? runV16PrivateSocketSnapshot(profile, secret, currentBaseUrl)
 .then(snap => ({ ok: true, snap }))
 .catch(error => ({ ok: false, error: error?.message || 'Private socket unavailable' }))
 : Promise.resolve({ ok: false, error: 'Private socket disabled by settings' }),
 v16RuntimeSend('v16:getPrivateAccountSnapshot', { profileId: profile.id, force: !!force }),
 ]);
 if (socketResult.ok) socketSnapshot = socketResult.snap;
 else socketError = socketResult.error;

 if (!response?.ok && !socketSnapshot) {
 v16LiveAccountView = {
 ...v16LiveAccountView,
 status: 'error',
 data: null,
 error: response?.error || socketError || 'Failed to load private Delta data.',
 fetchedAt: Date.now(),
 rateLimit: null,
 };
 v16UpdateRateLimitBanner(null);
 if (statusEl) statusEl.textContent = v16LiveAccountView.error;
 return null;
 }

 const restRateLimit = v16NormalizeRateLimitMeta(response?.rateLimit || null);
 const restSnapshot = response?.ok ? {
 walletBalances: Array.isArray(response.walletBalances) ? response.walletBalances : [],
 positions: Array.isArray(response.positions) ? response.positions : [],
 marginedPositions: Array.isArray(response.marginedPositions) ? response.marginedPositions : [],
 fills: Array.isArray(response.fills) ? response.fills : [],
 orderHistory: Array.isArray(response.orderHistory) ? response.orderHistory : [],
 openOrders: Array.isArray(response.openOrders) ? response.openOrders : [],
 walletTransactions: Array.isArray(response.walletTransactions) ? response.walletTransactions : [],
 fillsToday: Array.isArray(response.fillsToday) ? response.fillsToday : [],
 orderHistoryToday: Array.isArray(response.orderHistoryToday) ? response.orderHistoryToday : [],
 walletTransactionsToday: Array.isArray(response.walletTransactionsToday) ? response.walletTransactionsToday : [],
 historyWindowStart: Number(response.historyWindowStart || 0),
 historyWindowDays: Number(response.historyWindowDays || 0),
 candidateSnapshots: Array.isArray(response.candidateSnapshots) ? response.candidateSnapshots : [],
 historyDiagnostics: response?.historyDiagnostics && typeof response.historyDiagnostics === 'object' ? response.historyDiagnostics : {},
 fetchedAt: Number(response.fetchedAt || Date.now()),
 region: response.region || '',
 baseUrl: response.baseUrl || '',
 cached: !!response.cached,
 cacheAgeMs: Number(response.cacheAgeMs || 0),
 rateLimit: restRateLimit,
 } : null;

 const snapshot = {
 walletBalances: Array.isArray(socketSnapshot?.walletBalances) && socketSnapshot.walletBalances.length ? socketSnapshot.walletBalances : (restSnapshot?.walletBalances || []),
 positions: Array.isArray(socketSnapshot?.positions) && socketSnapshot.positions.length ? socketSnapshot.positions : (restSnapshot?.positions || []),
 marginedPositions: Array.isArray(socketSnapshot?.marginedPositions) && socketSnapshot.marginedPositions.length ? socketSnapshot.marginedPositions : (restSnapshot?.marginedPositions || []),
 fills: v16MergeUniqueRecords(socketSnapshot?.fills || [], restSnapshot?.fills || [], ['fill_id', 'f', 'id', 'order_id', 'o']),
 orderHistory: v16MergeUniqueRecords(socketSnapshot?.orderHistory || [], restSnapshot?.orderHistory || [], ['order_id', 'id', 'client_order_id']),
 openOrders: v16MergeUniqueRecords(socketSnapshot?.openOrders || [], restSnapshot?.openOrders || [], ['order_id', 'id', 'client_order_id']),
 walletTransactions: restSnapshot?.walletTransactions || [],
 fillsToday: restSnapshot?.fillsToday || [],
 orderHistoryToday: restSnapshot?.orderHistoryToday || [],
 walletTransactionsToday: restSnapshot?.walletTransactionsToday || [],
 historyWindowStart: Number(restSnapshot?.historyWindowStart || 0),
 historyWindowDays: Number(restSnapshot?.historyWindowDays || 0),
 candidateSnapshots: Array.isArray(restSnapshot?.candidateSnapshots) ? restSnapshot.candidateSnapshots : [],
 historyDiagnostics: restSnapshot?.historyDiagnostics || {},
 fetchedAt: Number(socketSnapshot?.fetchedAt || restSnapshot?.fetchedAt || Date.now()),
 region: socketSnapshot?.region || restSnapshot?.region || '',
 baseUrl: socketSnapshot?.baseUrl || restSnapshot?.baseUrl || '',
 cached: !!restSnapshot?.cached,
 cacheAgeMs: Number(restSnapshot?.cacheAgeMs || 0),
 rateLimit: restRateLimit,
 socketError,
 marketDataMode,
 feedSource: socketSnapshot && restSnapshot ? 'socket+rest' : (socketSnapshot ? 'socket' : 'rest'),
 };

 v16LiveAccountView = {
 ...v16LiveAccountView,
 status: 'success',
 data: snapshot,
 fetchedAt: Date.now(),
 error: '',
 rateLimit: restRateLimit,
 };
 v16UpdateRateLimitBanner(restRateLimit, 'Private account');
 await storeSet({ [V16_LIVE_SNAPSHOT_KEY]: snapshot });

 if (statusEl) {
 const transportCopy = socketSnapshot
 ? ' | Private socket live'
 : socketError
 ? ' | REST mode (socket unavailable)'
 : '';
 const cooldownCopy = restRateLimit ? ` | API cooldown ${v16FormatDurationShort(restRateLimit.waitMs)} (cached)` : '';
 statusEl.textContent = `Live Delta data loaded from ${String(snapshot.region || '').toUpperCase()} | ${v16ShortBaseUrl(snapshot.baseUrl)}${transportCopy}${cooldownCopy}`;
 }
 return snapshot;
 })().finally(() => {
 v16PrivateAccountRefreshPromise = null;
 });

 return v16PrivateAccountRefreshPromise;
}

async function v16LoadLiveAccountPaneContext(preloaded = null, forceRefresh = false) {
 const syncEnabled = v16IsLiveAccountSyncEnabled();
 let snapshot = forceRefresh
 ? await refreshV16PrivateAccountData(true)
 : (!syncEnabled
 ? (await storeGet(V16_LIVE_SNAPSHOT_KEY))?.[V16_LIVE_SNAPSHOT_KEY] || null
 : (await refreshV16PrivateAccountData(false)) || (await storeGet(V16_LIVE_SNAPSHOT_KEY))?.[V16_LIVE_SNAPSHOT_KEY] || null);
 if (
 snapshot
 && !forceRefresh
 && syncEnabled
 && !(Array.isArray(snapshot?.fills) && snapshot.fills.length)
 && !(Array.isArray(snapshot?.orderHistory) && snapshot.orderHistory.length)
 && !v16NormalizeRateLimitMeta(snapshot?.rateLimit)
 && v16CapabilityAllowsAccountRead()
 ) {
 snapshot = (await refreshV16PrivateAccountData(true).catch(() => snapshot)) || snapshot;
 }
 if (!snapshot) {
 return {
 syncEnabled,
 snapshot: null,
 metrics: null,
 history: [],
 activeRateLimit: null,
 statusText: syncEnabled
 ? 'Load a Trade Enabled or Read Only profile with session secrets to fetch private Delta account data.'
 : 'Live account sync is paused in Settings. Enable it or click Refresh for an on-demand snapshot.',
 statusClass: 'live-account-status',
 };
 }
 const scanResults = Array.isArray(preloaded?.scanResults) ? preloaded.scanResults : ((await getV16Snapshot())?.scanResults || []);
 const fundingHeatmap = Array.isArray(preloaded?.fundingHeatmap) ? preloaded.fundingHeatmap : ((await storeGet(['fundingHeatmap']))?.fundingHeatmap || []);
 const notesStore = await storeGet(V16_LIVE_JOURNAL_NOTES_KEY);
 const notesMap = notesStore?.[V16_LIVE_JOURNAL_NOTES_KEY] || {};
 const autoTradeStore = await storeGet(['autoTradeLog', 'autoTradeSettings', 'optionsStraddleLog', V16_AUTO_TRADE_MANUAL_CONTROLS_KEY, V16_NOTIFICATION_FEED_KEY, V16_UX_HINT_DISMISSALS_KEY, 'alerts']);
 const autoTradeLog = Array.isArray(autoTradeStore?.autoTradeLog) ? autoTradeStore.autoTradeLog : [];
 const straddleLog = Array.isArray(autoTradeStore?.optionsStraddleLog) ? autoTradeStore.optionsStraddleLog : [];
 const autoTradeSettings = autoTradeStore?.autoTradeSettings || {};
 const manualControls = v16SanitizeManualControls(autoTradeStore?.[V16_AUTO_TRADE_MANUAL_CONTROLS_KEY] || {});
 const notificationFeed = Array.isArray(autoTradeStore?.[V16_NOTIFICATION_FEED_KEY]) ? autoTradeStore[V16_NOTIFICATION_FEED_KEY] : [];
 const uxHintDismissals = v16NormalizeUxHintDismissals(autoTradeStore?.[V16_UX_HINT_DISMISSALS_KEY] || {});
 const alerts = Array.isArray(autoTradeStore?.alerts) ? autoTradeStore.alerts : [];
 v16LiveAccountView.autoTradeSettings = autoTradeSettings;
 v16LiveAccountView.uxHintDismissals = uxHintDismissals;
 const activeProfileId = String(getV16ActiveAccountProfile().id || '').trim();
 const productDefinitions = await v16BuildProductDefinitionsForSnapshot(snapshot);

 // Auto-fill journal entries for auto-traded positions
 let notesUpdated = false;
 const allAutoEntries = [...autoTradeLog, ...straddleLog];
 for (const atEntry of allAutoEntries) {
 const sym = v16NormalizeSymbol(atEntry?.symbol || atEntry?.straddleLeg?.symbol || '');
 if (!sym) continue;
 // Build possible trade IDs that could match
 const matchTradeIds = Object.keys(notesMap).length > 0 ? [] : null; // skip if no notes at all
 // For each trade, check if notes already exist - if not, auto-generate
 // This runs once per render - we'll match by symbol + close time
 }
 // Auto-fill: iterate resolved trades and match to auto-trade entries
 const tempMetrics = v16ComputeSessionMetrics(snapshot, scanResults, notesMap, productDefinitions);
 console.log('[JOURNAL] Auto-fill: trades=' + tempMetrics.trades.length + ' atLog=' + autoTradeLog.length + ' straddleLog=' + straddleLog.length);
 for (const trade of tempMetrics.trades) {
 const tradeId = String(trade.id || '');
 const existingNotes = String(notesMap[tradeId]?.notes || '');
 const hasManualNotes = !!existingNotes && !existingNotes.startsWith('[Auto]');
 if (!tradeId || hasManualNotes) continue; // preserve manual notes, refresh auto-generated notes
 const sym = v16NormalizeSymbol(trade.symbol || '');
 // Match to futures auto-trade log
 const atMatch = v16ResolveAutoTradeJournalMatch(trade, autoTradeLog);
 // Match to straddle log
 const stMatch = straddleLog.find(sl => {
 const slSym = v16NormalizeSymbol(sl?.straddleLeg?.symbol || sl?.callLeg?.symbol || '');
 return slSym === sym;
 });
 const matched = atMatch || stMatch;
 console.log('[JOURNAL] Trade', tradeId, sym, 'match:', !!matched, 'hasNotes:', !!(notesMap[tradeId]?.notes));
 if (!matched) continue;
 const isStraddle = !!stMatch;
 const score = Number(matched.score || matched.straddleLeg?.score || matched.tradeQuality || 0);
 const tier = String(matched.tier || matched.alertTier || '').toUpperCase();
 const direction = String(trade.side || v16ResolveEntryDirectionLabel(matched) || '').toUpperCase();
 const closeReason = v16ResolveJournalCloseReason(trade, matched, tempMetrics.orderHistory || []);
 const source = isStraddle ? 'Straddle Auto-Trade' : 'Scanner Auto-Trade';
 const setupTag = isStraddle
 ? (matched.type === 'native_straddle' ? 'Native Straddle' : 'Synthetic Straddle')
 : (String(matched.setupFamilyLabel || '').trim()
 || v16HumanizeSetupFamily(matched.setupFamily || '')
 || (tier ? v16HumanizeSetupFamily(`auto_${tier.toLowerCase()}`) : 'Auto Trade'));
 const confidence = score >= 85 ? 5 : score >= 70 ? 4 : score >= 50 ? 3 : score >= 30 ? 2 : 1;
 const noteLines = [
 `[Auto] ${source} | ${direction}`,
 !isStraddle && setupTag ? `Setup: ${setupTag}` : '',
 `Score: ${score}${tier ? ` | Tier: ${tier}` : ''}`,
 isStraddle ? `Strike: ${matched.atmStrike || '?'} | Spot@Entry: $${Number(matched.spotAtEntry || 0).toFixed(0)}` : '',
 matched.sl ? `SL: $${Number(matched.sl).toFixed(4)}` : '',
 matched.tp ? `TP: $${Number(matched.tp).toFixed(4)}` : '',
 closeReason && closeReason !== 'active' ? `Closed: ${closeReason}` : '',
 ].filter(Boolean).join('\n');
 notesMap[tradeId] = v16NormalizeJournalRecord({
 notes: noteLines,
 setupTag,
 mistakeTag: '',
 confidence,
 checklist: { followedPlan: true, respectedRisk: true, cleanExecution: true },
 updatedAt: Date.now(),
 });
 notesUpdated = true;
 }
 if (notesUpdated) {
 await storeSet({ [V16_LIVE_JOURNAL_NOTES_KEY]: notesMap });
 }
 const metrics = v16ComputeSessionMetrics(snapshot, scanResults, notesMap, productDefinitions);
 metrics.trades = (Array.isArray(metrics.trades) ? metrics.trades : []).map(trade =>
 v16EnrichTradeWithAutoTradeContext(trade, autoTradeLog, metrics.orderHistory || [])
 );
 metrics.todayTrades = (Array.isArray(metrics.todayTrades) ? metrics.todayTrades : []).map(trade =>
 v16EnrichTradeWithAutoTradeContext(trade, autoTradeLog, metrics.orderHistory || [])
 );
 const fundingLookup = v16BuildPositionFundingLookup(scanResults, fundingHeatmap);
 metrics.positions = metrics.positions.map(position => ({
 ...position,
 notionalValue: v16ResolvePositionNotional(position),
 fundingEstimate: v16ResolvePositionFundingEstimate(position, fundingLookup),
 trailingEntry: v16ResolvePositionTrailingEntry(position, autoTradeLog, activeProfileId, autoTradeSettings),
 protection: null,
 }));
 metrics.positions = metrics.positions.map(position => ({
 ...position,
 protection: v16ResolvePositionProtectionMeta(position, position.trailingEntry),
 autoTradeSizingSummary: v16BuildAutoTradeSizingSummary(position.trailingEntry),
 reverseTrade: v16ResolveReverseTradeMeta(position.trailingEntry || {}),
 }));
 const signalLookup = new Map();
 (Array.isArray(scanResults) ? scanResults : []).forEach(s => {
 if (s?.symbol) signalLookup.set(v16NormalizeSymbol(s.symbol), String(s.direction || '').toLowerCase());
 });
 metrics.positions = metrics.positions.map(position => ({
 ...position,
 currentSignal: signalLookup.get(v16NormalizeSymbol(position.symbol || '')) || '',
 }));
 const occupiedSymbols = new Set([
 ...(Array.isArray(metrics.positions) ? metrics.positions : []).map(position => v16NormalizeSymbol(position?.symbol || '')),
 ...(Array.isArray(metrics.openOrders) ? metrics.openOrders : [])
 .filter(order => !order?.reduceOnly && ['open', 'pending'].includes(String(order?.state || '').toLowerCase()))
 .map(order => v16NormalizeSymbol(order?.symbol || '')),
 ].filter(Boolean));
 metrics.manualControls = manualControls;
 metrics.manualReservedSlots = v16CountReservedSlotsFromControls(manualControls, occupiedSymbols);
 metrics.notificationFeed = notificationFeed;
 metrics.uxHintDismissals = uxHintDismissals;
 metrics.recentAlerts = alerts;
 metrics.autoTradeLog = autoTradeLog;
 v16LiveAccountView.lastPositionMetrics = metrics;
 const straddleDashboard = await v16RuntimeSend('v17:getStraddleDashboard', {});
 metrics.straddleDashboard = straddleDashboard?.ok ? straddleDashboard : { ok: false, entries: [], summary: { activeCount: 0, closedCount: 0, activePnlUSD: 0, premiumOpenUSD: 0 } };
 const history = await v16AppendEquityHistory(metrics);
 await v16SyncLiveManageHistory(metrics, history);
 const activeRateLimit = v16NormalizeRateLimitMeta(snapshot?.rateLimit);
 const fillAttemptError = (Array.isArray(metrics?.historyDiagnostics?.fills?.attempts) ? metrics.historyDiagnostics.fills.attempts : [])
 .map(attempt => attempt?.error)
 .find(Boolean) || '';
 const orderAttemptError = (Array.isArray(metrics?.historyDiagnostics?.orderHistory?.attempts) ? metrics.historyDiagnostics.orderHistory.attempts : [])
 .map(attempt => attempt?.error)
 .find(Boolean) || '';
 const rawHistoryCopy = (metrics.rawFillCount !== metrics.fills.length || metrics.rawOrderCount !== metrics.orderHistory.length)
 ? ` | Raw ${metrics.rawFillCount} fills / ${metrics.rawOrderCount} orders`
 : '';
 const historyErrorCopy = (!metrics.fills.length && !metrics.orderHistory.length && (fillAttemptError || orderAttemptError))
 ? ` | History error: ${fillAttemptError || orderAttemptError}`
 : '';
 const cooldownCopy = activeRateLimit
 ? ` | API cooldown ${v16FormatDurationShort(activeRateLimit.waitMs)} | extra refresh paused`
 : '';
 const syncCopy = !syncEnabled ? ' | auto sync paused' : '';
 const modeLabel = v16MarketDataModeLabel(snapshot?.marketDataMode || globalThis.deltaMarketDataMode || 'auto');
 const updatedLabel = v16FormatFeedAge(snapshot?.fetchedAt || 0);
 const compactStatus = `Wallet ${metrics.walletSymbol} ${v16FmtNumber(metrics.walletBalance, 2)} | Available ${v16FmtNumber(metrics.walletAvailable, 2)} | ${metrics.positions.length} pos | ${metrics.openOrders.length} orders | ${modeLabel}${syncEnabled ? '' : ' paused'} | ${updatedLabel}`;
 const detailStatus = `Wallet ${metrics.walletSymbol} ${v16FmtNumber(metrics.walletBalance, 2)} | Available ${v16FmtNumber(metrics.walletAvailable, 2)} | ${metrics.positions.length} open positions | ${metrics.openOrders.length} open orders | Parsed ${metrics.fills.length} fills / ${metrics.orderHistory.length} orders${rawHistoryCopy}${historyErrorCopy}${syncCopy}${cooldownCopy} | Mode ${modeLabel} | Feed ${v16MarketDataSourceLabel(snapshot?.feedSource || 'rest')} | Updated ${updatedLabel}`;
 const statusText = `${compactStatus}${historyErrorCopy}${activeRateLimit ? ` | cooldown ${v16FormatDurationShort(activeRateLimit.waitMs)}` : ''}`;
 return {
 syncEnabled,
 snapshot,
 metrics,
 history,
 activeRateLimit,
 statusText,
 statusDetail: detailStatus,

// Positions, funds, orders, settings bindings, init and VAR dashboard
 statusClass: `live-account-status ${activeRateLimit ? 'warn' : (metrics.todayPnl >= 0 ? 'good' : 'bad')}`,
 };
}

// Positions, orders, settings bindings, init and VAR dashboard
async function renderV16PositionsPane(preloaded = null, forceRefresh = false) {
 const pane = document.getElementById('pane-positions');
 if (!pane) return;
 v16ApplyTradingUiPrefs();
 v16LiveAccountView.positionNotificationsEnabled = localStorage.getItem('v16PositionNotificationsEnabled') === '1';
 const statusEl = document.getElementById('liveAccountStatus');
 const context = await v16LoadLiveAccountPaneContext(preloaded, forceRefresh);
 if (statusEl) {
 statusEl.textContent = context.statusText;
 statusEl.title = context.statusDetail || context.statusText || '';
 statusEl.className = context.statusClass;
 }
 if (!context.snapshot || !context.metrics) {
 v16UpdateRateLimitBanner(null);
 return;
 }
 v16UpdateRateLimitBanner(context.activeRateLimit, 'Positions');
 const { snapshot, metrics, history } = context;
 await v16RenderSystemHealthStrip('livePositionsHealthBar', { metrics, snapshot });
 v16RenderSessionCards(metrics);
 v16RenderPositions(metrics);
 const positionsSearchInput = document.getElementById('positionsSearchInput');
 if (positionsSearchInput) positionsSearchInput.value = String(v16LiveAccountView.positionsSearch || '');
 v16RenderJournal(metrics.trades);
 const todayHistory = history.filter(point => Number(point.ts || 0) >= v16StartOfToday());
 v16RenderEquityChart(todayHistory, metrics.todayTrades);
 const liveEquityMetaEl = document.getElementById('liveEquityMeta');
 if (liveEquityMetaEl) {
 liveEquityMetaEl.textContent = `${todayHistory.length} points today | Hover to inspect P&L and trade events | ${v16MarketDataSourceLabel(snapshot?.feedSource || 'rest')} | updated ${v16FormatFeedAge(snapshot?.fetchedAt || 0)}.`;
 }
 await renderV16RiskManageBoard();
}

function v16TradingUiPrefs() {
 return {
 compactDensity: localStorage.getItem('v16TradingCompactDensity') === '1',
 compactEquity: localStorage.getItem('v16TradingCompactEquity') === '1',
 };
}

function v16ApplyTradingUiPrefs() {
 const prefs = v16TradingUiPrefs();
 ['pane-positions', 'pane-orders', 'pane-funds'].forEach(id => {
 const pane = document.getElementById(id);
 if (pane) pane.classList.toggle('trading-density-compact', prefs.compactDensity);
 });
 document.querySelectorAll('[data-trading-density-toggle]').forEach(button => {
 button.classList.toggle('active', prefs.compactDensity);
 button.textContent = prefs.compactDensity ? 'Comfort density' : 'Compact density';
 });
 document.querySelectorAll('[data-equity-density-toggle]').forEach(button => {
 button.classList.toggle('active', prefs.compactEquity);
 button.textContent = prefs.compactEquity ? 'Full curve' : 'Compact curve';
 });
 document.querySelectorAll('.live-equity-card').forEach(card => {
 card.classList.toggle('is-compact', prefs.compactEquity);
 });
}

function v16RenderFunds(metrics = {}) {
 const hero = document.getElementById('liveFundsHero');
 const balanceGrid = document.getElementById('liveFundsBalanceGrid');
 const balanceMeta = document.getElementById('liveFundsBalanceMeta');
 const capacityGrid = document.getElementById('liveFundsCapacityGrid');
 const capacityMeta = document.getElementById('liveFundsCapacityMeta');
 const capacityMeter = document.getElementById('liveFundsCapacityMeter');
 const reconcileLine = document.getElementById('liveFundsReconcileLine');
 const ledgerList = document.getElementById('liveFundsLedgerList');
 const ledgerMeta = document.getElementById('liveFundsLedgerMeta');
 if (!hero || !balanceGrid || !capacityGrid || !ledgerList) return;
 v16LiveAccountView.lastFundsMetrics = metrics;
 v16ApplyTradingUiPrefs();
 const balances = Array.isArray(metrics.balances) ? metrics.balances : [];
 const positions = Array.isArray(metrics.positions) ? metrics.positions : [];
 const walletBalance = Number(metrics.walletBalance || 0);
 const walletAvailable = Number(metrics.walletAvailable || 0);
 const marginUsed = positions.reduce((sum, position) => sum + Number(position.margin || 0), 0);
 const reserved = Math.max(0, walletBalance - walletAvailable - marginUsed);
 const utilization = walletBalance > 0 ? (marginUsed / walletBalance) * 100 : 0;
 const exposure = Number(metrics.exposure?.notional || positions.reduce((sum, position) => sum + Math.abs(Number(position.notionalValue || 0)), 0));
 const equity = walletBalance + Number(metrics.unrealized || 0);
 const fmtMoney = value => `${metrics.walletSymbol || 'USD'} ${v16FmtNumber(Number(value || 0), 2)}`;
 const showZeroBalances = document.getElementById('liveFundsShowZero')?.checked === true;
 const visibleBalances = showZeroBalances ? balances : balances.filter(item => {
 const bal = Math.abs(Number(item.balance || 0));
 const avail = Math.abs(Number(item.available || 0));
 return bal > 0.00000001 || avail > 0.00000001;
 });
 hero.innerHTML = [
 { label: 'Wallet', value: fmtMoney(walletBalance), meta: `${visibleBalances.length}/${balances.length || 0} visible balance line${balances.length === 1 ? '' : 's'}`, tone: 'info' },
 { label: 'Available', value: fmtMoney(walletAvailable), meta: 'Free balance / available margin', tone: walletAvailable > 0 ? 'good' : 'warn' },
 { label: 'Margin used', value: fmtMoney(marginUsed), meta: `${v16FmtNumber(utilization, 1)}% wallet utilization`, tone: utilization >= 80 ? 'bad' : utilization >= 50 ? 'warn' : 'good' },
 { label: 'Net Today', value: v16FormatSignedCash(metrics.todayPnl || 0), meta: `Equity ${fmtMoney(equity)}`, tone: Number(metrics.todayPnl || 0) >= 0 ? 'good' : 'bad' },
 ].map(card => `<div class="funds-hero-card funds-hero-card--${v16Esc(card.tone)}"><span>${v16Esc(card.label)}</span><strong class="${v16Esc(card.tone)}">${v16Esc(card.value)}</strong><small>${v16Esc(card.meta)}</small></div>`).join('');
 if (balanceMeta) balanceMeta.textContent = `${visibleBalances.length} visible of ${balances.length || 0} wallet line${balances.length === 1 ? '' : 's'} | primary ${v16Esc(metrics.walletSymbol || 'USD')}`;
 balanceGrid.innerHTML = visibleBalances.length
 ? visibleBalances.map(item => {
 const bal = Number(item.balance || 0);
 const avail = Number(item.available || 0);
 const locked = Math.max(0, bal - avail);
 const pct = bal > 0 ? (avail / bal) * 100 : 0;
 return `<div class="funds-balance-row">
 <div><strong>${v16Esc(item.symbol || 'USD')}</strong><span>Balance ${v16FmtNumber(bal, 4)}</span></div>
 <div><strong>${v16FmtNumber(avail, 4)}</strong><span>Available</span></div>
 <div><strong>${v16FmtNumber(locked, 4)}</strong><span>Locked</span></div>
 <div class="funds-meter"><span style="width:${Math.max(0, Math.min(100, pct))}%"></span></div>
 </div>`;
 }).join('')
 : `<div class="empty"><div class="ei">--</div><div class="eh">${balances.length ? 'Zero balances hidden' : 'No balance returned'}</div><div class="es">${balances.length ? 'Enable Show zero balances to inspect empty assets.' : 'Refresh after API credentials are saved.'}</div></div>`;
 if (capacityMeta) capacityMeta.textContent = `${positions.length} position${positions.length === 1 ? '' : 's'} | exposure ${fmtMoney(exposure)} | reserved estimate ${fmtMoney(reserved)}`;
 if (capacityMeter) {
 const usedPct = Math.max(0, Math.min(100, utilization));
 const exposurePct = walletBalance > 0 ? Math.max(0, Math.min(100, (exposure / walletBalance) * 100)) : 0;
 capacityMeter.innerHTML = `
 <div class="funds-meter-row"><span>Margin use</span><strong>${v16FmtNumber(usedPct, 1)}%</strong></div>
 <div class="funds-capacity-track"><span class="${usedPct >= 80 ? 'bad' : usedPct >= 50 ? 'warn' : 'good'}" style="width:${usedPct}%"></span></div>
 <div class="funds-meter-row"><span>Open notional vs wallet</span><strong>${walletBalance > 0 ? `${v16FmtNumber(exposurePct, 1)}%` : '--'}</strong></div>
 <div class="funds-capacity-track exposure"><span style="width:${exposurePct}%"></span></div>`;
 }
 if (reconcileLine) {
 reconcileLine.innerHTML = `<strong>Reconcile</strong><span>Wallet equity = ${fmtMoney(walletBalance)} wallet + ${v16FmtSigned(Number(metrics.unrealized || 0))} unrealized = ${fmtMoney(equity)}</span>`;
 }
 capacityGrid.innerHTML = [
 ['Wallet equity', fmtMoney(equity), 'Wallet plus unrealized P&L'],
 ['Available funds', fmtMoney(walletAvailable), 'Ready for new margin or withdrawal'],
 ['Position margin', fmtMoney(marginUsed), `${positions.length} open position${positions.length === 1 ? '' : 's'}`],
 ['Reserved / locked', fmtMoney(reserved), 'Balance not currently free'],
 ['Open notional', fmtMoney(exposure), 'Absolute live exposure'],
 ['Unrealized P&L', v16FmtSigned(metrics.unrealized || 0), 'Current open P&L'],
 ['Closed today', v16FmtSigned(metrics.realizedToday || 0), metrics.realizedJournalSource || 'Realized source'],
 ['Fees + funding', v16FmtSigned(-Math.abs(Number(metrics.feesPaidToday || 0)) + Number(metrics.feeCreditsToday || 0) + Number(metrics.fundingToday || 0)), 'Today fee/funding impact'],
 ].map(([label, value, meta]) => `<div class="funds-capacity-item"><span>${v16Esc(label)}</span><strong>${v16Esc(value)}</strong><small>${v16Esc(meta)}</small></div>`).join('');
 const ledgerFilter = String(document.getElementById('liveFundsLedgerFilter')?.value || 'all').toLowerCase();
 const allRecent = (Array.isArray(metrics.walletTransactions) ? metrics.walletTransactions : []);
 const filteredRecent = allRecent.filter(item => {
 if (ledgerFilter === 'all') return true;
 const role = v16WalletTransactionRole(item).toLowerCase();
 if (ledgerFilter === 'transfer') return /deposit|withdraw|transfer/i.test(role);
 return role.includes(ledgerFilter);
 });
 const recent = filteredRecent.slice(0, 12);
 if (ledgerMeta) ledgerMeta.textContent = recent.length ? `${recent.length} latest ${ledgerFilter === 'all' ? 'wallet' : ledgerFilter} transaction${recent.length === 1 ? '' : 's'}` : 'No wallet transactions returned.';
 ledgerList.innerHTML = recent.length
 ? recent.map(item => {
 const role = v16WalletTransactionRole(item);
 const amount = Number(item.amount || 0);
 return `<div class="funds-ledger-row funds-ledger-row--${amount >= 0 ? 'good' : 'bad'}">
 <div><strong>${v16Esc(role.replace(/_/g, ' '))}</strong><span>${v16Esc(v16FormatTs(item.createdAt || 0))}</span></div>
 <div><strong class="${amount >= 0 ? 'good' : 'bad'}">${v16FmtSigned(amount)}</strong><span>${v16Esc(item.asset || metrics.walletSymbol || 'USD')}</span></div>
 </div>`;
 }).join('')
 : `<div class="empty"><div class="ei">--</div><div class="eh">No ${ledgerFilter === 'all' ? 'cash movement' : ledgerFilter} movement loaded</div><div class="es">Delta did not return matching wallet transactions for this profile.</div></div>`;
}

