function v16ResolveAcceptedOrderState(response = {}) {
 const candidates = [
 response?.result?.state,
 response?.result?.order_state,
 response?.result?.orderState,
 response?.result?.status,
 response?.order?.state,
 response?.preview?.state,
 ].map(value => String(value || '').trim().toLowerCase()).filter(Boolean);
 return candidates[0] || '';
}

function v16NotifyOrderConfirmation(title = 'Order placed', message = '') {
 const safeTitle = String(title || 'Order placed');
 const safeMessage = String(message || 'Order request was accepted.');
 globalThis.showSystemToast?.(safeTitle, safeMessage, 'success', 4200);
 try {
 chrome.notifications?.create?.(`fwd-order-${Date.now()}`, {
 type: 'basic',
 iconUrl: 'icons/icon128.png',
 title: safeTitle,
 message: safeMessage,
 priority: 1,
 }, () => void chrome.runtime?.lastError);
 } catch (_) {}
}

function v16NotifyLiveTradeAccepted(draft = {}, response = {}) {
 const symbol = String(draft.symbol || response?.preview?.symbol || '').trim().toUpperCase() || 'Order';
 const side = normalizePositionSide(draft.side || response?.preview?.side || '', 'long') === 'short' ? 'SELL' : 'BUY';
 const size = Math.max(0, Math.round(Number(response?.preview?.size || draft.size || 0)));
 const state = v16ResolveAcceptedOrderState(response);
 const traded = ['filled', 'fully_filled', 'closed', 'complete', 'completed', 'executed'].some(token => state.includes(token));
 const title = traded ? 'Order traded' : 'Order placed';
 const message = `${side} ${symbol}${size > 0 ? ` x ${size}` : ''} ${traded ? 'filled on Delta.' : 'sent to Delta.'}`;
 v16NotifyOrderConfirmation(title, message);
}

async function submitV16LiveOrder() {
 const previewCard = document.getElementById('liveOrderPreviewCard');
 const submitBtn = document.getElementById('liveOrderSubmit');
 if (!previewCard || !submitBtn) return;
 if (v16LiveAccountView.submitInFlight) {
 previewCard.innerHTML = '<div class="account-inline-note warn">Order is already being submitted. Wait for confirmation before pressing Place Order again.</div>';
 return;
 }
 v16LiveAccountView.submitInFlight = true;
 submitBtn.disabled = true;
 previewCard.innerHTML = '<div class="account-inline-note">Submitting request...</div>';
 let response = null;
 try {
 if (v16LiveAccountView.activeOpenOrder) {
 response = await v16RuntimeSend('v16:updateOrder', v16ReadOpenOrderEditDraftFromForm());
 if (!response?.ok) {
 previewCard.innerHTML = `<div class="account-inline-note bad">${v16Esc(response?.error || 'Failed to update order.')}</div>`;
 submitBtn.disabled = false;
 return;
 }
 v16LiveAccountView.lastOrderAction = { type: response.mode === 'cancel_replace' ? 'replaced' : 'updated', symbol: String(v16LiveAccountView.activeOpenOrder.symbol || '').trim().toUpperCase(), at: Date.now() };
 previewCard.innerHTML = `<div class="account-inline-note good">${v16Esc(response.warning || 'Order update sent to Delta.')}</div>`;
 v16NotifyOrderConfirmation('Order updated', `${v16LiveAccountView.lastOrderAction.symbol || 'Order'} update sent to Delta.`);
 } else if (v16LiveAccountView.protectionOrder) {
 response = await v16RuntimeSend('v16:placeProtectionOrder', {
 profileId: getV16ActiveAccountProfile().id,
 ...v16ReadProtectionOrderDraftFromForm(),
 });
 if (!response?.ok) {
 previewCard.innerHTML = `<div class="account-inline-note bad">${v16Esc(response?.error || 'Failed to place protection order.')}</div>`;
 submitBtn.disabled = false;
 return;
 }
 v16LiveAccountView.lastOrderAction = { type: v16LiveAccountView.protectionOrder.kind === 'target' ? 'target-placed' : 'stop-placed', symbol: String(v16LiveAccountView.protectionOrder.symbol || '').trim().toUpperCase(), at: Date.now() };
 previewCard.innerHTML = '<div class="account-inline-note good">Protection order sent to Delta.</div>';
 v16NotifyOrderConfirmation('Protection order placed', `${v16LiveAccountView.lastOrderAction.symbol || 'Order'} protection order sent to Delta.`);
 } else if (v16LiveAccountView.positionAction) {
 const positionActionDraft = document.getElementById('livePositionActionOrderType')
 ? v16ReadPositionActionDraftFromForm()
 : v16LiveAccountView.positionAction;
 v16LiveAccountView.positionAction = positionActionDraft;
 response = await v16RuntimeSend('v16:placePositionAction', {
 profileId: getV16ActiveAccountProfile().id,
 ...positionActionDraft,
 });
 if (!response?.ok) {
 previewCard.innerHTML = `<div class="account-inline-note bad">${v16Esc(response?.error || 'Failed to execute position action.')}</div>`;
 submitBtn.disabled = false;
 return;
 }
 v16LiveAccountView.lastOrderAction = { type: String(v16LiveAccountView.positionAction.requestedAction || 'close'), symbol: String(v16LiveAccountView.positionAction.symbol || '').trim().toUpperCase(), at: Date.now() };
 previewCard.innerHTML = `<div class="account-inline-note good">${v16Esc(response.warning || 'Position action sent to Delta.')}</div>`;
 v16NotifyOrderConfirmation('Position order placed', `${v16LiveAccountView.lastOrderAction.symbol || 'Position'} action sent to Delta.`);
 } else {
 const draft = v16ReadLiveOrderDraftFromForm();
 const profile = getV16ActiveAccountProfile();
 const blockReason = v16ResolveTradeEntryBlockReason({
 symbol: draft.symbol,
 preview: v16LiveAccountView.preview || null,
 profile,
 draft,
 });
 if (blockReason) {
 previewCard.innerHTML = `<div class="account-inline-note bad">${v16Esc(blockReason)}</div>`;
 submitBtn.disabled = false;
 return;
 }
 response = await v16RuntimeSend('v16:placeTradeOrder', {
 profileId: profile.id,
 ...draft,
 });
 if (!response?.ok) {
 previewCard.innerHTML = `<div class="account-inline-note bad">${v16Esc(response?.error || 'Failed to place live order.')}</div>`;
 submitBtn.disabled = false;
 return;
 }
 v16LiveAccountView.lastOrderAction = { type: 'placed', symbol: draft.symbol, at: Date.now() };
 previewCard.innerHTML = '<div class="account-inline-note good">Live order sent to Delta.</div>';
 v16NotifyLiveTradeAccepted(draft, response);
 }
 await renderV16PositionsPane(null, true);
 setTimeout(() => {
 closeV16LiveOrderOverlay();
 }, 400);
 } finally {
 v16LiveAccountView.submitInFlight = false;
 }
}

