function getV16SignalActionState(signal = null) {
 const profile = getV16ActiveAccountProfile();
 const capabilityMeta = getAccountCapabilityMeta(profile.capability);
 const killSwitch = getV16KillSwitchState();
 const hasSecret = hasV16SessionSecret(profile.id);
 const side = normalizePositionSide(signal?.direction || signal?.side || '', 'long');
 const directionLabel = side === 'short' ? 'short' : 'long';
 const previewLabel = killSwitch.enabled
 ? 'Kill switch armed'
 : capabilityMeta.allowsTrade
 ? (hasSecret ? 'Trade-enabled preview' : 'Trade-enabled, no key loaded')
 : capabilityMeta.allowsAccountRead
 ? 'Read-only review'
 : 'Public research';
 return {
 profile,
 capabilityMeta,
 killSwitch,
 hasSecret,
 directionLabel,
 previewLabel,
 canPreviewTrade: capabilityMeta.allowsTrade && !killSwitch.enabled,
 };
}

function buildV16SignalActionMarkup(signal = null) {
 const actionState = getV16SignalActionState(signal);
 return `
 <div class="v16-signal-policy">
 <span class="policy-pill ${actionState.capabilityMeta.tone}">${v16Esc(v16ReadableCapabilityLabel(actionState.capabilityMeta.label))}</span>
 <span class="policy-copy">${v16Esc(actionState.profile.name)} | ${v16Esc(actionState.previewLabel)}</span>
 </div>
 <div class="v16-signal-actions">
 <button class="v16-signal-btn secondary" data-v16-card-action="chart">Open Chart</button>
 <button class="v16-signal-btn primary" data-v16-card-action="review">Review</button>
 <button class="v16-signal-btn secondary" data-v16-card-action="risk">Risk Bridge</button>
 </div>`;
}

function v16ResolveFundingSignalSide(signal = {}, settings = {}) {
 const baseSide = normalizePositionSide(signal?.direction || signal?.side || '', 'long');
 if (signal?.autoTradeExecutionDirection) return normalizePositionSide(signal.autoTradeExecutionDirection, baseSide);
 const reverseApplied = signal?.autoTradeReverseApplied === true || settings?.reverseSignals === true;
 return reverseApplied ? (baseSide === 'short' ? 'long' : 'short') : baseSide;
}

function v16IsFundingAdverseForSignal(signal = {}, threshold = 0, settings = {}) {
 const limit = Math.abs(Number(threshold || 0));
 const rate = Number(signal?.fundingRate || 0);
 const side = v16ResolveFundingSignalSide(signal, settings);
 if (!(limit > 0) || !rate) return false;
 return side === 'short' ? rate <= -limit : rate >= limit;
}

function v16BuildFundingForecast(signal = {}, settings = {}, profile = {}) {
 const rate = Number(signal?.fundingRate || 0);
 const side = v16ResolveFundingSignalSide(signal, settings);
 const notional = Math.max(0, Number(settings?.autoSizeUSD || profile?.maxOrderSizeUSD || 0));
 const intervalSeconds = v16NormalizeFundingIntervalSeconds(signal?.fundingIntervalSeconds || 28800);
 const eventsPerDay = v16FundingEventsPerDay(intervalSeconds);
 const intervalHours = v16FundingIntervalHours(intervalSeconds);
 const exposureFactor = side === 'short' ? rate : -rate;
 const perSettlement = notional > 0 ? (notional * (exposureFactor / 100)) : 0;
 return {
 notional,
 rate,
 intervalSeconds,
 intervalHours,
 eventsPerDay,
 nextFundingAt: Number(signal?.nextFundingAt || 0),
 costSettlement: perSettlement,
 cost24h: perSettlement * eventsPerDay,
 cost48h: perSettlement * eventsPerDay * 2,
 };
}

async function v16BuildSignalDecisionState(signal = {}) {
 const now = Date.now();
 const store = await storeGet([
 'autoTrade',
 'autoTradeSettings',
 'autoTradeCooldowns',
 'autoTradeDecisionAuditV16',
 V16_SETUP_PERFORMANCE_KEY,
 V16_AUTO_TRADE_MANUAL_CONTROLS_KEY,
 ]);
 const profile = getV16ActiveAccountProfile();
 const settings = sanitizeAutoTradeSettings(store?.autoTradeSettings || {});
 const decision = resolveDecisionAction(signal, signal?.activeThresholds || {});
 const entryTrigger = resolveEntryTrigger(signal, settings);
 const riskQuality = resolveRiskQualityGate(signal, settings);
 const symbol = v16NormalizeSymbol(signal?.symbol || '');
 const perfRows = store?.[V16_SETUP_PERFORMANCE_KEY]?.rows || {};
 const familyKey = String(signal?.setupFamily || signal?.setupFamilyLabel || 'mixed').trim().toLowerCase().replace(/[^a-z0-9]+/g, '_').replace(/^_+|_+$/g, '') || 'mixed';
 const setupEdge = Object.values(perfRows)
 .filter(row => String(row?.familyKey || '').toLowerCase() === familyKey)
 .sort((a, b) => Number(b?.trades || 0) - Number(a?.trades || 0))[0] || null;
 const blockedSymbols = new Set(sanitizeBlockedSymbolList(profile?.blockedSymbols || []));
 const manualControls = v16SanitizeManualControls(store?.[V16_AUTO_TRADE_MANUAL_CONTROLS_KEY] || {}, now);
 const manual = v16ResolveManualControlRecord(manualControls, symbol, now);
 const liveMetrics = v16LiveAccountView.lastPositionMetrics || {};
 const slotSummary = v16ResolveConcurrentExposureSummary(liveMetrics);
 const fundingForecast = v16BuildFundingForecast(signal, settings, profile);
 const cooldownTs = Number(store?.autoTradeCooldowns?.[symbol] || 0);
 const cooldownMs = Math.max(0, Number(settings?.cooldownSec || 0) * 1000 - (now - cooldownTs));
 const currentExposureSymbols = new Set([
 ...(Array.isArray(liveMetrics.positions) ? liveMetrics.positions : []).map(position => v16NormalizeSymbol(position?.symbol || '')),
 ...(Array.isArray(liveMetrics.openOrders) ? liveMetrics.openOrders : [])
 .filter(order => !order?.reduceOnly && ['open', 'pending'].includes(String(order?.state || '').toLowerCase()))
 .map(order => v16NormalizeSymbol(order?.symbol || '')),
 ].filter(Boolean));
 const gating = [];
 if (!store?.autoTrade) gating.push('Auto-trade is off');
 if (!getAccountCapabilityMeta(profile?.capability).allowsTrade) gating.push('Active profile is not trade enabled');
 if (getV16KillSwitchState().enabled) gating.push('Kill switch is on');
 if (blockedSymbols.has(symbol)) gating.push('Symbol is blocked in the active profile');
 if (manual.paused) gating.push(`Manual pause active for ${v16FormatDurationShort(Math.max(0, Number(manual.record?.pausedUntil || 0) - now))}`);
 if (manual.reentryBlocked) gating.push(`Re-entry blocked for ${v16FormatDurationShort(Math.max(0, Number(manual.record?.reentryBlockedUntil || 0) - now))}`);
 if (manual.blockedToday) gating.push('Symbol is blocked for the rest of today');
 if (cooldownMs > 0) gating.push(`Cooldown active for ${v16FormatDurationShort(cooldownMs)}`);
 if (decision.action !== 'TRADE NOW') gating.push(v16DescribeDecisionAction(decision.action || 'PASS'));
 if (!(Number(signal?.tradeQuality?.score || 0) >= Number(settings?.minScore || 75))) gating.push(`Trade quality ${Number(signal?.tradeQuality?.score || 0)} is below ${Number(settings?.minScore || 75)}`);
 if (!(signal?.entry && signal?.sl && (signal?.tp1 || signal?.tp))) gating.push('Signal is missing entry, stop, or target');
 if (settings.entryTriggerRequired && !entryTrigger.passed) gating.push(`Entry trigger waiting: ${(entryTrigger.reasons || []).join(', ') || 'confirmation required'}`);
 if (settings.riskQualityRequired && !riskQuality.passed) gating.push(`Risk quality blocked: ${(riskQuality.reasons || []).join(', ') || 'quality gate failed'}`);
 if (!manual.ignoreFunding && v16IsFundingAdverseForSignal(signal, Number(settings?.maxAdverseFundingRatePct || 0), settings)) gating.push('Funding is adverse for the proposed side');
 if (!currentExposureSymbols.has(symbol) && slotSummary.available <= 0) gating.push(`All trade slots are in use (${slotSummary.used}/${slotSummary.maxConcurrent} used)`);
 const eligible = gating.length === 0;
 const statusLabel = eligible
 ? 'Eligible now'
 : decision.action === 'TRADE NOW'
 ? 'Blocked now'
 : 'Setup only';
 const statusTone = eligible ? 'good' : (decision.action === 'TRADE NOW' ? 'bad' : 'warn');
 return {
 symbol,
 profile,
 settings,
 decision,
 manual,
 slotSummary,
 fundingForecast,
 entryTrigger,
 riskQuality,
 setupEdge,
 cooldownMs,
 gating,
 eligible,
 statusLabel,
 statusTone,
 audit: store?.autoTradeDecisionAuditV16 || {},
 };
}

async function v16RunSignalManualControlAction(signal = {}, kind = '') {
 const symbol = v16NormalizeSymbol(signal?.symbol || '');
 if (!symbol) return;
 const durationMs = {
 pause: 6 * 60 * 60 * 1000,
 reentry: 6 * 60 * 60 * 1000,
 ignore_funding: 8 * 60 * 60 * 1000,
 reserve_slot: 6 * 60 * 60 * 1000,
 }[kind] || 0;
 let response;
 if (kind === 'close_block_today') {
 response = await v16RuntimeSend('v16:closeAndBlockSymbolToday', { symbol });
 } else {
 response = await v16RuntimeSend('v16:updateAutoTradeManualControl', {
 symbol,
 kind,
 durationMs,
 });
 }
 if (!response?.ok) throw new Error(response?.error || 'Manual control update failed');
 showSystemToast('Manual control updated', `${symbol} ${kind.replace(/_/g, ' ')} applied.`, 'success', 3200);
 if (document.getElementById('pane-positions')?.classList.contains('active')) await renderV16PositionsPane(null, false);
 if (document.getElementById('pane-orders')?.classList.contains('active')) await renderV16OrdersPane(null, false);
}

