function v16RiskAutoToneClass(tone = '') {
 const safeTone = String(tone || '').trim().toLowerCase();
 return ['good', 'warn', 'bad', 'info', 'waiting'].includes(safeTone) ? safeTone : 'info';
}

function v16RiskAutoCardHtml(label = '', value = '', detail = '', tone = 'info') {
 return `<div class="risk-auto-card is-${v16Esc(v16RiskAutoToneClass(tone))}"><span>${v16Esc(label)}</span><strong>${v16Esc(value)}</strong>${detail ? `<small>${v16Esc(detail)}</small>` : ''}</div>`;
}

function v16RiskAutoCheckHtml(label = '', passed = false, detail = '') {
 return `<div class="risk-auto-check ${passed ? 'passed' : 'blocked'}"><span>${passed ? 'OK' : 'BLOCK'}</span><strong>${v16Esc(label)}</strong>${detail ? `<small>${v16Esc(detail)}</small>` : ''}</div>`;
}

function v16RiskAutoModeLabel({ autoTradeOn = false, settings = {} } = {}) {
 if (autoTradeOn) return 'Live';
 if (settings.paperTrackingEnabled) return 'Paper';
 if (settings.entryTriggerRequired || settings.riskQualityRequired) return 'Assist';
 return 'Off';
}

function v16RiskAutoMetricPositions(snapshot = null) {
 const livePositions = Array.isArray(snapshot?.marginedPositions) ? snapshot.marginedPositions : [];
 if (livePositions.length) return livePositions;
 const metricsPositions = Array.isArray(v16LiveAccountView?.lastPositionMetrics?.positions) ? v16LiveAccountView.lastPositionMetrics.positions : [];
 return metricsPositions;
}

async function renderV16RiskAutomationCockpit() {
 const root = document.getElementById('pane-riskcalc');
 if (!root) return;
 await loadV16AccountState();
 const store = await storeGet([
 'autoTrade',
 'autoTradeSettings',
 'autoTradeDailyLoss',
 'apiCircuitBreaker',
 'lastScan',
 'lastScanTs',
 V16_LIVE_SNAPSHOT_KEY,
 V16_AUTO_TRADE_MANUAL_CONTROLS_KEY,
 ]).catch(() => ({}));
 const profile = getV16ActiveAccountProfile();
 const capabilityMeta = getAccountCapabilityMeta(profile?.capability || 'Public');
 const killSwitch = getV16KillSwitchState();
 const hasSecret = hasV16SessionSecret(profile?.id || '');
 const settings = sanitizeAutoTradeSettings(store?.autoTradeSettings || {});
 const snapshot = store?.[V16_LIVE_SNAPSHOT_KEY] || v16LiveAccountView?.data || null;
 const positions = v16RiskAutoMetricPositions(snapshot);
 const openOrders = Array.isArray(snapshot?.openOrders) ? snapshot.openOrders : [];
 const manualControls = v16SanitizeManualControls(store?.[V16_AUTO_TRADE_MANUAL_CONTROLS_KEY] || {}, Date.now());
 const runtimeIssue = v16NormalizeRateLimitMeta(store?.apiCircuitBreaker || v16LiveAccountView?.rateLimit || null);
 const caps = resolveVarPositionCaps(profile, { marketIndex: globalThis._lastMarketIndex || snapshot?.marketIndex || null });
 const slotMax = Number(settings.maxConcurrent || caps.totalSlots || profile?.varMaxPositions || 0);
 const reservedSlots = v16CountReservedSlotsFromControls(manualControls, new Set(positions.map(position => v16NormalizeSymbol(position.symbol || position.product_symbol || ''))));
 const slotUsed = positions.length + reservedSlots;
 const dailyLossLimit = Number(settings.dailyLossLimitUSD || 0);
 const dailyLossUsed = Math.abs(Math.min(Number(store?.autoTradeDailyLoss || 0), 0));
 const profileReady = !!profile?.id && capabilityMeta.allowsAccountRead;
 const tradeCapable = !!capabilityMeta.allowsTrade;
 const apiReady = capabilityMeta.allowsAccountRead ? hasSecret : true;
 const riskReady = !(dailyLossLimit > 0 && dailyLossUsed >= dailyLossLimit) && !(slotMax > 0 && slotUsed >= slotMax);
 const automationMode = v16RiskAutoModeLabel({ autoTradeOn: !!store.autoTrade, settings });
 const liveAutomationAllowed = !!store.autoTrade && tradeCapable && apiReady && !killSwitch.enabled && riskReady && !runtimeIssue;
 const blockers = [];
 if (!tradeCapable && store.autoTrade) blockers.push('profile is not Trade Enabled');
 if (capabilityMeta.allowsAccountRead && !hasSecret) blockers.push('API session secret is missing');
 if (killSwitch.enabled) blockers.push('kill switch is on');
 if (dailyLossLimit > 0 && dailyLossUsed >= dailyLossLimit) blockers.push('daily loss limit reached');
 if (slotMax > 0 && slotUsed >= slotMax) blockers.push('all trade slots are in use');
 if (runtimeIssue) blockers.push('API is cooling down');
 if (!store.autoTrade) blockers.push('live automation is off');
 const decisionTitle = liveAutomationAllowed ? 'Live automation can place qualified orders' : `Trade blocked: ${blockers[0] || 'automation is not ready'}`;
 const decisionDetail = liveAutomationAllowed
 ? 'All core live gates are clear. Strategy checks still apply per signal.'
 : blockers.length ? blockers.join(', ') : 'Enable rules only after reviewing profile, API, and risk limits.';
 const strip = document.getElementById('riskAutomationStrip');
 if (strip) {
 const stripRows = [
 ['Profile', capabilityMeta.label || 'Public', profileReady ? (tradeCapable ? 'Trade-enabled profile' : 'Read-only profile') : 'Research profile only', profileReady ? (tradeCapable ? 'good' : 'warn') : 'warn'],
 ['API', apiReady ? 'Ready' : 'Missing', apiReady ? (hasSecret ? 'Private session available' : 'Public data only') : 'Save/test credentials', apiReady ? 'good' : 'bad'],
 ['Risk', riskReady ? 'Clear' : 'Blocked', dailyLossLimit > 0 ? `$${dailyLossUsed.toFixed(0)} / $${dailyLossLimit.toFixed(0)} daily loss` : `${slotUsed}/${slotMax || '-'} slots used`, riskReady ? 'good' : 'bad'],
 ['Automation', automationMode, liveAutomationAllowed ? 'Live gates clear' : (store.autoTrade ? 'Live toggle on, gate blocked' : 'No live order automation'), liveAutomationAllowed ? 'good' : (store.autoTrade ? 'bad' : 'warn')],
 ['Kill Switch', killSwitch.enabled ? 'On' : 'Off', killSwitch.reason || (killSwitch.enabled ? 'Execution locked' : 'No global execution block'), killSwitch.enabled ? 'bad' : 'good'],
 ];
 strip.innerHTML = stripRows.map(([label, value, detail, tone]) => `<div class="risk-auto-status is-${v16Esc(v16RiskAutoToneClass(tone))}"><span>${v16Esc(label)}</span><strong>${v16Esc(value)}</strong><small>${v16Esc(detail)}</small></div>`).join('');
 }
 const decision = document.getElementById('riskAutomationDecision');
 if (decision) {
 decision.className = `risk-auto-decision is-${liveAutomationAllowed ? 'good' : blockers.some(item => item.includes('kill') || item.includes('daily') || item.includes('slots') || item.includes('cooling')) ? 'bad' : 'warn'}`;
 const checks = [
 ['Profile allows live action', tradeCapable || !store.autoTrade, capabilityMeta.label || 'Public'],
 ['API/session ready', apiReady, hasSecret ? 'Private account calls can run' : 'No private credential session'],
 ['Kill switch off', !killSwitch.enabled, killSwitch.reason || 'Global guard is clear'],
 ['Daily loss under limit', !(dailyLossLimit > 0 && dailyLossUsed >= dailyLossLimit), dailyLossLimit > 0 ? `$${dailyLossUsed.toFixed(0)} / $${dailyLossLimit.toFixed(0)}` : 'No USD day-loss cap set'],
 ['Trade slots available', !(slotMax > 0 && slotUsed >= slotMax), slotMax > 0 ? `${slotUsed}/${slotMax} used` : 'No max concurrent cap set'],
 ['API cooldown clear', !runtimeIssue, runtimeIssue ? `Retry in ${v16FormatDurationShort(runtimeIssue.waitMs)}` : 'No cooldown recorded'],
 ];
 decision.innerHTML = `
 <div class="risk-auto-decision-main">
 <span>Decision Engine</span>
 <strong>${v16Esc(decisionTitle)}</strong>
 <small>${v16Esc(decisionDetail)}</small>
 </div>
 <div class="risk-auto-checks" id="riskAutomationChecks">
 ${checks.map(([label, passed, detail]) => v16RiskAutoCheckHtml(label, passed, detail)).join('')}
 </div>`;
 }
 const apiGrid = document.getElementById('riskApiSafetyGrid');
 if (apiGrid) {
 apiGrid.innerHTML = [
 v16RiskAutoCardHtml('Profile Mode', capabilityMeta.label || 'Public', capabilityMeta.description || 'Current account capability.', tradeCapable ? 'good' : capabilityMeta.allowsAccountRead ? 'warn' : 'info'),
 v16RiskAutoCardHtml('Credential State', hasSecret ? 'Session Ready' : 'No Secret', hasSecret ? 'Private account snapshot can be requested.' : 'Open API Keys and run Test API Key.', hasSecret ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Live Sync', v16IsLiveAccountSyncEnabled() ? 'On' : 'Off', v16IsLiveAccountSyncEnabled() ? 'Positions and analytics can refresh.' : 'Manual refresh only.', v16IsLiveAccountSyncEnabled() ? 'good' : 'warn'),
 v16RiskAutoCardHtml('API Cooldown', runtimeIssue ? 'Cooling' : 'Clear', runtimeIssue ? `Retry in ${v16FormatDurationShort(runtimeIssue.waitMs)}` : 'No private/public cooldown active.', runtimeIssue ? 'bad' : 'good'),
 v16RiskAutoCardHtml('Open Positions', String(positions.length), `${openOrders.length} open order${openOrders.length === 1 ? '' : 's'} currently known.`, positions.length ? 'info' : 'good'),
 v16RiskAutoCardHtml('Kill Switch', killSwitch.enabled ? 'On' : 'Off', killSwitch.reason || (killSwitch.enabled ? 'Execution locked.' : 'Execution guard clear.'), killSwitch.enabled ? 'bad' : 'good'),
 ].join('');
 }
 const apiNote = document.getElementById('riskApiSafetyNote');
 if (apiNote) {
 apiNote.textContent = apiReady
 ? 'API safety is usable. Keep live mode off until order permissions, max order size, and daily loss limits are confirmed.'
 : 'API safety is incomplete. Save/test credentials before expecting live positions, live analytics, or order previews.';
 apiNote.className = `risk-auto-note ${apiReady ? 'good' : 'warn'}`;
 }
 const preview = document.getElementById('riskAutomationRulePreview');
 if (preview) {
 preview.innerHTML = `<span>Rule Preview</span><strong>${v16Esc(decisionTitle)}</strong><small>${v16Esc(decisionDetail)}</small>`;
 }
 const rulesGrid = document.getElementById('riskAutomationRulesGrid');
 if (rulesGrid) {
 rulesGrid.innerHTML = [
 v16RiskAutoCardHtml('Automation Mode', automationMode, store.autoTrade ? 'Live futures auto-trade toggle is on.' : settings.paperTrackingEnabled ? 'Qualified signals go to paper ledger.' : 'Automation will not place live futures orders.', liveAutomationAllowed ? 'good' : store.autoTrade ? 'bad' : 'warn'),
 v16RiskAutoCardHtml('Entry Score', String(settings.minScore || 0), 'Minimum signal score for automated entry consideration.', Number(settings.minScore || 0) >= 70 ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Max Per Scan', String(settings.maxPerScan || 0), 'Limits how many new signals can be acted on per scan.', Number(settings.maxPerScan || 0) > 0 ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Max Per Day', String(settings.maxPerDay || 0), 'Daily automation entry cap.', Number(settings.maxPerDay || 0) > 0 ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Max Concurrent', String(settings.maxConcurrent || 0), `${slotUsed}/${slotMax || '-'} slots used including reserved manual controls.`, slotMax > 0 && slotUsed >= slotMax ? 'bad' : 'good'),
 v16RiskAutoCardHtml('Risk Quality Gate', settings.riskQualityRequired ? 'Required' : 'Optional', settings.riskQualityRequired ? `R:R >= ${settings.riskQualityMinRewardRisk}, stop <= ${settings.riskQualityMaxStopDistancePct}%` : 'Signals may pass without quality gate.', settings.riskQualityRequired ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Backtest Gate', `${settings.backtestMinTrades || 0} trades`, `PF >= ${settings.backtestMinProfitFactor || 0}, expectancy >= ${settings.backtestMinExpectancy || 0}.`, Number(settings.backtestMinTrades || 0) > 0 ? 'good' : 'warn'),
 v16RiskAutoCardHtml('Cooldown', `${settings.cooldownSec || 0}s`, 'Delay after automated action before next eligible entry.', Number(settings.cooldownSec || 0) > 0 ? 'good' : 'warn'),
 ].join('');
 }
 const rulesNote = document.getElementById('riskAutomationRulesNote');
 if (rulesNote) {
 rulesNote.textContent = liveAutomationAllowed
 ? 'Live automation is armed at the global level. Each signal still needs strategy, trigger, liquidity, funding, and risk-quality approval.'
 : `Live automation will not place orders because ${blockers.join(', ') || 'one or more gates are not ready'}.`;
 rulesNote.className = `risk-auto-note ${liveAutomationAllowed ? 'good' : 'warn'}`;
 }
}

function setRiskAutomationPanel(mode = 'cockpit') {
 const target = ['cockpit', 'api', 'automation'].includes(String(mode || '')) ? String(mode) : 'cockpit';
 document.querySelectorAll('[data-risk-auto-tab]').forEach(button => {
 const active = button.dataset.riskAutoTab === target;
 button.classList.toggle('active', active);
 button.setAttribute('aria-selected', active ? 'true' : 'false');
 });
 document.querySelectorAll('[data-risk-auto-panel]').forEach(panel => {
 panel.classList.toggle('active', panel.dataset.riskAutoPanel === target);
 });
 void renderV16RiskAutomationCockpit();
}

document.addEventListener('click', event => {
 const tab = event.target.closest('[data-risk-auto-tab]');
 if (!tab) return;
 setRiskAutomationPanel(tab.dataset.riskAutoTab || 'cockpit');
});

