function renderV16VarDashboard() {
 void renderV16RiskAutomationCockpit();
 const profile = typeof getV16ActiveAccountProfile === 'function' ? getV16ActiveAccountProfile() : {};
 const metrics = v16LiveAccountView?.lastPositionMetrics || {};
 const positions = metrics.positions || [];
 const marketIndex = globalThis._lastMarketIndex || v16LiveAccountView?.data?.marketIndex || null;
 const caps = resolveVarPositionCaps(profile, { marketIndex });

 // Profile config
 const totalCapital = Number(profile.baseBalance || 1000);
 const maxDDPct = Number(profile.varMaxDrawdownPct ?? 40);
 const cycleCount = Number(profile.varCycleCount ?? 4);
 const longAllocPct = Number(caps.longAllocationPct || 70);
 const shortAllocPct = Number(caps.shortAllocationPct || 30);
 const maxLongPos = Number(caps.longSlots || 7);
 const maxShortPos = Number(caps.shortSlots || 3);
 const maxPerSector = Number(profile.varMaxTradesPerSector ?? 2);
 const maxLossPerTrade = Number(profile.varMaxLossPerTradeUSD ?? 20);

 // Computed
 const maxDrawdown = totalCapital * (maxDDPct / 100);
 const cycleBudget = maxDrawdown / cycleCount;
 const longBudget = cycleBudget * (longAllocPct / 100);
 const shortBudget = cycleBudget * (shortAllocPct / 100);

 // Current state from live positions
 const longPositions = positions.filter(p => p.side === 'long');
 const shortPositions = positions.filter(p => p.side === 'short');
 const longCount = longPositions.length;
 const shortCount = shortPositions.length;

 // Compute total session drawdown (from metrics)
 const totalPnl = Number(metrics.netPnl ?? metrics.todayPnl ?? 0);
 const totalDrawdown = Math.abs(Math.min(totalPnl, 0));
 const currentCycle = Math.min(Math.floor(totalDrawdown / cycleBudget) + 1, cycleCount);
 const cycleUsed = totalDrawdown - (currentCycle - 1) * cycleBudget;
 const cycleRemaining = Math.max(cycleBudget - cycleUsed, 0);
 const cyclePct = cycleBudget > 0 ? Math.min((cycleUsed / cycleBudget) * 100, 100) : 0;

 // Long/Short notional used
 const longUsed = longPositions.reduce((s, p) => s + Math.abs(Number(p.exposurePlan?.maxLoss || 0)), 0);
 const shortUsed = shortPositions.reduce((s, p) => s + Math.abs(Number(p.exposurePlan?.maxLoss || 0)), 0);
 const longFillPct = longBudget > 0 ? Math.min((longUsed / longBudget) * 100, 100) : 0;
 const shortFillPct = shortBudget > 0 ? Math.min((shortUsed / shortBudget) * 100, 100) : 0;

 // Sector exposure
 const sectorCounts = {};
 positions.forEach(p => {
 const sector = typeof getSector === 'function' ? getSector(p.symbol || p.product_symbol || '') : 'Other';
 sectorCounts[sector] = (sectorCounts[sector] || 0) + 1;
 });

 // Format currency
 const fmtUSD = (v) => '$' + Math.abs(v).toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 0 });

 // --- Populate Summary Cards ---
 const el = (id) => document.getElementById(id);
 if (el('varTotalCapital')) el('varTotalCapital').textContent = fmtUSD(totalCapital);
 if (el('varMaxDD')) el('varMaxDD').textContent = fmtUSD(maxDrawdown);
 if (el('varMaxDDPct')) el('varMaxDDPct').textContent = `${maxDDPct}% of capital`;
 if (el('varCycleBudget')) el('varCycleBudget').textContent = fmtUSD(cycleBudget);
 if (el('varCycleLabel')) el('varCycleLabel').textContent = `Max DD / ${cycleCount} cycles`;
 if (el('varPerLotLoss')) el('varPerLotLoss').textContent = fmtUSD(maxLossPerTrade);

 // --- Cycle Progress ---
 if (el('varCycleTrack')) {
 let cycleHTML = '';
 for (let i = 1; i <= cycleCount; i++) {
 const state = i < currentCycle ? 'spent' : i === currentCycle ? 'active' : 'remaining';
 cycleHTML += `<div class="var-cycle-dot ${state}">
 <div class="var-cycle-num">${i}</div>
 <div class="var-cycle-status">${state === 'spent' ? 'Spent' : state === 'active' ? 'Active' : 'Reserve'}</div>
 </div>`;
 }
 el('varCycleTrack').innerHTML = cycleHTML;
 }
 if (el('varCycleFill')) {
 const cycleColor = cyclePct > 80 ? '#ff6b82' : cyclePct > 50 ? '#f0bf52' : '#2fe0a1';
 el('varCycleFill').style.width = cyclePct + '%';
 el('varCycleFill').style.background = cycleColor;
 }
 if (el('varCycleStats')) {
 el('varCycleStats').innerHTML = `Cycle ${currentCycle}/${cycleCount} | Used ${fmtUSD(cycleUsed)} / ${fmtUSD(cycleBudget)} | Remaining ${fmtUSD(cycleRemaining)}`;
 }

 // --- Directional Allocation ---
 if (el('varBiasNote')) {
 const regimeMeta = getMarketRegimeMeta(marketIndex?.regime);
 const biasLabel = caps.preferredSide === 'short'
 ? 'Bearish bias'
 : caps.preferredSide === 'long'
 ? 'Bullish bias'
 : 'Neutral bias';
 el('varBiasNote').textContent = `${biasLabel} ${maxLongPos} long / ${maxShortPos} short slots | ${longAllocPct}% / ${shortAllocPct}% cycle budget | ${regimeMeta.label}`;
 }
 if (el('varLongBudget')) el('varLongBudget').textContent = `${fmtUSD(longBudget)} (${longAllocPct}%)`;
 if (el('varShortBudget')) el('varShortBudget').textContent = `${fmtUSD(shortBudget)} (${shortAllocPct}%)`;
 if (el('varLongFill')) {
 el('varLongFill').style.width = longFillPct + '%';
 el('varLongFill').style.background = longCount >= maxLongPos ? '#ff6b82' : '#2fe0a1';
 }
 if (el('varShortFill')) {
 el('varShortFill').style.width = shortFillPct + '%';
 el('varShortFill').style.background = shortCount >= maxShortPos ? '#ff6b82' : '#ff7b5a';
 }
 if (el('varLongPositions')) el('varLongPositions').innerHTML = `${longCount} / ${maxLongPos} positions` + (longCount >= maxLongPos ? ' <span style="color:#ff6b82;font-weight:700">FULL</span>' : '');
 if (el('varShortPositions')) el('varShortPositions').innerHTML = `${shortCount} / ${maxShortPos} positions` + (shortCount >= maxShortPos ? ' <span style="color:#ff6b82;font-weight:700">FULL</span>' : '');

 // --- Sector Exposure Grid ---
 if (el('varSectorGrid')) {
 const allSectors = typeof SECTORS !== 'undefined' ? Object.keys(SECTORS) : ['Layer 1', 'DeFi', 'Meme', 'AI / Data', 'Infra', 'Gaming', 'Layer 2', 'Exchange', 'Privacy', 'Commodity', 'Stock', 'New'];
 let sectorHTML = '';
 allSectors.forEach(sector => {
 const count = sectorCounts[sector] || 0;
 const isFull = count >= maxPerSector;
 const pct = Math.min((count / maxPerSector) * 100, 100);
 const blocks = [];
 for (let i = 0; i < maxPerSector; i++) {
 blocks.push(`<div class="var-sector-block ${i < count ? (isFull ? 'full' : 'used') : 'empty'}"></div>`);
 }
 sectorHTML += `
 <div class="var-sector-item ${isFull ? 'at-limit' : ''}">
 <div class="var-sector-name">${sector}</div>
 <div class="var-sector-blocks">${blocks.join('')}</div>
 <div class="var-sector-count">${count}/${maxPerSector}</div>
 </div>`;
 });
 el('varSectorGrid').innerHTML = sectorHTML;
 }

 // --- VAR Status Banner ---
 if (el('varStatus')) {
 const warnings = [];
 if (cyclePct >= 100) warnings.push('Cycle budget exhausted - kill switch recommended');
 else if (cyclePct >= 80) warnings.push(`Cycle ${currentCycle} is ${cyclePct.toFixed(0)}% consumed`);
 if (longCount >= maxLongPos) warnings.push('Long position slots full');
 if (shortCount >= maxShortPos) warnings.push('Short position slots full');
 Object.entries(sectorCounts).forEach(([sector, count]) => {
 if (count >= maxPerSector) warnings.push(`${sector}: sector limit reached (${count}/${maxPerSector})`);
 });

 if (warnings.length === 0) {
 el('varStatus').innerHTML = `<div class="var-status-ok">All VAR limits within bounds. Cycle ${currentCycle}/${cycleCount} active.</div>`;
 el('varStatus').className = 'var-status ok';
 } else {
 el('varStatus').innerHTML = `<div class="var-status-warn">${warnings.map(w => '- ' + w).join('<br>')}</div>`;
 el('varStatus').className = 'var-status warn';
 }
 }
}

globalThis.renderV16VarDashboard = renderV16VarDashboard;
